INSERT INTO stories VALUES(1,'US-AGENT-001','user','创建个人 Agent','用户首次使用 BridgeAI，创建自己的 AI Agent，配置基本信息和偏好。',NULL,replace('\n[2026-04-18T07:00:11.417008+00:00] Agent验收: 无AC，所有关联issues已accepted，验收通过\n[2026-04-18T11:16:54.895188+00:00] AI验收发现问题: ISSUE-A003(US-AGENT-001-AC-1)\n[2026-04-18T11:16:54.895372+00:00] AI验收发现问题: ISSUE-UI005(US-AGENT-001-AC-2, US-AGENT-001-AC-3)\n[2026-04-18T11:16:54.895458+00:00] AI验收发现问题: ISSUE-C001(US-AGENT-001-AC-4)\n[2026-04-18T11:27:28.555474+00:00] 修正: ISSUE-A003恢复为split状态。AC-1(头像上传stub)问题归因: ISSUE-A003只拆分出后端API子issue(A003a)，移动端头像上传实现无对应子issue，存在拆分遗漏。','\n',char(10)),0,NULL,'active','migration','2026-04-14 15:17:30.773837','2026-04-18T11:13:36.034980+00:00');
