INSERT INTO acceptance_criteria VALUES(145,'ISSUE-A001~c1',NULL,replace('实现注册接口:\n- 手机号/邮箱注册\n- 密码强度验证\n- 验证码发送和校验\n- 用户唯一性检查\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/auth.ts'', ''apps/server/src/services/authService.ts''], ''prompt'': ''检查用户注册 API 实现，验证有 /api/v1/auth/register 端点，包含手机号/邮箱验证和密码加密''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(146,'ISSUE-A001~c2',NULL,replace('实现登录接口:\n- 密码登录\n- 验证码登录\n- 登录失败处理(限制重试)\n- 登录日志记录\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/auth.ts'', ''apps/server/src/services/authService.ts''], ''prompt'': ''检查用户登录 API 实现，验证有 /api/v1/auth/login 端点，包含密码验证和失败限制机制''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(147,'ISSUE-A001~c3',NULL,replace('第三方登录:\n- 微信 OAuth 登录\n- Google OAuth 登录\n- OAuth 回调处理\n- 账号绑定和解绑\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/oauthService.ts'', ''apps/server/src/routes/oauth.ts''], ''prompt'': ''检查第三方登录实现，验证有微信和 Google OAuth 集成，确认回调处理正确''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(148,'ISSUE-A001~c4',NULL,replace('密码重置:\n- 忘记密码申请\n- 重置验证码发送\n- 密码重置确认\n- 重置令牌有效期\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/auth.ts''], ''prompt'': ''检查密码重置功能，验证有 /api/v1/auth/forgot-password 和 reset-password 端点''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(149,'ISSUE-A001~c5',NULL,replace('移动端登录 UI:\n- 登录表单(手机号/密码)\n- 验证码输入界面\n- 第三方登录按钮\n- 注册入口\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Auth/LoginScreen.tsx''], ''prompt'': ''检查移动端登录界面，验证有 LoginScreen 组件，包含表单验证和第三方登录按钮''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
