INSERT INTO acceptance_criteria VALUES(152,'ISSUE-A002~c2',NULL,replace('刷新令牌:\n- Refresh Token 生成\n- Token 刷新接口\n- Refresh Token 存储\n- 刷新限制和轮换\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 Refresh Token 实现，验证有 /api/v1/auth/refresh 端点，确认 Refresh Token 存储在数据库/Redis'', ''context_files'': [''apps/server/src/routes/auth.ts'', ''apps/server/src/services/authService.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
