INSERT INTO acceptance_criteria VALUES(165,'ISSUE-A004~c3',NULL,replace('安全防护:\n- XSS 过滤中间件\n- SQL 注入防护(参数化查询)\n- NoSQL 注入防护\n- HTML 转义处理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/security.ts'', ''apps/server/src/utils/sanitizer.ts''], ''prompt'': ''检查安全防护，验证有 xss 中间件，确认所有数据库查询使用参数化查询''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
