INSERT INTO acceptance_criteria VALUES(167,'ISSUE-A004~c5',NULL,replace('上传安全:\n- 文件类型限制\n- 文件大小限制\n- 图片内容验证\n- 恶意文件检测\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/upload.ts''], ''prompt'': ''检查文件上传验证，验证 multer 配置了 fileFilter 和 limits，确认有文件类型白名单''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(168,'ISSUE-AI001~c1',NULL,replace('适配器实现:\n- OpenAI GPT系列适配器\n- Anthropic Claude适配器\n- 文心一言适配器\n- 统一接口抽象层\n- 模型能力注册表\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/adapters/''], ''prompt'': ''检查LLM适配器实现，验证有OpenAIAdapter、ClaudeAdapter等类实现统一的ILLMAdapter接口，包含chat completion和embedding方法''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(169,'ISSUE-AI001~c2',NULL,replace('熔断器实现:\n- 失败率监控\n- 熔断状态管理(关闭/半开/打开)\n- 自动恢复探测\n- 熔断事件通知\n- 多维度熔断策略\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/circuitBreaker.ts''], ''prompt'': ''检查熔断器实现，验证有CircuitBreaker类，包含CLOSED、HALF_OPEN、OPEN三种状态，支持failureThreshold和recoveryTimeout配置''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(170,'ISSUE-AI001~c3',NULL,replace('路由策略:\n- 基于成本的智能路由\n- 延迟优先路由\n- 质量优先路由\n- 轮询/权重负载均衡\n- 模型能力匹配\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/llmRouter.ts''], ''prompt'': ''检查路由实现，验证有LLMRouter类，支持cost、latency、quality路由策略，根据模型能力标签匹配请求''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(171,'ISSUE-AI001~c4',NULL,replace('降级策略:\n- 模型降级(cheap模型替代)\n- 提供商降级(备用提供商)\n- 功能降级(简化输出)\n- 缓存响应回退\n- 异步队列兜底\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/fallback/''], ''prompt'': ''检查降级策略，验证有FallbackStrategy接口及实现类，支持model-downgrade、provider-switch、cache-fallback等策略''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(172,'ISSUE-AI001~c5',NULL,replace('API配置:\n- LLM服务统一API\n- 提供商配置管理\n- API密钥安全存储\n- 模型参数配置\n- 流式响应支持\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/ai.ts''], ''prompt'': ''检查API实现，验证有/ai/chat和/ai/embeddings端点，支持stream参数，配置从environment或vault读取''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(173,'ISSUE-AI001~c6',NULL,replace('监控系统:\n- 请求延迟指标\n- 成功率/失败率统计\n- Token使用量监控\n- 成本追踪\n- 熔断事件日志\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/metricsService.ts''], ''prompt'': ''检查监控实现，验证有LLMMetricsService类，暴露prometheus指标：llm_requests_total、llm_latency_seconds、llm_tokens_used''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
