INSERT INTO acceptance_criteria VALUES(202,'ISSUE-AI005~c1',NULL,replace('适配层:\n- GPT-4 Vision适配器\n- Claude Vision适配器\n- 其他Vision模型支持\n- 图像编码处理\n- 多模态请求封装\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查多模态适配，验证有VisionModelAdapter类或接口，GPT4VisionAdapter和ClaudeVisionAdapter实现，支持image URL/base64输入'', ''context_files'': [''apps/server/src/services/ai/adapters/vision/'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(203,'ISSUE-AI005~c2',NULL,replace('分析能力:\n- 场景识别\n- 物体检测与描述\n- 活动理解\n- 图像分类标签\n- 视觉特征提取\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查内容分析，验证有ImageAnalysisService类，包含analyze方法返回scene_description、detected_objects、activity_tags、visual_features'', ''context_files'': [''apps/server/src/services/ai/imageAnalysisService.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(204,'ISSUE-AI005~c3',NULL,replace('审核系统:\n- 敏感内容检测\n- 涉黄/暴力识别\n- 隐私信息检测\n- 违规图片标记\n- 审核置信度评分\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查安全审核，验证有ImageModerationService类，包含moderate方法返回is_safe、violation_type、confidence_score，支持NSFW、violence检测'', ''context_files'': [''apps/server/src/services/ai/imageModerationService.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(205,'ISSUE-AI005~c4',NULL,replace('OCR功能:\n- 图像文字提取\n- 多语言支持\n- 手写体识别\n- 文字位置定位\n- 结构化输出\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查OCR实现，验证有OCRService类，包含extractText方法返回extracted_text、language、bounding_boxes，支持多语言和手写体'', ''context_files'': [''apps/server/src/services/ai/ocrService.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(206,'ISSUE-AI005~c5',NULL,replace('检索系统:\n- 自然语言图片搜索\n- 相似图片匹配\n- 语义标签检索\n- 图像嵌入生成\n- 向量索引支持\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查相册检索，验证有ImageSearchService类，包含searchByText方法使用自然语言描述搜索，生成image_embeddings存储到向量数据库'', ''context_files'': [''apps/server/src/services/ai/imageSearchService.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(207,'ISSUE-AI005~c6',NULL,replace('API实现:\n- 图像分析API\n- 批量图像处理\n- 流式上传支持\n- 结果缓存机制\n- 异步处理队列\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查Vision API，验证有/api/v1/ai/vision/analyze、/moderate、/ocr端点，支持multipart/form-data上传，返回analysis结果'', ''context_files'': [''apps/server/src/routes/ai/vision.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(208,'ISSUE-AI006~c1',NULL,replace('降级层级:\n- L1: 主模型降级到备用模型\n- L2: 高质量降级到低成本模型\n- L3: AI生成降级到模板回复\n- L4: 实时降级到异步队列\n- L5: 服务完全不可用提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/degradationStrategy.ts''], ''prompt'': ''检查降级策略，验证有DegradationStrategy类或配置，支持5个降级级别，每个级别有对应的fallback实现和触发条件''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(209,'ISSUE-AI006~c2',NULL,replace('决策系统:\n- 服务健康状态监控\n- 降级级别自动判断\n- 用户影响评估\n- 渐进式降级/恢复\n- 降级原因记录\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/degradationController.ts''], ''prompt'': ''检查降级决策器，验证有DegradationController类，监控error_rate、latency_percentile，自动选择degradation_level，记录decision_reason''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(210,'ISSUE-AI006~c3',NULL,replace('模板机制:\n- 场景模板库\n- 变量替换支持\n- 模板匹配算法\n- 个性化模板选择\n- 模板动态更新\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/templateResponseService.ts''], ''prompt'': ''检查模板系统，验证有TemplateResponseService类，包含templates配置，支持变量插值{{variable}}，根据scene和intent匹配模板''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(211,'ISSUE-AI006~c4',NULL,replace('缓存机制:\n- 相似请求缓存\n- 缓存命中策略\n- 缓存过期管理\n- 降级时优先使用\n- 缓存预热\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/responseCacheService.ts''], ''prompt'': ''检查缓存回退，验证有AIResponseCacheService类，使用similarity_hash索引缓存，支持TTL过期，degradation时返回stale cache''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(212,'ISSUE-AI006~c5',NULL,replace('队列系统:\n- 延迟任务队列\n- 优先级管理\n- 失败重试机制\n- 队列状态查询\n- 结果回调通知\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/asyncQueueService.ts''], ''prompt'': ''检查异步队列，验证有AIAsyncQueueService类，使用Redis/Bull队列，支持priority、retry_count，提供job status查询API''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(213,'ISSUE-AI006~c6',NULL,replace('监控告警:\n- 降级事件统计\n- 降级持续时间\n- 用户影响评估\n- 自动告警触发\n- 恢复通知\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/resilience/metricsService.ts''], ''prompt'': ''检查降级监控，验证有ResilienceMetricsService类，暴露降级metrics：ai_degradation_events_total、degradation_duration_seconds，集成告警''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(214,'ISSUE-API001~c1',NULL,replace('配置OpenAPI规范和文档生成:\n- 安装swagger-jsdoc和swagger-ui-express\n- 配置OpenAPI 3.0基础信息(标题、版本、描述)\n- 设置API服务器配置(开发/测试/生产环境)\n- 配置安全方案(JWT Bearer认证)\n- 文档路由配置(/api-docs)\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查OpenAPI配置，验证有swagger配置文件中定义OpenAPI 3.0规范，包含info、servers、securitySchemes，有/api-docs路由可访问文档UI'', ''context_files'': [''apps/server/src/config/swagger.ts'', ''apps/server/src/routes/docs.ts'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(215,'ISSUE-API001~c2',NULL,replace('为认证模块编写OpenAPI文档:\n- POST /api/v1/auth/register - 用户注册\n- POST /api/v1/auth/login - 用户登录\n- POST /api/v1/auth/refresh - 刷新Token\n- POST /api/v1/auth/logout - 用户登出\n- POST /api/v1/auth/forgot-password - 忘记密码\n- POST /api/v1/auth/reset-password - 重置密码\n- 每个端点包含: 请求体、响应示例、错误码、安全要求\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查认证API文档，验证所有认证端点有OpenAPI注释，包含请求参数、响应示例、错误状态码，可在Swagger UI中查看'', ''context_files'': [''apps/server/src/routes/auth.ts'', ''apps/server/src/docs/auth.docs.ts'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(216,'ISSUE-API001~c3',NULL,replace('为用户资料模块编写OpenAPI文档:\n- GET /api/v1/users/me - 获取当前用户\n- PUT /api/v1/users/me - 更新用户信息\n- GET /api/v1/users/:id - 获取用户详情\n- PUT /api/v1/users/me/avatar - 更新头像\n- 包含数据模型定义(User, UserProfile)\n- 字段类型和验证规则文档化\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查用户API文档，验证用户相关端点有OpenAPI注释，包含User和UserProfile模型定义，字段类型正确，有响应示例'', ''context_files'': [''apps/server/src/routes/users.ts'', ''apps/server/src/docs/users.docs.ts'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(217,'ISSUE-API001~c4',NULL,replace('为Agent模块编写OpenAPI文档:\n- POST /api/v1/agents - 创建Agent\n- GET /api/v1/agents - 获取Agent列表\n- GET /api/v1/agents/:id - 获取Agent详情\n- PUT /api/v1/agents/:id - 更新Agent\n- DELETE /api/v1/agents/:id - 删除Agent\n- 三层信息模型文档(L1/L2/L3)\n- 场景配置字段说明\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查Agent API文档，验证Agent CRUD端点有完整OpenAPI注释，包含L1/L2/L3模型定义，场景配置字段有说明'', ''context_files'': [''apps/server/src/routes/agents.ts'', ''apps/server/src/docs/agents.docs.ts'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(218,'ISSUE-API001~c5',NULL,replace('为匹配引擎编写OpenAPI文档:\n- GET /api/v1/matches - 获取推荐列表\n- POST /api/v1/matches/:id/like - 喜欢/匹配\n- POST /api/v1/matches/:id/pass - 跳过\n- GET /api/v1/matches/mutual - 双向匹配列表\n- 匹配算法参数说明\n- 筛选条件文档化\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查匹配API文档，验证匹配相关端点有OpenAPI注释，包含查询参数、匹配响应结构、筛选条件说明'', ''context_files'': [''apps/server/src/routes/matches.ts'', ''apps/server/src/docs/matches.docs.ts'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(219,'ISSUE-API001~c6',NULL,replace('为聊天模块编写OpenAPI文档:\n- GET /api/v1/chats - 获取聊天列表\n- GET /api/v1/chats/:id/messages - 获取消息历史\n- POST /api/v1/chats/:id/messages - 发送消息(REST备用)\n- WebSocket事件文档\n- 消息类型和格式定义\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查聊天API文档，验证聊天REST端点有OpenAPI注释，WebSocket事件有独立文档，消息模型定义完整'', ''context_files'': [''apps/server/src/routes/chats.ts'', ''apps/server/src/docs/chats.docs.ts'', ''apps/server/docs/websocket.md'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(220,'ISSUE-API001~c7',NULL,replace('API文档自动化流程:\n- 文档自动生成脚本(npm run docs:generate)\n- 文档静态站点导出\n- CI/CD集成(自动部署文档站点)\n- 文档版本管理(与API版本同步)\n- 变更日志自动生成\n- E2E测试集成(基于文档生成测试数据)\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查API文档自动化，验证有文档生成脚本，可导出静态站点，CI配置自动部署，有版本管理机制，E2E测试可使用文档数据'', ''context_files'': [''package.json'', ''.github/workflows/docs-deploy.yml'', ''scripts/generate-api-docs.ts'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(221,'ISSUE-C001~c1',NULL,replace('Agent 创建接口:\n- 创建 Agent 端点\n- Agent 类型选择(VisionShare, AgentDate, AgentJob, AgentAd)\n- 基础信息设置(名称、描述)\n- 用户关联和权限\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/agents.ts'', ''apps/server/src/services/agentService.ts''], ''prompt'': ''检查 Agent 创建 API，验证有 /api/v1/agents POST 端点，包含 name, type, description 字段''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(222,'ISSUE-C001~c2',NULL,replace('Agent 类型定义:\n- 四种场景类型枚举\n- 场景特定配置 Schema\n- 类型验证和转换\n- 场景能力声明\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/shared/src/types/agent.ts''], ''prompt'': ''检查 Agent 类型定义，验证有 AgentType 枚举包含 VISIONSHARE, AGENTDATE, AGENTJOB, AGENTAD''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(223,'ISSUE-C001~c3',NULL,replace('Agent 生命周期:\n- 状态枚举: draft, active, paused, archived\n- 状态转换规则\n- 状态变更 API\n- 状态历史记录\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/agentService.ts''], ''prompt'': ''检查 Agent 状态管理，验证有 AgentStatus 枚举和状态转换验证''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(224,'ISSUE-C001~c4',NULL,replace('Agent 查询接口:\n- 获取用户所有 Agent\n- 按类型筛选\n- 按状态筛选\n- 分页和排序\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/agents.ts''], ''prompt'': ''检查 Agent 查询 API，验证有 /api/v1/agents GET 端点支持筛选和分页''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(225,'ISSUE-C001~c5',NULL,replace('Agent 管理 UI:\n- Agent 列表页面\n- 创建 Agent 向导\n- Agent 卡片组件\n- 空状态设计\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/AgentListScreen.tsx'', ''apps/mobile/src/screens/Agent/CreateAgentScreen.tsx''], ''prompt'': ''检查移动端 Agent 界面，验证有 AgentListScreen 和 CreateAgentScreen''}}',1,'sufficient','required','required','not_needed','sufficient','pending','pending');
INSERT INTO acceptance_criteria VALUES(226,'ISSUE-C002~c1',NULL,replace('Agent L1层 - 可编辑的基础信息:\n- 年龄、性别、地域、职业等基础字段\n- 字段验证和约束规则\n- 用户资料编辑界面\n- L1数据库存储\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查L1模型实现，验证有AgentL1Model表，包含age、gender、location、occupation等基础字段，支持CRUD操作'', ''context_files'': [''apps/server/src/models/agentL1Model.ts'', ''apps/mobile/src/screens/ProfileEditScreen.tsx'']}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(227,'ISSUE-C002~c2',NULL,replace('Agent L2层 - 场景特定结构化属性:\n- VisionShare: 拍照类型、设备、风格\n- AgentDate: 择偶标准、兴趣爱好\n- AgentJob: 技能、经验、期望薪资\n- AgentAd: 消费偏好、品牌倾向\n- L1到L2的映射关系\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查L2模型实现，验证有AgentL2Model和场景特定子表，支持结构化属性存储和查询'', ''context_files'': [''apps/server/src/models/agentL2Model.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(228,'ISSUE-C002~c3',NULL,replace('Agent L3层 - 非结构化表达:\n- 自由文本自我介绍\n- 多媒体内容(照片、视频)\n- AI提炼的自然语言描述\n- L3与L1/L2的关联\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查L3模型实现，验证有AgentL3Model支持text_content和media_urls字段，与AI提炼服务集成'', ''context_files'': [''apps/server/src/models/agentL3Model.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(229,'ISSUE-C002a~c1',NULL,replace('基础信息 Schema:\n- age: 年龄段枚举\n- gender: 性别\n- location: 地理位置(省市区)\n- occupation: 职业\n- education: 教育水平\n- 字段验证规则\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 L1 模型定义，验证有 L1Profile 类型包含 age, gender, location, occupation 字段'', ''context_files'': [''packages/shared/src/types/agentProfile.ts'']}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(230,'ISSUE-C002a~c2',NULL,replace('数据库模型:\n- Prisma AgentProfile 模型 L1 字段\n- JSON 字段存储灵活数据\n- 索引优化\n- 数据迁移\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 Prisma schema，验证 AgentProfile 模型有 l1Data JSON 字段和相关索引'', ''context_files'': [''prisma/schema.prisma'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(231,'ISSUE-C002a~c3',NULL,replace('L1 信息接口:\n- 获取 L1 信息\n- 更新 L1 信息\n- 字段级验证\n- 变更历史\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 L1 API，验证有 /api/v1/agents/:id/profile/l1 端点支持 GET/PUT'', ''context_files'': [''apps/server/src/routes/agentProfile.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(232,'ISSUE-C002a~c4',NULL,replace('L1 配置 UI:\n- 表单字段组件\n- 地理位置选择器\n- 职业/教育选择器\n- 实时验证\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 L1 编辑界面，验证有 L1ProfileForm 组件包含年龄、性别、地域等字段'', ''context_files'': [''apps/mobile/src/components/AgentProfile/L1ProfileForm.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(233,'ISSUE-C002a~c5',NULL,replace('完成度系统:\n- 字段权重定义\n- 完成度百分比计算\n- 缺失字段提示\n- 完成度展示\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查完成度计算，验证有 calculateL1Completion 函数，确认返回 0-100 百分比'', ''context_files'': [''apps/server/src/utils/profileCompletion.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(234,'ISSUE-C002b~c1',NULL,replace('结构化信息定义:\n- 场景特定的 L2 Schema\n- 字段类型: enum, range, boolean, multi_select\n- 条件字段(dependent fields)\n- Schema 版本管理\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查 L2 Schema 定义，验证有各场景的 L2 Schema JSON 文件，包含字段类型和选项'', ''context_files'': [''packages/shared/src/schemas/l2/'']}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
