INSERT INTO acceptance_criteria VALUES(284,'ISSUE-COM002b~c2',NULL,replace('消息处理:\n- 消息验证和过滤\n- 消息存储\n- 消息广播\n- 发送确认\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/socket/handlers/messageHandler.ts''], ''prompt'': ''检查消息处理，验证有消息发送 socket handler 和存储逻辑''}}',1,'sufficient','lacking','sufficient','not_needed','sufficient','pending','pending');
INSERT INTO acceptance_criteria VALUES(285,'ISSUE-COM002b~c3',NULL,replace('查询接口:\n- 分页查询历史消息\n- 消息搜索\n- 按时间范围查询\n- 消息过滤\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/chat.ts''], ''prompt'': ''检查历史查询，验证有 /api/v1/chat/rooms/:id/messages GET 支持分页''}}',1,'sufficient','lacking','sufficient','not_needed','sufficient','pending','pending');
