INSERT INTO acceptance_criteria VALUES(287,'ISSUE-COM002b~c5',NULL,replace('离线处理:\n- 离线消息存储\n- 上线推送\n- 消息队列\n- 推送通知\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/offlineMessageService.ts''], ''prompt'': ''检查离线消息，验证有离线消息队列和用户上线推送逻辑''}}',1,'sufficient','lacking','lacking','not_needed','sufficient','pending','pending');
INSERT INTO acceptance_criteria VALUES(288,'ISSUE-COM002b~c6',NULL,replace('回执系统:\n- 已读状态追踪\n- 已读回执发送\n- 已读时间记录\n- 批量已读标记\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/readReceiptService.ts''], ''prompt'': ''检查已读回执，验证有 read receipt 机制和已读时间存储''}}',1,'sufficient','lacking','lacking','not_needed','sufficient','pending','pending');
