INSERT INTO acceptance_criteria VALUES(291,'ISSUE-CR001~c1',NULL,replace('信用分数据库设计:\n- CreditScore 表设计(用户ID、当前分数、等级、更新时间)\n- CreditHistory 表设计(分数变更历史记录)\n- CreditFactor 表设计(各维度评分因子存储)\n- 数据库索引优化(按用户ID和日期查询)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/database/prisma/schema.prisma'', ''packages/shared/src/types/credit.ts''], ''prompt'': ''检查信用分数据模型，验证Prisma schema中有CreditScore、CreditHistory、CreditFactor模型，确认字段完整性和关联关系''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(292,'ISSUE-CR001~c2',NULL,replace('信用分计算核心算法:\n- 基础信息完整性评分(资料完善度)\n- 行为信用评分(活跃度、响应率)\n- 交易信用评分(完成率、纠纷记录)\n- 社交信用评分(评价、举报记录)\n- 加权综合算法实现\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/creditScoreService.ts'', ''apps/server/src/config/creditWeights.ts''], ''prompt'': ''检查信用分计算算法，验证有CreditScoreService.calculateScore方法，确认多维度评分逻辑和权重配置正确''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(293,'ISSUE-CR001~c3',NULL,replace('信用等级划分机制:\n- 等级定义(例如: 优秀900-1000、良好750-899、一般600-749、较差<600)\n- 等级权益配置(不同等级的权限差异)\n- 等级升降级规则\n- 等级徽章和视觉展示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/shared/src/types/credit.ts'', ''apps/server/src/config/creditLevels.ts''], ''prompt'': ''检查信用等级系统，验证有CreditLevel枚举定义，确认等级划分规则和权益配置正确''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(294,'ISSUE-CR001~c4',NULL,replace('信用分对外接口:\n- GET /api/v1/credit/score - 获取当前用户信用分\n- GET /api/v1/credit/history - 获取信用分历史记录\n- GET /api/v1/credit/factors - 获取各维度评分详情\n- POST /api/v1/credit/recalculate - 触发重新计算(管理员)\n- 其他用户信用分查询(脱敏)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/credit.ts'', ''apps/server/src/services/creditScoreService.ts''], ''prompt'': ''检查信用分API，验证有/credit/score、/credit/history、/credit/factors端点，确认响应格式和权限控制''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(295,'ISSUE-CR001~c5',NULL,replace('信用分动态更新:\n- 事件驱动更新(交易完成、评价提交等)\n- 定时任务全量计算(每日/每周)\n- 更新频率限制(防止刷分)\n- 异常波动检测和告警\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/creditScoreService.ts'', ''apps/server/src/jobs/creditUpdateJob.ts'', ''apps/server/src/events/creditEventHandlers.ts''], ''prompt'': ''检查信用分更新机制，验证有事件监听和定时任务实现，确认更新频率控制和异常检测逻辑''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(296,'ISSUE-CR001~c6',NULL,replace('信用分在匹配中的应用:\n- 信用分筛选接口(最低分数要求)\n- 信用分排序权重\n- 信用不达标用户过滤\n- 匹配结果中的信用分展示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/matchingService.ts'', ''apps/server/src/services/queryBuilder.ts''], ''prompt'': ''检查信用分匹配集成，验证匹配查询支持信用分筛选，确认信用分权重在排序算法中的应用''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(297,'ISSUE-CR002a~c1',NULL,replace('评价系统数据库设计:\n- Review 表设计(评价ID、评价者、被评价者、评分、内容、场景类型)\n- ReviewReply 表设计(评价回复)\n- ReviewReport 表设计(评价举报)\n- ReviewStats 表设计(评价统计缓存)\n- 索引优化(按用户ID和场景类型查询)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/database/prisma/schema.prisma'', ''packages/shared/src/types/review.ts''], ''prompt'': ''检查评价数据模型，验证Prisma schema中有Review、ReviewReply、ReviewReport、ReviewStats模型，确认关联关系和索引''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(298,'ISSUE-CR002a~c2',NULL,replace('评分提交和查询接口:\n- POST /api/v1/reviews - 提交评价\n- GET /api/v1/reviews/received - 获取收到的评价\n- GET /api/v1/reviews/given - 获取发出的评价\n- PUT /api/v1/reviews/:id/reply - 回复评价\n- DELETE /api/v1/reviews/:id - 删除评价(管理员)\n- 评价权限验证(交易完成后才可评价)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/reviews.ts'', ''apps/server/src/services/reviewService.ts''], ''prompt'': ''检查评分API，验证有reviews端点支持CRUD操作，确认权限控制和交易关联验证''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(299,'ISSUE-CR002a~c3',NULL,replace('评价内容审核机制:\n- 敏感词过滤和AI内容审核\n- 恶意刷评价检测(同一用户多次评价)\n- 评价真实性验证(需有实际交互)\n- 申诉和举报处理流程\n- 异常评价自动标记\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/reviewModerationService.ts'', ''apps/server/src/services/reviewAntiCheatService.ts''], ''prompt'': ''检查评价审核机制，验证有内容审核服务和反作弊检测，确认敏感词过滤和异常评价标记逻辑''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(300,'ISSUE-CR002b~c1',NULL,replace('移动端评价UI:\n- 评价列表页面(收到的/发出的)\n- 评价卡片组件(评分、内容、时间)\n- 评分输入组件(星级评分+文字评价)\n- 评价详情页(含回复)\n- 评价统计展示(平均分、分布图)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Reviews/ReviewListScreen.tsx'', ''apps/mobile/src/components/Reviews/ReviewCard.tsx'', ''apps/mobile/src/components/Reviews/StarRating.tsx''], ''prompt'': ''检查评价UI组件，验证有ReviewListScreen、ReviewCard、StarRating组件，确认交互和展示正确''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(301,'ISSUE-CR002c~c1',NULL,replace('评价对信用分的影响:\n- 收到好评增加信用分\n- 收到差评扣除信用分\n- 评价数量对信用的影响\n- 评价回复率计入信用\n- 触发信用分重算事件\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/events/reviewEventHandlers.ts'', ''apps/server/src/services/creditScoreService.ts''], ''prompt'': ''检查评价与信用分联动，验证评价提交后触发信用分更新，确认好评/差评对信用分的影响规则''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(302,'ISSUE-CR002c~c2',NULL,replace('评价相关通知:\n- 收到新评价推送通知\n- 待评价提醒(交易完成后24小时)\n- 评价回复通知\n- 差评预警通知(信用分下降时)\n- 通知偏好设置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/notificationService.ts'', ''apps/server/src/events/reviewNotificationHandlers.ts''], ''prompt'': ''检查评价通知系统，验证有新评价、待评价、差评等场景的通知触发逻辑''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(303,'ISSUE-CR003a~c1',NULL,replace('积分系统数据库设计:\n- PointsAccount 表设计(用户ID、当前余额、总获取、总消耗、冻结金额)\n- PointsTransaction 表设计(交易ID、类型、金额、描述、关联场景)\n- PointsFreeze 表设计(冻结记录用于交易担保)\n- 账户唯一性约束和用户关联\n- 余额非负约束\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查积分账户数据模型，验证Prisma schema中有PointsAccount、PointsTransaction、PointsFreeze模型，确认字段和约束'', ''context_files'': [''apps/server/prisma/schema.prisma'', ''packages/shared/src/types/points.ts'']}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(304,'ISSUE-CR003c~c1',NULL,replace('积分记录查询接口:\n- GET /api/v1/points/balance - 获取当前余额\n- GET /api/v1/points/transactions - 获取交易记录(支持筛选和分页)\n- GET /api/v1/points/transactions/:id - 获取交易详情\n- GET /api/v1/points/stats - 获取积分统计(收入/支出分类)\n- 交易记录导出功能\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/points.ts'', ''apps/server/src/services/pointsService.ts''], ''prompt'': ''检查积分API，验证有/points/balance、/points/transactions端点，确认筛选、分页和统计功能''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(305,'ISSUE-CR003d~c1',NULL,replace('移动端积分界面:\n- 积分钱包首页(余额、收支概览)\n- 交易记录列表(时间轴展示)\n- 交易详情页(含关联场景)\n- 积分获取任务列表\n- 积分充值入口(预留)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Points/PointsWalletScreen.tsx'', ''apps/mobile/src/components/Points/TransactionList.tsx'', ''apps/mobile/src/components/Points/PointsTaskList.tsx''], ''prompt'': ''检查积分UI，验证有PointsWalletScreen、TransactionList、PointsTaskList组件，确认余额展示和交易记录''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(306,'ISSUE-CR003d~c2',NULL,replace('积分在VisionShare场景的应用:\n- 照片查看积分支付接口\n- 支付前余额检查\n- 积分支付给供给方(平台抽成)\n- 支付成功后的照片解锁\n- 支付失败和退款处理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/visionSharePaymentService.ts'', ''apps/server/src/services/photoUnlockService.ts''], ''prompt'': ''检查VisionShare积分支付，验证有PhotoPaymentService，确认支付流程、解锁机制和分账逻辑''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(307,'ISSUE-DATE001-2~c2',NULL,replace('AI提炼功能:\n- 自然语言描述转结构化数据\n- 从用户自我介绍提取关键信息\n- 识别隐性偏好（通过否定词、强调词）\n- 智能补全建议（基于已有信息推断其他偏好）\n- 提炼结果的可编辑确认\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/datingExtractionService.ts'', ''apps/server/src/prompts/dating/''], ''prompt'': ''检查AI交友需求提炼服务，验证能从自然语言文本提取结构化交友偏好，包括显性和隐性偏好识别，并有智能补全建议功能''}}',1,'required','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(308,'ISSUE-DATE002~c1',NULL,replace('匹配算法:\n- 多维度相似度计算（基础条件、性格、兴趣、生活方式）\n- 权重配置（硬条件vs软偏好）\n- 互补性评分（性格互补、技能互补）\n- 地理位置接近度计算\n- 综合匹配度分数（0-100）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/matchAlgorithm.ts'', ''packages/shared/src/utils/datingSimilarity.ts''], ''prompt'': ''检查交友匹配度算法实现，验证有多维度相似度计算、硬软条件权重、互补性评分，输出0-100的综合匹配度分数''}}',1,'required','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(309,'ISSUE-DATE002~c2',NULL,replace('推荐逻辑:\n- 每日匹配候选池生成\n- Agent自动筛选高匹配度对象\n- 批量匹配候选人的排序算法\n- 过滤已匹配/已拒绝/黑名单用户\n- 推荐多样性保证（避免同质化）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/recommendationService.ts''], ''prompt'': ''检查Agent主动推荐逻辑，验证有每日候选池生成、自动筛选、排序算法、过滤机制和多样性保证功能''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(310,'ISSUE-DATE002~c3',NULL,replace('推送系统:\n- 每日推荐推送（新匹配对象提醒）\n- 推送内容个性化（展示匹配亮点）\n- 推送频率控制（避免打扰）\n- 用户偏好学习时间设置\n- 推送点击跳转匹配详情\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/matchNotificationService.ts'', ''apps/mobile/src/services/notifications.ts''], ''prompt'': ''检查匹配结果推送通知系统，验证有每日推荐推送、个性化内容、频率控制、时间偏好设置和跳转功能''}}',1,'sufficient','required','required','required','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(311,'ISSUE-DATE002~c4',NULL,replace('对话启动:\n- Agent自动发起对话流程\n- 个性化开场白生成（基于匹配点）\n- 对方Agent的自动响应\n- 对话目标设定（了解特定信息）\n- 对话轮次控制（初步交流后暂停等待用户）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/agentInitiatedChat.ts'', ''apps/server/src/services/ai/openingLineService.ts''], ''prompt'': ''检查Agent发起对话匹配功能，验证能自动发起对话、生成个性化开场白、控制对话轮次，在初步交流后暂停等待用户介入''}}',1,'required','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(312,'ISSUE-DATE002~c5',NULL,replace('移动端UI:\n- 每日推荐列表（卡片式展示）\n- 匹配详情页（照片、基本信息、匹配度、共同兴趣）\n- 匹配亮点高亮展示\n- 快速操作（喜欢/跳过/查看详情）\n- 匹配历史记录\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/dating/RecommendationsScreen.tsx'', ''apps/mobile/src/components/dating/MatchCard.tsx''], ''prompt'': ''检查移动端匹配结果展示界面，验证有卡片式推荐列表、匹配详情页、亮点高亮、快速操作按钮和匹配历史功能''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(313,'ISSUE-DATE002~c6',NULL,replace('反馈系统:\n- 喜欢/跳过快捷反馈\n- 不感兴趣原因收集（可选）\n- 推荐准确性评分\n- 反馈数据用于算法优化\n- 用户偏好学习\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/feedbackService.ts'', ''apps/server/src/services/dating/preferenceLearning.ts''], ''prompt'': ''检查用户反馈与推荐优化系统，验证有快捷反馈、原因收集、准确性评分功能，且反馈数据用于持续优化推荐算法''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(314,'ISSUE-DATE003~c1',NULL,replace('隔离机制:\n- 双人Agent对话房间创建\n- 对话状态管理（进行中/已完成/中断）\n- 对话超时控制（单轮和总时长）\n- 对话轮次限制配置\n- 用户不可见隔离层（防止提前暴露）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/agentConversationRoom.ts'', ''apps/server/src/services/dating/conversationStateManager.ts''], ''prompt'': ''检查Agent对话房间隔离机制，验证有双人隔离房间、状态管理、超时和轮次控制，确保用户在对话完成前不可见对方真实身份''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(315,'ISSUE-DATE003~c2',NULL,replace('对话生成:\n- 基于交友画像的对话策略\n- 话题选择与引导（从浅入深）\n- 人设一致性维护（与L3模型一致）\n- 信息获取与验证\n- 对话上下文记忆（多轮连贯性）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/datingConversationService.ts'', ''apps/server/src/prompts/dating/conversation/''], ''prompt'': ''检查Agent对话生成与管理功能，验证能基于交友画像进行策略对话、话题引导、人设一致维护，并保持多轮上下文连贯''}}',1,'required','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(316,'ISSUE-DATE003~c3',NULL,replace('质量评估:\n- 对话流畅度监测\n- 话题深度评估\n- 双方参与度分析\n- 信息获取有效性\n- 实时质量分数（低质量时调整策略）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/conversationQualityService.ts''], ''prompt'': ''检查对话质量实时评估系统，验证能监测流畅度、评估话题深度、分析参与度，并实时计算质量分数用于策略调整''}}',1,'required','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(317,'ISSUE-DATE003~c4',NULL,replace('报告生成:\n- 对话内容摘要（关键信息提取）\n- 匹配度重新评估（基于对话）\n- 共同话题亮点提炼\n- 潜在问题提示（价值观冲突等）\n- 建议是否继续交流\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/conversationReportService.ts'', ''packages/shared/src/types/conversationReport.ts''], ''prompt'': ''检查对话摘要与评估报告生成功能，验证能生成对话摘要、重新评估匹配度、提炼亮点、提示潜在问题并给出继续建议''}}',1,'required','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(318,'ISSUE-DATE003~c5',NULL,replace('移动端UI:\n- Agent对话进行中状态提示\n- 对话完成通知\n- 对话摘要查看界面\n- 匹配评估报告展示\n- 用户决策操作（同意/拒绝/再聊一轮）\n- 决策理由收集（可选）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/dating/ConversationReportScreen.tsx'', ''apps/mobile/src/components/dating/DecisionButtons.tsx''], ''prompt'': ''检查用户介入与决策界面，验证有对话状态提示、完成通知、摘要查看、评估报告展示和用户决策操作功能''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(319,'ISSUE-DATE003~c6',NULL,replace('安全机制:\n- 敏感话题检测与回避\n- 不当内容拦截\n- 对话异常中断处理\n- 用户紧急终止对话\n- 争议上报机制\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/dating/conversationSafetyService.ts'', ''apps/server/src/middleware/safety/''], ''prompt'': ''检查异常处理与安全机制，验证有敏感话题检测、不当内容拦截、异常中断处理、紧急终止和争议上报功能''}}',1,'sufficient','required','required','required','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(320,'ISSUE-DESIGN-1~c1',NULL,'核心概念定义文档，包含 5+ 个概念定义','functional','{''ai'': {''prompt'': ''检查 .issuetree/spec/CONCEPTS.md 是否存在且包含至少 5 个 CONCEPT-XXX 定义'', ''context_files'': [''.issuetree/spec/CONCEPTS.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(321,'ISSUE-DESIGN-1~c2',NULL,'项目介绍文档，包含项目名称、描述、核心价值','functional','{''ai'': {''prompt'': ''检查 .issuetree/spec/PROJECT.md 是否存在且包含项目名称和描述'', ''context_files'': [''.issuetree/spec/PROJECT.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(322,'ISSUE-DESIGN-1~c3',NULL,'技术栈文档，包含编程语言、运行时、核心依赖','functional','{''ai'': {''prompt'': ''检查 .issuetree/spec/TECH_STACK.md 是否存在且包含技术栈选择'', ''context_files'': [''.issuetree/spec/TECH_STACK.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(323,'ISSUE-DESIGN-1~c4',NULL,'架构文档，包含目录结构、模块设计','functional','{''ai'': {''prompt'': ''检查 .issuetree/spec/ARCHITECTURE.md 是否存在且包含架构设计'', ''context_files'': [''.issuetree/spec/ARCHITECTURE.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(324,'ISSUE-DESIGN-1~c5',NULL,'用户故事文档，包含 3+ 个用户故事，ID 格式为 US-XXX-{slug}','functional','{''ai'': {''prompt'': ''检查 .issuetree/spec/USER_STORIES.md 是否存在且包含至少 3 个 US-XXX 用户故事'', ''context_files'': [''.issuetree/spec/USER_STORIES.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(325,'ISSUE-DESIGN-2~c1',NULL,'IssueTree.md 包含所有 feature/component issues 及依赖关系','functional','{''ai'': {''prompt'': ''检查 IssueTree.md 是否包含完整的 issues 图'', ''context_files'': [''.issuetree/IssueTree.md'']}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(326,'ISSUE-F001~c1',NULL,replace('使用 pnpm workspaces 设置 monorepo 结构，包含以下目录:\n- apps/server: Express 后端服务\n- apps/mobile: Expo React Native 移动端\n- packages/shared: 共享类型定义和工具函数\n- packages/config: 共享配置文件(ESLint, TypeScript等)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''pnpm-workspace.yaml'', ''package.json''], ''prompt'': ''检查项目根目录是否有 pnpm-workspace.yaml，且包含 apps/* 和 packages/* 目录结构，确认 package.json 中定义了 workspaces''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(327,'ISSUE-F001~c2',NULL,replace('为每个 workspace 配置 TypeScript:\n- 根目录 tsconfig.json 作为基础配置\n- 每个子项目继承并扩展配置\n- 配置严格的类型检查选项\n- 设置路径别名和模块解析\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''tsconfig.json'', ''apps/server/tsconfig.json'', ''apps/mobile/tsconfig.json''], ''prompt'': ''检查各目录下的 tsconfig.json 是否存在且配置完整，验证 compilerOptions 包含 strict 模式和正确的 target 设置''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(328,'ISSUE-F001~c3',NULL,replace('配置代码质量工具链:\n- ESLint 配置(使用 @typescript-eslint)\n- Prettier 配置(统一代码格式)\n- Husky + lint-staged (Git 钩子)\n- commitlint (提交信息规范)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.eslintrc.js'', ''prettier.config.js'', ''.husky/pre-commit'', ''commitlint.config.js''], ''prompt'': ''检查 .eslintrc.js/.eslintrc.json、prettier.config.js/.prettierrc、.husky 目录和 commitlint.config.js 是否存在且配置正确''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(329,'ISSUE-F001~c4',NULL,replace('建立环境变量管理方案:\n- 创建 .env.example 模板文件\n- 配置 dotenv 加载环境变量\n- 设置不同环境的配置文件(.env.development, .env.production)\n- 环境变量类型定义和验证\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.env.example'', ''.env.development.example'', ''.env.production.example''], ''prompt'': ''检查 .env.example 是否存在且包含必要的环境变量定义(数据库、API密钥、端口等)，确认有 .env.*.example 文件用于不同环境''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(330,'ISSUE-F001~c5',NULL,replace('创建项目基础文档:\n- 根目录 README.md (项目介绍、快速开始)\n- CONTRIBUTING.md (贡献指南)\n- docs/ 目录下的架构文档\n- API 文档结构模板\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''README.md'', ''CONTRIBUTING.md''], ''prompt'': ''检查 README.md 是否包含项目描述、技术栈、安装步骤、开发命令；确认 CONTRIBUTING.md 和 docs/ 目录存在''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(331,'ISSUE-F001~c6',NULL,replace('配置 Git 工作流:\n- 设置 GitHub/GitLab 仓库\n- 配置分支保护规则(main, develop)\n- PR 模板和 Code Review 流程\n- CI/CD 基础工作流配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.github/workflows/ci.yml'', ''.github/pull_request_template.md''], ''prompt'': ''检查 .github/workflows/ 或 CI 配置文件是否存在，确认有 PR 模板 .github/pull_request_template.md 和分支策略文档''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(332,'ISSUE-F001~c7',NULL,replace('安装并配置开发数据库:\n- PostgreSQL 数据库创建 (visionshare_dev)\n- PostGIS 扩展安装和启用\n- 数据库连接配置 (.env.dev)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.env.dev''], ''prompt'': ''检查数据库 visionshare_dev 是否存在，PostGIS 扩展是否已启用，.env.dev 是否包含正确的数据库连接配置''}}',1,'sufficient','not_needed','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(333,'ISSUE-F002~c1',NULL,replace('配置 Prisma ORM:\n- 安装 @prisma/client 和 prisma CLI\n- 配置 schema.prisma 基础设置(数据源、生成器)\n- 设置数据库连接字符串管理\n- 配置 Prisma Client 单例模式\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/schema.prisma'', ''packages/database/src/client.ts''], ''prompt'': ''检查 schema.prisma 是否存在且包含 datasource db 和 generator client 配置，确认 prisma 目录结构和客户端生成配置正确''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(334,'ISSUE-F002~c2',NULL,replace('定义核心实体模型:\n- User (用户): id, email, phone, password, profile, createdAt, updatedAt\n- Agent (智能体): id, userId, name, type, config, status, creditScore\n- AgentProfile (Agent资料): L1基础信息, L2结构化信息, L3自然语言描述\n- Scene (场景): VisionShare, AgentDate, AgentJob, AgentAd\n- 关系定义和索引优化\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/schema.prisma''], ''prompt'': ''检查 schema.prisma 中是否定义了 User, Agent, AgentProfile, Scene 等模型，验证字段类型、关系和索引配置''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(335,'ISSUE-F002~c3',NULL,replace('定义通信相关模型:\n- ChatRoom (聊天室): id, type, sceneId, participants, metadata\n- Message (消息): id, roomId, senderId, content, type, status, createdAt\n- Connection (连接): socket连接管理、在线状态\n- 消息已读状态追踪\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/schema.prisma''], ''prompt'': ''检查 schema.prisma 中是否定义了 ChatRoom, Message, Connection 等通信相关模型，验证消息状态枚举和关系''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(336,'ISSUE-F002~c4',NULL,replace('定义匹配和信用相关模型:\n- Match (匹配记录): matcherId, matcheeId, score, status, scene\n- CreditRecord (信用记录): userId, score, reason, delta\n- Transaction (积分交易): userId, amount, type, description\n- Rating (评分): fromUserId, toUserId, score, comment\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/schema.prisma''], ''prompt'': ''检查 schema.prisma 中是否定义了 Match, CreditRecord, Transaction, Rating 等模型，验证字段和关系''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(337,'ISSUE-F002~c5',NULL,replace('建立数据库迁移流程:\n- 创建初始迁移文件\n- 配置迁移脚本命令\n- 设置迁移回滚机制\n- 开发环境和生产环境迁移策略\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/migrations/migration_lock.toml'', ''package.json''], ''prompt'': ''检查 prisma/migrations/ 目录是否存在迁移文件，验证 package.json 中有 prisma migrate 相关脚本命令''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(338,'ISSUE-F002~c6',NULL,replace('创建种子数据和工具:\n- seed.ts 种子数据脚本\n- 开发环境测试数据生成\n- Prisma Studio 配置\n- 数据库查询工具和辅助函数\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/seed.ts'', ''package.json''], ''prompt'': ''检查 prisma/seed.ts 是否存在，验证种子数据包含测试用户、Agent和场景配置，确认有 db:seed 脚本''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(339,'ISSUE-F002~c7',NULL,replace('优化数据库性能:\n- 为常用查询字段添加索引\n- 配置复合索引\n- 设置适当的外键约束\n- 文档记录查询优化策略\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''prisma/schema.prisma''], ''prompt'': ''检查 schema.prisma 中关键模型是否有 @@index 定义，验证常用查询字段(如 userId, agentId, createdAt)有索引''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(340,'ISSUE-F003~c1',NULL,replace('配置 Express 应用:\n- 安装 Express 和相关中间件\n- 配置 body-parser, cors, helmet\n- 设置应用入口文件 (app.ts, server.ts)\n- 配置开发热重载\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/app.ts'', ''apps/server/src/server.ts'', ''apps/server/package.json''], ''prompt'': ''检查 apps/server/src/app.ts 和 server.ts 是否存在，验证 Express 应用配置包含 cors, helmet, body-parser 中间件''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(341,'ISSUE-F003~c2',NULL,replace('建立模块化路由结构:\n- routes/ 目录结构\n- API 版本控制 (v1, v2)\n- 路由模块化组织 (auth, user, agent, chat, match等)\n- 路由前缀和命名规范\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/index.ts'', ''apps/server/src/routes/v1/''], ''prompt'': ''检查 apps/server/src/routes/ 目录结构，验证有 v1 或版本控制目录，确认路由按功能模块组织''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(342,'ISSUE-F003~c3',NULL,replace('配置全局中间件:\n- 请求日志中间件\n- 错误处理中间件\n- 请求超时处理\n- 请求 ID 注入\n- 压缩和静态文件服务\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/''], ''prompt'': ''检查中间件配置文件，验证有 errorHandler, requestLogger, timeout 等全局中间件实现''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(343,'ISSUE-F003~c4',NULL,replace('建立标准化响应:\n- ApiResponse 统一响应类\n- 错误类和错误码定义\n- HTTP 状态码映射\n- 异常捕获和转换\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/response.ts'', ''apps/server/src/errors/''], ''prompt'': ''检查是否有统一的响应和错误处理类，验证 ApiResponse 包含 success, data, message, errorCode 字段''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(344,'ISSUE-F003~c5',NULL,replace('配置运行环境:\n- 不同环境的配置加载\n- 开发服务器启动脚本\n- 生产环境 PM2/Docker 配置\n- 端口和主机配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/package.json'', ''apps/server/Dockerfile''], ''prompt'': ''检查 package.json 脚本，验证有 dev, build, start, 和 docker 相关命令，确认端口配置正确''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(345,'ISSUE-F003~c6',NULL,replace('实现系统健康检查:\n- /health 健康检查端点\n- /ready 就绪探针\n- /metrics 指标端点(基础)\n- 数据库连接状态检查\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/health.ts''], ''prompt'': ''检查是否有 /health 和 /ready 端点实现，验证返回包含 status, timestamp, checks 等字段''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(346,'ISSUE-F004~c1',NULL,replace('配置 Expo 项目:\n- 使用 create-expo-app 初始化项目\n- 配置 Expo SDK 和依赖\n- 设置 TypeScript 支持\n- 配置 metro bundler\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/app.json'', ''apps/mobile/package.json''], ''prompt'': ''检查 apps/mobile/ 目录是否有 Expo 项目结构，验证 app.json 和 package.json 配置正确''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(347,'ISSUE-F004~c2',NULL,replace('设置导航系统:\n- 配置 React Navigation\n- 设置底部 Tab 导航\n- 配置 Stack 导航器\n- 实现深层链接配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/navigation/'', ''apps/mobile/app/''], ''prompt'': ''检查导航配置，验证使用 Expo Router 或 React Navigation，确认有 Tab 和 Stack 导航结构''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(348,'ISSUE-F004~c3',NULL,replace('配置状态管理:\n- 集成 Zustand/Redux Toolkit\n- 设置用户状态存储\n- 配置持久化存储(AsyncStorage)\n- 状态类型定义\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/store/''], ''prompt'': ''检查状态管理配置，验证有 store 定义、持久化配置和类型定义''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(349,'ISSUE-F004~c4',NULL,replace('配置 API 通信:\n- 集成 Axios/Fetch\n- 配置请求/响应拦截器\n- 设置 API 基础 URL\n- 请求错误处理和重试机制\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/api/client.ts''], ''prompt'': ''检查 API 客户端配置，验证有 baseURL 配置、拦截器处理和错误处理''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(350,'ISSUE-F004~c5',NULL,replace('设置 UI 基础设施:\n- 配置 NativeWind/Tamagui/原生样式\n- 设置主题和颜色系统\n- 创建基础组件库(Button, Input, Card等)\n- 响应式布局适配\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/'', ''apps/mobile/src/theme/''], ''prompt'': ''检查 UI 组件和主题配置，验证有设计系统、主题定义和基础组件实现''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(351,'ISSUE-F004~c6',NULL,replace('配置原生权限:\n- 相机权限配置\n- 位置权限配置\n- 通知权限配置\n- 存储权限配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/app.json''], ''prompt'': ''检查 app.json 中的权限配置，验证有 camera, location, notifications 等权限声明''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(352,'ISSUE-F005~c1',NULL,replace('配置日志库:\n- 集成 Pino/Winston 日志库\n- 配置日志级别 (DEBUG, INFO, WARN, ERROR)\n- 设置结构化日志格式(JSON)\n- 配置日志轮转和清理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/logger.ts'', ''apps/server/src/config/logger.ts''], ''prompt'': ''检查日志配置，验证使用 Pino 或 Winston，确认日志级别可配置且支持结构化输出''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(353,'ISSUE-F005~c2',NULL,replace('实现请求上下文:\n- 请求 ID 生成和传播\n- 用户上下文注入\n- 异步上下文存储 (AsyncLocalStorage)\n- 链路追踪支持\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/requestContext.ts''], ''prompt'': ''检查请求上下文实现，验证每个请求有唯一 requestId，确认日志中包含 trace 信息''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(354,'ISSUE-F005~c3',NULL,replace('配置日志输出:\n- 控制台输出(开发环境)\n- 文件输出(按日期/大小轮转)\n- 错误日志单独输出\n- 可选: 远程日志服务集成\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/config/logger.ts'', ''logs/''], ''prompt'': ''检查日志输出配置，验证有 console 和 file transports，确认错误日志单独存储''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(355,'ISSUE-F005~c4',NULL,replace('实现日志脱敏:\n- 密码、Token 自动脱敏\n- 手机号、邮箱部分隐藏\n- 可配置的脱敏字段列表\n- 脱敏规则测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/logger.ts'', ''apps/server/src/utils/sanitizer.ts''], ''prompt'': ''检查日志脱敏实现，验证密码、token 等敏感字段被自动脱敏，确认有脱敏测试''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(356,'ISSUE-F005~c5',NULL,replace('移动端日志系统:\n- 移动端日志库集成\n- 日志本地存储\n- 崩溃日志收集\n- 日志上传机制\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/utils/logger.ts''], ''prompt'': ''检查移动端日志配置，验证有日志库集成和崩溃报告配置''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
