INSERT INTO acceptance_criteria VALUES(384,'CRIT-INF005-5',NULL,replace('记录推送送达、打开、转化数据。\n支持推送效果分析报表。\n实现失败重推机制。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- notification/analytics'', ''expected'': ''All analytics tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(385,'CRIT-INF006-1',NULL,replace('实现 SMTP 发送适配器。\n集成 SendGrid API 适配器。\n集成 AWS SES 适配器。\n支持发送渠道故障切换。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- email/adapters'', ''expected'': ''All adapter tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(386,'CRIT-INF006-2',NULL,replace('支持 HTML/文本邮件模板。\n实现模板变量注入和多语言支持。\n提供模板版本管理和预览功能。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- email/templates'', ''expected'': ''All template tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(387,'CRIT-INF006-3',NULL,replace('支持注册验证邮件。\n支持密码重置邮件。\n支持系统通知邮件。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- email/transactional'', ''expected'': ''All transactional tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(388,'CRIT-INF006-4',NULL,replace('支持批量邮件队列发送。\n实现发送速率控制。\n支持发送任务暂停/恢复。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- email/bulk'', ''expected'': ''All bulk tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(389,'CRIT-INF006-5',NULL,replace('实现邮件打开/点击追踪。\n处理退信和投诉反馈。\n维护邮箱信誉列表。\n','\n',char(10)),'functional','{''test'': {''command'': ''npm test -- email/tracking'', ''expected'': ''All tracking tests passed''}}',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(390,'ISSUE-INT001a~c1',NULL,replace('VisionShare端到端测试:\n- 需求发布到接单完整流程\n- 相机拍照上传与AI脱敏处理\n- 照片查看与积分支付流程\n- AI相册智能检索功能验证\n- 移动端与后端API集成验证\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/e2e/tests/visionshare/'', ''apps/e2e/tests/scenarios/visionshare.test.ts''], ''prompt'': ''检查VisionShare端到端测试实现，验证包含完整的场景测试用例，覆盖需求发布、接单、拍照上传、AI脱敏、积分支付等全流程''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(391,'ISSUE-INT001a~c2',NULL,replace('AgentDate端到端测试:\n- 交友画像配置完整流程\n- Agent主动匹配推荐机制\n- Agent间对话匹配流程\n- 双向同意引荐机制验证\n- 人机切换场景测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/e2e/tests/agentdate/'', ''apps/e2e/tests/scenarios/agentdate.test.ts''], ''prompt'': ''检查AgentDate端到端测试实现，验证包含交友画像配置、匹配推荐、Agent对话、双向引荐等完整流程测试''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(392,'ISSUE-INT001b~c3',NULL,replace('AgentJob端到端测试:\n- 求职者画像与简历配置\n- 招聘方职位发布流程\n- 简历智能匹配筛选验证\n- 薪资协商与面试安排流程\n- 招聘场景人机切换测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/e2e/tests/agentjob/'', ''apps/e2e/tests/scenarios/agentjob.test.ts''], ''prompt'': ''检查AgentJob端到端测试实现，验证包含求职招聘全流程测试，涵盖画像配置、职位发布、智能匹配、薪资协商等场景''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(393,'ISSUE-INT001b~c4',NULL,replace('AgentAd端到端测试:\n- 消费需求画像配置\n- 商家优惠配置发布\n- Agent优惠协商谈判流程\n- 一键购买与优惠码验证\n- 多商家比价场景测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/e2e/tests/agentad/'', ''apps/e2e/tests/scenarios/agentad.test.ts''], ''prompt'': ''检查AgentAd端到端测试实现，验证包含消费广告场景完整测试，涵盖画像配置、优惠协商、一键购买等核心功能''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(394,'ISSUE-INT001c~c5',NULL,replace('跨模块集成验证:\n- Auth-Core-Matching层间API契约测试\n- AI服务与核心业务模块集成验证\n- 通信层与各场景模块消息流转测试\n- 信用积分系统全链路验证\n- Socket.io实时通信集成测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/e2e/tests/integration/'', ''apps/e2e/tests/contracts/'', ''apps/e2e/tests/websocket/''], ''prompt'': ''检查跨模块集成测试实现，验证API契约测试、模块间消息流转测试、全链路集成测试覆盖率''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(395,'ISSUE-INT001c~c6',NULL,replace('测试框架集成验证:\n- Jest单元测试覆盖率达标(>80%)\n- API集成测试通过率100%\n- E2E端到端测试稳定性验证\n- 移动端测试框架集成\n- 测试报告自动生成与展示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''coverage/'', ''apps/server/jest.config.js'', ''apps/mobile/jest.config.js'', ''apps/e2e/playwright.config.ts''], ''prompt'': ''检查测试框架集成情况，验证测试覆盖率报告配置，确认Jest、API测试、E2E测试、移动端测试均正常运行并生成报告''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(396,'ISSUE-INT002a~c1',NULL,replace('API性能测试与优化:\n- 核心API响应时间基准测试(目标P95<200ms)\n- 高并发场景API吞吐量测试\n- 数据库查询性能分析与优化\n- 缓存策略实施与验证(Redis)\n- API限流与熔断机制压力测试\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查API性能测试实现，验证有k6或Artillery压测脚本，包含基准测试、并发测试、限流测试，确认性能优化方案'', ''context_files'': [''apps/server/perf/'', ''perf/api-load-test.yml'', ''apps/server/src/middleware/rateLimiter.ts'']}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(397,'ISSUE-INT002a~c2',NULL,replace('数据库性能优化:\n- 慢查询分析与索引优化\n- 高并发读写性能测试\n- Prisma连接池配置优化\n- 复杂查询(匹配算法)性能优化\n- 数据库分表分库策略评估\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查数据库性能优化实现，验证慢查询日志配置、索引优化方案、Prisma连接池配置，确认性能测试报告'', ''context_files'': [''apps/server/prisma/schema.prisma'', ''apps/server/src/services/matching/'', ''perf/db-perf-report.md'']}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(398,'ISSUE-INT002b~c1',NULL,replace('WebSocket性能测试:\n- Socket.io连接数压力测试(目标1000+并发)\n- 消息广播延迟测试(目标<100ms)\n- 房间系统并发性能验证\n- 在线状态同步性能测试\n- 连接断开重连稳定性测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''perf/websocket-load-test.yml'', ''apps/server/src/socket/'', ''apps/e2e/tests/websocket/websocket-perf.test.ts''], ''prompt'': ''检查WebSocket性能测试实现，验证有Socket.io压测脚本，包含连接并发、消息延迟、房间系统等场景测试''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(399,'ISSUE-INT002b~c2',NULL,replace('AI服务性能测试:\n- LLM API响应时间优化与测试\n- AI服务熔断器触发与恢复验证\n- 多LLM降级策略压力测试\n- 图像分析Vision API性能测试\n- AI服务队列与并发控制验证\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/ai/'', ''apps/server/src/circuit-breaker/'', ''perf/ai-service-load-test.yml''], ''prompt'': ''检查AI服务性能测试实现，验证熔断器配置、降级策略、并发控制，确认有AI服务压力测试脚本''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(400,'ISSUE-INT002c~c1',NULL,replace('移动端性能优化:\n- 应用启动时间测试与优化(目标<3s)\n- 列表滚动性能测试(目标60fps)\n- 内存占用分析与优化\n- 图片加载与缓存性能优化\n- 电池消耗与网络流量优化\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/performance/'', ''apps/mobile/e2e/perf.test.ts'', ''apps/mobile/metro.config.js''], ''prompt'': ''检查移动端性能测试实现，验证有性能测试方案，包含启动时间、滚动性能、内存分析、图片缓存等测试''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(401,'ISSUE-INT002c~c2',NULL,replace('全链路压力测试:\n- 端到端场景压测(模拟真实用户行为)\n- 峰值流量承载能力测试\n- 系统瓶颈识别与优化报告\n- 监控告警阈值配置验证\n- 性能测试报告与优化建议文档\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''perf/full-load-test.yml'', ''perf/reports/'', ''docs/PERFORMANCE_REPORT.md'', ''apps/server/src/monitoring/''], ''prompt'': ''检查全链路压力测试实现，验证有完整压测方案、瓶颈分析报告、性能优化建议，确认监控告警配置''}}',1,'sufficient','required','required','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(402,'ISSUE-INT003~c1',NULL,replace('演示环境准备:\n- 独立演示环境服务器部署(Demo环境)\n- 演示环境数据库初始化与数据隔离\n- 域名与SSL证书配置(demo.bridgeai.com)\n- CDN加速与静态资源优化\n- 演示环境监控与日志配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''deploy/demo/'', ''infra/terraform/demo.tf'', ''deploy/demo/docker-compose.yml'', ''docs/DEMO_ENV_SETUP.md''], ''prompt'': ''检查演示环境部署配置，验证有独立的Demo环境部署脚本，确认域名、SSL、CDN配置正确，检查监控和日志配置''}}',1,'sufficient','required','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(403,'ISSUE-INT003~c2',NULL,replace('演示数据准备:\n- 演示用户账号数据(5个预设账号)\n- VisionShare演示任务数据(10个示例任务)\n- AgentDate演示用户画像数据\n- AgentJob演示职位与简历数据\n- AgentAd演示商家优惠与消费需求数据\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/prisma/seeds/demo/'', ''apps/server/scripts/seed-demo.ts'', ''docs/DEMO_DATA.md''], ''prompt'': ''检查演示数据准备实现，验证有演示数据种子脚本(seed scripts)，包含各场景的预设数据，确认数据脚本可重复执行''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(404,'ISSUE-INT003~c3',NULL,replace('演示脚本编写:\n- VisionShare场景演示脚本(3分钟)\n- AgentDate场景演示脚本(4分钟)\n- AgentJob场景演示脚本(4分钟)\n- AgentAd场景演示脚本(4分钟)\n- 演示流程时间控制与转场设计\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''docs/demo-scripts/'', ''docs/DEMO_SCRIPT_VISIONSHARE.md'', ''docs/DEMO_SCRIPT_AGENTDATE.md'', ''docs/DEMO_SCRIPT_AGENTJOB.md'', ''docs/DEMO_SCRIPT_AGENTAD.md''], ''prompt'': ''检查演示脚本文档，验证有完整的场景演示脚本，包含操作步骤、讲解词、时间控制，确认脚本逻辑清晰''}}',1,'sufficient','not_needed','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(405,'ISSUE-INT003~c4',NULL,replace('演示应急预案:\n- 网络延迟/断网场景应对策略\n- AI服务故障回退方案(预设回复)\n- 演示数据重置脚本(快速恢复)\n- 热备份演示环境配置\n- 常见问题FAQ与应对方案\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''docs/DEMO_CONTINGENCY_PLAN.md'', ''scripts/demo-reset.sh'', ''deploy/demo/backup.yml'', ''docs/DEMO_FAQ.md''], ''prompt'': ''检查演示应急预案文档，验证有故障应对策略、数据重置脚本、热备份方案，确认有FAQ文档''}}',1,'sufficient','not_needed','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(406,'ISSUE-INT003~c5',NULL,replace('演示录制准备:\n- 核心场景演示视频录制(带旁白)\n- 移动端操作演示录屏\n- Web端与移动端双屏演示方案\n- 演示视频剪辑与字幕添加\n- 备用演示视频离线存储\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''docs/demo-videos/'', ''docs/DEMO_VIDEO_GUIDE.md'', ''assets/demo-recordings/''], ''prompt'': ''检查演示录制资源，验证有演示视频文件，包含各场景录制，确认有备用离线演示方案''}}',1,'sufficient','not_needed','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(407,'ISSUE-INT003~c6',NULL,replace('Demo Go-Live准备:\n- 演示前检查清单(Pre-demo Checklist)\n- 演示设备与环境测试\n- 演示者培训与彩排记录\n- 演示反馈收集表单\n- 演示后数据清理与报告\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''docs/DEMO_CHECKLIST.md'', ''docs/DEMO_PREPARATION_LOG.md'', ''docs/DEMO_FEEDBACK_FORM.md'', ''docs/DEMO_REPORT_TEMPLATE.md''], ''prompt'': ''检查演示准备文档，验证有Pre-demo检查清单、设备测试记录、培训文档，确认有演示反馈收集机制''}}',1,'sufficient','not_needed','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(408,'ISSUE-JOB001~c1',NULL,replace('模型设计:\n- 求职者Agent类型定义(JobSeekerAgent)\n- 基本信息字段(姓名、联系方式、所在地)\n- 专业技能标签体系\n- 工作经历结构化存储\n- 教育背景信息\n- 期望薪资范围与职位类型\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/shared/src/types/jobSeeker.ts'', ''packages/shared/src/schemas/jobSeekerSchema.ts''], ''prompt'': ''检查求职画像数据模型，验证有JobSeekerProfile类型定义，包含技能、工作经历、教育背景、期望薪资等字段，使用Zod进行验证''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(409,'ISSUE-JOB001~c2',NULL,replace('AI提炼:\n- 自然语言简历解析\n- 关键信息自动提取(技能/经验/学历)\n- 技能标签智能匹配与标准化\n- 工作经历时间线生成\n- 简历质量评分与优化建议\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/job/resumeExtraction.ts'', ''apps/server/src/ai/prompts/resumeExtraction.ts''], ''prompt'': ''检查AI简历提炼服务，验证有ResumeExtractionService，能将自然语言转换为结构化简历数据，包含技能提取和工作经历解析''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(410,'ISSUE-JOB001~c3',NULL,replace('隐私管理:\n- 简历可见性设置(公开/仅投递/隐藏)\n- 敏感信息脱敏处理(手机号/邮箱)\n- 联系方式访问权限控制\n- 投递记录追踪\n- 简历撤回功能\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''packages/shared/src/types/resumePrivacy.ts'', ''apps/server/src/services/job/resumePrivacyService.ts''], ''prompt'': ''检查简历隐私控制，验证有ResumePrivacySettings类型，支持可见性设置和敏感信息脱敏，能通过中介联系保护隐私''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(411,'ISSUE-JOB001~c4',NULL,replace('CRUD接口:\n- 创建/更新简历API\n- 简历版本管理\n- 多简历支持(针对不同职位)\n- 简历预览功能\n- 简历导出(PDF/Markdown)\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/routes/job/resumeRoutes.ts'', ''apps/server/src/controllers/job/resumeController.ts''], ''prompt'': ''检查简历API，验证有完整的RESTful端点(/api/job/resumes)，支持CRUD操作、版本管理和多简历功能''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(412,'ISSUE-JOB001~c5',NULL,replace('UI实现:\n- 简历表单组件(分步骤填写)\n- 技能标签选择器\n- 工作经历时间线编辑\n- 简历预览页面\n- 隐私设置界面\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Job/ResumeEditScreen.tsx'', ''apps/mobile/src/screens/Job/ResumePreviewScreen.tsx''], ''prompt'': ''检查移动端简历界面，验证有ResumeEditScreen和ResumePreviewScreen组件，支持分步骤填写和技能标签选择''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(413,'ISSUE-JOB001~c6',NULL,replace('投递系统:\n- 向职位投递简历功能\n- 投递状态追踪(已投递/已查看/感兴趣/不合适)\n- 投递历史记录\n- 投递反馈通知\n- 批量投递限制管理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/job/resumeSubmissionService.ts'', ''apps/mobile/src/screens/Job/SubmissionHistoryScreen.tsx''], ''prompt'': ''检查简历投递系统，验证有ResumeSubmission模型和投递状态管理，支持向职位投递和状态追踪功能''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
