INSERT INTO acceptance_criteria VALUES(441,'ISSUE-SEC001~c2',NULL,replace('权限控制系统:\n- 定义权限列表(资源+操作)\n- 权限与角色关联\n- 支持细粒度权限(resource:action)\n- 权限验证中间件\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/models/permission.ts'', ''apps/server/src/middleware/rbac.ts''], ''prompt'': ''检查权限系统，验证有Permission模型，支持resource:action格式，确认权限中间件authorize()正确实现''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
