INSERT INTO acceptance_criteria VALUES(445,'ISSUE-SEC001~c6',NULL,replace('权限文档与测试:\n- API权限矩阵文档\n- 角色权限对照表\n- 权限测试用例覆盖\n- 权限错误响应规范\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''docs/permissions.md'', ''apps/server/tests/rbac.test.ts''], ''prompt'': ''检查权限文档，验证有API权限矩阵，角色权限对照表，确认测试用例覆盖所有权限场景''}}',1,'sufficient','not_needed','not_needed','required','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(446,'ISSUE-SEC002~c1',NULL,replace('加密方案设计:\n- 静态数据加密(AES-256)\n- 传输数据加密(TLS 1.3)\n- 敏感字段识别与标记\n- 加密算法选择与配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/encryption.ts'', ''apps/server/src/config/security.ts''], ''prompt'': ''检查数据加密策略，验证使用AES-256加密静态数据，TLS 1.3保护传输，确认敏感字段有标记''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(447,'ISSUE-SEC002~c2',NULL,replace('密钥管理:\n- 主密钥安全存储\n- 数据加密密钥(DEK)管理\n- 密钥轮换机制\n- 密钥访问审计\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/keyManagement.ts'', ''.env.example'', ''apps/server/src/config/kms.ts''], ''prompt'': ''检查密钥管理系统，验证主密钥存储在环境变量/KMS，DEK分离存储，确认有密钥轮换机制''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(448,'ISSUE-SEC002~c3',NULL,replace('字段级加密:\n- 手机号加密存储\n- 身份证/证件信息加密\n- 聊天记录内容加密\n- 加密字段自动编解码\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/encryption.ts'', ''prisma/schema.prisma''], ''prompt'': ''检查数据库字段加密，验证敏感字段(phone, idCard)加密存储，确认Prisma中间件自动加解密''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(449,'ISSUE-SEC002~c4',NULL,replace('数据脱敏:\n- 日志中敏感信息脱敏\n- API响应数据脱敏\n- 手机号/邮箱部分隐藏\n- 脱敏规则配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/mask.ts'', ''apps/server/src/middleware/logging.ts''], ''prompt'': ''检查数据脱敏，验证日志中敏感信息被脱敏，API响应中手机号显示为138****8888格式，确认有脱敏工具函数''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(450,'ISSUE-SEC002~c5',NULL,replace('个人信息保护:\n- PII数据识别标记\n- 数据访问权限控制\n- 数据导出加密\n- 数据删除安全处理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/models/user.ts'', ''apps/server/src/services/dataExport.ts'', ''apps/server/src/services/gdpr.ts''], ''prompt'': ''检查PII保护，验证有PII数据标识，访问需要特殊权限，确认数据导出加密，删除时安全擦除''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(451,'ISSUE-SEC002~c6',NULL,replace('性能与监控:\n- 加密操作性能优化\n- 加密服务健康检查\n- 密钥操作审计日志\n- 加密异常告警\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/encryption.ts'', ''apps/server/src/services/monitoring.ts''], ''prompt'': ''检查加密性能，验证有缓存机制减少重复加密，确认有健康检查端点，审计日志记录密钥操作''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(452,'ISSUE-SEC003~c1',NULL,replace('API限流:\n- 基于IP的限流\n- 基于用户的限流\n- 不同端点差异化限流\n- 限流响应头(X-RateLimit-*)\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查API限流，验证使用express-rate-limit或redis-rate-limiter，确认IP和用户级别限流，响应头包含限流信息'', ''context_files'': [''apps/server/src/middleware/rateLimiter.ts'', ''apps/server/src/config/rateLimit.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(453,'ISSUE-SEC003~c2',NULL,replace('DDoS攻击防护:\n- 异常流量检测\n- 自动IP封禁机制\n- 请求频率异常告警\n- 慢速攻击防护\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查DDoS防护，验证有异常流量检测，确认自动封禁高频IP，有慢速攻击防护(timeout配置)'', ''context_files'': [''apps/server/src/middleware/ddosProtection.ts'', ''apps/server/src/services/firewall.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(454,'ISSUE-SEC003~c3',NULL,replace('IP访问控制:\n- IP白名单机制\n- IP黑名单机制\n- 地理位置限制\n- IP信誉检查\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查IP黑白名单，验证有IP过滤中间件，支持白名单优先或黑名单模式，确认可配置地理位置限制'', ''context_files'': [''apps/server/src/middleware/ipFilter.ts'', ''apps/server/src/config/ipList.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(455,'ISSUE-SEC003~c4',NULL,replace('请求安全:\n- 请求体大小限制\n- Content-Type校验\n- 恶意Payload检测\n- SQL注入/XSS防护\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查请求安全，验证有body-parser大小限制，helmet中间件配置，输入验证防止SQL注入和XSS'', ''context_files'': [''apps/server/src/middleware/security.ts'', ''apps/server/src/app.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(456,'ISSUE-SEC003~c5',NULL,replace('跨域与安全头:\n- CORS白名单配置\n- 安全响应头设置\n- CSP内容安全策略\n- HSTS严格传输安全\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查CORS配置，验证有白名单限制，确认设置X-Content-Type-Options/X-Frame-Options/CSP等安全头'', ''context_files'': [''apps/server/src/middleware/cors.ts'', ''apps/server/src/app.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(457,'ISSUE-SEC003~c6',NULL,replace('安全监控:\n- 攻击行为日志记录\n- 异常请求统计分析\n- 安全事件告警通知\n- 封禁IP管理界面\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查安全监控，验证有攻击日志记录，异常统计报表，确认有管理界面查看封禁IP和解封功能'', ''context_files'': [''apps/server/src/services/securityMonitor.ts'', ''apps/server/src/routes/admin/index.ts'']}}',1,'sufficient','not_needed','required','required','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(458,'ISSUE-SEC004~c1',NULL,replace('基础上传验证:\n- 允许的图片格式(白名单)\n- 文件大小限制\n- 文件头Magic Number校验\n- 双重扩展名检查\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/middleware/upload.ts'', ''apps/server/src/utils/fileValidator.ts''], ''prompt'': ''检查文件上传验证，验证只允许jpg/png/gif/webp，文件大小限制，确认Magic Number校验文件真实类型''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(459,'ISSUE-SEC004~c2',NULL,replace('内容安全:\n- 色情图片检测\n- 暴力恐怖图片识别\n- 敏感政治内容检测\n- 图片分类与标签\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/imageModeration.ts'', ''apps/server/src/services/ai/imageAnalysis.ts''], ''prompt'': ''检查图片内容检测，验证集成阿里云/腾讯云内容安全API或自研AI模型，确认色情/暴力检测准确率高''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(460,'ISSUE-SEC004~c3',NULL,replace('安全扫描:\n- 文件病毒扫描\n- 嵌入式恶意代码检测\n- 可执行文件伪装检查\n- 扫描结果缓存\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/virusScan.ts'', ''apps/server/src/config/clamav.ts''], ''prompt'': ''检查病毒扫描，验证集成ClamAV或其他杀毒引擎，确认检测EICAR测试文件，扫描结果有缓存''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(461,'ISSUE-SEC004~c4',NULL,replace('元数据安全:\n- EXIF数据清理\n- GPS位置信息移除\n- 拍摄设备信息清除\n- 缩略图重建\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/utils/imageProcessor.ts''], ''prompt'': ''检查图片元数据处理，验证使用sharp/exiftool清理EXIF，确认GPS和设备信息已移除，保留必要的方向信息''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(462,'ISSUE-SEC004~c5',NULL,replace('安全存储:\n- 文件名随机化重命名\n- 分离存储目录结构\n- 存储路径不直接暴露\n- CDN访问控制\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/storage.ts'', ''apps/server/src/routes/images.ts''], ''prompt'': ''检查存储安全，验证文件名使用UUID随机化，确认存储路径按日期分片，通过代理访问而非直接URL''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(463,'ISSUE-SEC004~c6',NULL,replace('审计与管理:\n- 上传记录审计日志\n- 违规图片自动标记\n- 用户上传历史追踪\n- 违规用户限制上传\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/uploadAudit.ts'', ''apps/server/src/models/uploadLog.ts''], ''prompt'': ''检查上传审计，验证有上传日志记录，违规图片标记并隔离，确认违规用户被限制上传权限''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(464,'ISSUE-SEC005~c1',NULL,replace('举报功能:\n- 多类型举报(消息/用户/内容)\n- 举报原因选择\n- 证据截图上传\n- 举报记录管理\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/models/report.ts'', ''apps/server/src/routes/reports.ts''], ''prompt'': ''检查举报系统，验证有Report模型，支持message/user/content类型，确认可上传证据，有举报记录查询''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(465,'ISSUE-SEC005~c2',NULL,replace('审核流程:\n- 待审核队列管理\n- 人工审核界面\n- AI预审核辅助\n- 审核状态流转\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/moderationQueue.ts'', ''apps/admin/src/pages/ModerationDashboard.tsx''], ''prompt'': ''检查审核工作流，验证有审核队列，管理员可查看处理，AI预标记可疑内容，状态从pending到resolved''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(466,'ISSUE-SEC005~c3',NULL,replace('违规处置:\n- 内容删除/隐藏\n- 用户警告通知\n- 临时禁言/封禁\n- 信用分扣减\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/violationHandler.ts'', ''apps/server/src/services/creditService.ts''], ''prompt'': ''检查违规处理，验证可删除/隐藏违规内容，用户收到警告，支持禁言封禁，信用分系统联动扣分''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(467,'ISSUE-SEC005~c4',NULL,replace('申诉流程:\n- 用户申诉提交\n- 申诉审核流程\n- 处罚撤销机制\n- 信用分恢复\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/models/appeal.ts'', ''apps/server/src/services/appealService.ts''], ''prompt'': ''检查申诉系统，验证用户可提交申诉，有独立审核流程，申诉成功可撤销处罚和恢复信用分''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(468,'ISSUE-SEC005~c5',NULL,replace('内容过滤:\n- 敏感词库管理\n- 实时消息过滤\n- 正则匹配支持\n- 分级屏蔽策略\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/sensitiveWordFilter.ts'', ''apps/server/src/config/sensitiveWords.ts''], ''prompt'': ''检查敏感词过滤，验证有敏感词库，实时检测消息内容，支持正则，分级处理(提示/替换/拦截)''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(469,'ISSUE-SEC005~c6',NULL,replace('数据与报表:\n- 审核量统计\n- 违规类型分析\n- 审核效率指标\n- 举报准确率计算\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/admin/src/pages/ModerationStats.tsx'', ''apps/server/src/services/moderationAnalytics.ts''], ''prompt'': ''检查审核统计，验证有审核量/处理时效报表，违规类型分布，确认举报准确率统计(有效举报/总举报)''}}',1,'sufficient','not_needed','required','required','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(470,'ISSUE-T001~c1',NULL,replace('配置Jest测试运行器:\n- 根目录jest.config.js配置\n- 各workspace的jest配置继承和扩展\n- TypeScript支持(ts-jest配置)\n- 测试文件匹配规则\n- 测试超时和并发配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''jest.config.js'', ''jest.config.ts'', ''apps/server/jest.config.js'', ''packages/shared/jest.config.js''], ''prompt'': ''检查jest.config.js或jest.config.ts是否存在且配置完整，验证包含ts-jest配置、测试匹配模式、覆盖率收集配置''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(471,'ISSUE-T001~c2',NULL,replace('配置测试环境隔离:\n- 独立的测试数据库配置\n- 测试环境变量(.env.test)\n- 测试数据库自动创建和销毁\n- 测试数据清理机制\n- 并行测试安全隔离\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.env.test'', ''apps/server/src/tests/setup.ts'', ''apps/server/src/tests/teardown.ts''], ''prompt'': ''检查测试环境配置，验证有.env.test文件，测试数据库配置与生产隔离，确认有测试数据清理脚本''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(472,'ISSUE-T001~c3',NULL,replace('建立Mock工具集:\n- Jest Mock函数配置\n- Prisma Client自动Mock\n- 外部API Mock工具\n- Redis/缓存Mock\n- 文件系统Mock\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''__mocks__/prisma.ts'', ''apps/server/src/tests/mocks/index.ts'', ''apps/server/src/tests/helpers/mock-factory.ts''], ''prompt'': ''检查Mock工具配置，验证有__mocks__目录，Prisma Client Mock实现，外部服务Mock工具集''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(473,'ISSUE-T001~c4',NULL,replace('实现测试数据工厂:\n- 使用faker.js生成测试数据\n- 用户数据工厂\n- Agent数据工厂\n- 消息/聊天数据工厂\n- 数据工厂组合和关联\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/factories/user.factory.ts'', ''apps/server/src/tests/factories/agent.factory.ts'', ''apps/server/src/tests/factories/index.ts''], ''prompt'': ''检查测试数据工厂实现，验证有factories目录，包含user、agent、message等数据工厂，使用faker.js生成数据''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(474,'ISSUE-T001~c5',NULL,replace('配置代码覆盖率:\n- Jest覆盖率收集配置\n- 覆盖率阈值设置(行/分支/函数)\n- 覆盖率报告格式(html/text/lcov)\n- 排除文件配置\n- CI集成\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''jest.config.js'', ''.github/workflows/test.yml''], ''prompt'': ''检查Jest覆盖率配置，验证覆盖率阈值设置(建议80%)，确认有多种报告格式配置，检查CI集成''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(475,'ISSUE-T001~c6',NULL,replace('编写示例单元测试:\n- 服务层单元测试示例\n- 工具函数单元测试示例\n- Middleware单元测试示例\n- 测试最佳实践文档\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/services/__tests__/auth.service.test.ts'', ''apps/server/src/utils/__tests__/validation.test.ts''], ''prompt'': ''检查示例测试文件，验证有.service.test.ts、.util.test.ts等测试文件，测试用例覆盖正常和异常场景''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(476,'ISSUE-T002~c1',NULL,replace('配置Supertest测试框架:\n- Supertest库集成\n- Express应用实例化辅助\n- HTTP请求基类封装\n- 全局请求默认值配置\n- 错误处理测试支持\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/integration/setup.ts'', ''apps/server/src/tests/helpers/request.ts''], ''prompt'': ''检查Supertest配置，验证有request基类或辅助函数，能够创建Express测试实例，包含全局错误处理测试''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(477,'ISSUE-T002~c2',NULL,replace('管理测试数据库:\n- 测试前数据库迁移\n- 每个测试用例事务回滚\n- 测试数据种子(seed)\n- 测试数据库清理策略\n- 并发测试隔离\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/integration/setup.ts'', ''apps/server/src/tests/helpers/database.ts''], ''prompt'': ''检查测试数据库管理，验证每个测试后数据清理，有事务回滚或独立数据库实例，确保测试隔离性''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(478,'ISSUE-T002~c3',NULL,replace('创建认证测试工具:\n- JWT Token生成辅助\n- 测试用户登录辅助\n- 权限验证测试用例模板\n- 认证中间件测试\n- 角色权限测试数据\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/helpers/auth.ts'', ''apps/server/src/tests/factories/auth.helper.ts''], ''prompt'': ''检查认证测试辅助工具，验证有JWT生成函数，测试用户自动登录，支持不同角色权限测试''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(479,'ISSUE-T002~c4',NULL,replace('响应验证工具:\n- JSON Schema验证\n- 响应时间断言\n- HTTP状态码验证\n- 响应头验证\n- 错误响应格式验证\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/helpers/validator.ts'', ''apps/server/src/tests/schemas/api-response.schema.ts''], ''prompt'': ''检查API响应验证工具，验证有JSON Schema验证器，响应结构验证，错误响应格式检查工具''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(480,'ISSUE-T002~c5',NULL,replace('编写集成测试示例:\n- 认证API集成测试\n- 用户API集成测试\n- Agent API集成测试\n- 错误场景测试\n- 边界条件测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/integration/auth.integration.test.ts'', ''apps/server/src/tests/integration/user.integration.test.ts''], ''prompt'': ''检查集成测试示例，验证有.auth.integration.test.ts、.user.integration.test.ts等，覆盖CRUD操作和错误场景''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(481,'ISSUE-T002~c6',NULL,replace('API契约测试:\n- OpenAPI/Swagger契约验证 (使用Zod替代)\n- 请求参数验证\n- 响应字段类型检查\n- API版本兼容性测试\n- 破坏性变更检测\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/server/src/tests/helpers/validator.ts''], ''prompt'': ''检查API契约测试配置，验证使用Zod进行JSON Schema验证，有响应字段类型检查和请求参数验证工具''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(482,'ISSUE-T003~c1',NULL,replace('配置React Native测试环境:\n- React Native Jest预设配置\n- Expo Jest配置集成\n- Metro配置用于测试\n- 静态资源Mock配置\n- Native模块自动Mock\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/jest.config.js'', ''apps/mobile/package.json''], ''prompt'': ''检查React Native Jest配置，验证使用react-native预设或expo jest预设，Native模块Mock配置正确''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(483,'ISSUE-T003~c2',NULL,replace('配置Testing Library:\n- @testing-library/react-native安装和配置\n- render、screen工具导入\n- fireEvent事件模拟\n- waitFor异步处理\n- 测试工具函数封装\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/__tests__/utils/test-utils.tsx'', ''apps/mobile/jest.setup.js''], ''prompt'': ''检查Testing Library配置，验证有测试工具封装，包含render、screen、fireEvent等常用方法封装''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(484,'ISSUE-T003~c3',NULL,replace('Mock React Native原生模块:\n- Expo模块Mock(相机、存储、通知等)\n- React Native内置API Mock\n- 第三方库Native代码Mock\n- 平台特定代码Mock(iOS/Android)\n- 传感器和硬件Mock\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/__mocks__/expo-camera.ts'', ''apps/mobile/__mocks__/react-native.ts'', ''apps/mobile/jest.setup.js''], ''prompt'': ''检查Native模块Mock，验证有__mocks__目录包含expo模块、react-native模块的Mock实现''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(485,'ISSUE-T003~c4',NULL,replace('组件测试套件:\n- 基础UI组件测试\n- 表单组件测试\n- 列表组件测试\n- 导航组件测试\n- 状态交互测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/__tests__/*.test.tsx''], ''prompt'': ''检查组件测试示例，验证有基础UI组件测试文件，测试渲染、props传递、事件处理''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(486,'ISSUE-T003~c5',NULL,replace('React Hook测试:\n- @testing-library/react-hooks配置\n- 自定义Hook测试示例\n- API调用Hook测试\n- 状态管理Hook测试\n- 副作用Hook测试\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/hooks/__tests__/useAuth.test.ts'', ''apps/mobile/src/hooks/__tests__/useApi.test.ts''], ''prompt'': ''检查Hook测试配置，验证有renderHook工具使用，自定义Hook测试文件，包含useAuth、useApi等Hook测试''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(487,'ISSUE-T003~c6',NULL,replace('快照测试:\n- Jest快照测试配置\n- 组件快照测试示例\n- 快照更新策略\n- 平台特定快照(iOS/Android)\n- 快照失效检测\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/__tests__/__snapshots__/'', ''apps/mobile/src/components/__tests__/Snapshot.test.tsx''], ''prompt'': ''检查快照测试配置，验证有toMatchSnapshot使用，平台特定快照配置，快照文件管理策略''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(488,'ISSUE-T003~c7',NULL,replace('验证测试框架能正常工作:\n- 运行 npm test 命令无错误\n- 至少一个测试用例通过\n- 生成测试覆盖率报告\n- CI集成验证通过\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/package.json'', ''.github/workflows/ci.yml''], ''prompt'': ''验证测试能正常运行，检查npm test命令执行结果，确认有测试通过和覆盖率报告生成''}}',1,'sufficient','not_needed','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(489,'ISSUE-T004~c1',NULL,replace('配置Detox E2E测试:\n- Detox安装和配置(detox@>=20.x)\n- iOS模拟器测试配置(iPhone 14+, iOS 16+)\n- Android模拟器测试配置(Pixel 6 API 33+)\n- 测试构建配置(debug/release双模式)\n- 设备管理和启动配置\n- **测试超时配置(单测试≤2分钟)**\n- **测试重试机制(失败自动重试最多2次)**\n- **测试并发数限制(iOS≤3, Android≤2)**\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查Detox配置，验证有.detoxrc.js或package.json detox配置，包含iOS和Android构建配置，设备配置正确，有testRunner超时配置≥120000ms，有retries配置'', ''context_files'': [''.detoxrc.js'', ''apps/mobile/package.json'', ''apps/mobile/e2e/config.json''], ''metrics'': [''超时配置: 单测试≤120000ms'', ''重试配置: retries≥1'', ''并发配置: 明确指定worker数量'']}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(490,'ISSUE-T004~c2',NULL,replace('E2E测试数据准备:\n- 测试数据种子脚本(seeds/目录)\n- API辅助数据创建(封装数据工厂)\n- 测试用户自动注册(带唯一标识)\n- 测试数据清理策略(afterEach/afterAll)\n- 数据状态重置(测试间隔离)\n- **性能要求**: 数据创建≤3秒/实体\n- **隔离要求**: 测试用户ID格式 test-${timestamp}-${random}\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查E2E测试数据管理，验证有数据种子脚本，测试前后数据清理，API辅助创建测试数据，数据创建时间≤3秒，用户ID有唯一性保障'', ''context_files'': [''apps/mobile/e2e/support/data-setup.ts'', ''apps/mobile/e2e/support/data-cleanup.ts'', ''apps/mobile/e2e/support/data-factory.ts''], ''metrics'': [''数据创建: ≤3000ms/实体'', ''清理覆盖: 100%测试后清理'', ''唯一性: 用户ID带timestamp+random'']}}',1,'sufficient','required','partial','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(491,'ISSUE-T004~c3',NULL,replace('实现页面对象模式，支持复用和可维护:\n- **基础Page类封装**\n  * 通用等待方法(waitForElement, waitForVisible)\n  * 元素交互封装(tap, typeText, swipe)\n  * 断言辅助方法(assertElementVisible)\n- **登录页面对象(LoginPage)**\n  * 元素定位: testID(''login-email-input''), testID(''login-button'')\n  * 方法: login(email, password), assertLoginSuccess()\n- **首页页面对象(HomePage)**\n  * 元素定位: testID(''home-tab''), testID(''agent-list'')\n  * 方法: navigateToAgent(), assertHomeLoaded()\n- **聊天页面对象(ChatPage)**\n  * 元素定位: testID(''chat-input''), testID(''send-button'')\n  * 方法: sendMessage(text), assertMessageSent(text)\n- **Agent详情页面对象(AgentDetailPage)**\n  * 元素定位: testID(''agent-name''), testID(''edit-button'')\n- **页面元素定位策略**\n  * 优先使用testID，其次accessibilityLabel\n  * 禁止直接使用文字定位(国际化问题)\n- **复用要求**: 每个页面方法可被≥3个测试复用\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查页面对象模式实现，验证有pages目录，包含LoginPage、HomePage、ChatPage等，继承BasePage，使用testID定位元素，无非文字定位，每个页面类有≥5个方法'', ''context_files'': [''apps/mobile/e2e/pages/LoginPage.ts'', ''apps/mobile/e2e/pages/HomePage.ts'', ''apps/mobile/e2e/pages/BasePage.ts'', ''apps/mobile/e2e/pages/ChatPage.ts''], ''metrics'': [''页面覆盖: ≥4个页面类'', ''方法密度: ≥5个方法/页面'', ''定位策略: 100%使用testID'', ''复用性: 方法被≥3测试调用'']}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(492,'ISSUE-T004~c4',NULL,replace('编写核心用户流程测试，每个流程包含完整断言验证:\n- **用户注册登录流程**\n  * 断言: 注册成功后跳转首页\n  * 断言: 登录状态持久化(testID: user-avatar显示)\n  * 断言: token存储成功(AsyncStorage验证)\n- **Agent创建配置流程**\n  * 断言: 表单验证错误显示(testID: error-message)\n  * 断言: 创建成功后跳转Agent详情页\n  * 断言: API响应200且数据正确\n- **匹配和推荐流程**\n  * 断言: 推荐列表加载完成(testID: recommendation-list)\n  * 断言: 匹配按钮可点击并触发API\n  * 断言: 匹配成功状态更新UI\n- **聊天通信流程**\n  * 断言: 消息发送成功(testID: message-sent)\n  * 断言: 消息接收显示在列表\n  * 断言: 未读消息角标更新\n- **任务发布和接单流程**\n  * 断言: 任务创建表单提交成功\n  * 断言: 任务状态流转正确\n  * 断言: 接单后双方通知到达\n- **覆盖率要求: 核心流程≥90%，关键断言≥5个/流程**\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查E2E测试用例，验证有完整用户流程测试，每个测试包含至少5个expect断言，覆盖页面跳转、API响应、数据持久化、UI状态变化'', ''context_files'': [''apps/mobile/e2e/tests/auth-flow.test.ts'', ''apps/mobile/e2e/tests/agent-creation.test.ts'', ''apps/mobile/e2e/tests/matching.test.ts'', ''apps/mobile/e2e/tests/chat-flow.test.ts''], ''metrics'': [''断言密度: ≥5个expect/测试文件'', ''流程覆盖: 5个核心流程全部实现'', ''验证点: 页面跳转+API响应+数据持久化+UI状态'']}}',1,'sufficient','required','partial','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(493,'ISSUE-T004~c5',NULL,replace('E2E测试报告与诊断:\n- **测试报告生成配置**\n  * HTML报告: 美观的可视化报告\n  * JUnit XML: CI集成格式\n  * JSON报告: 程序化分析\n  * 报告包含: 通过率、执行时间、错误详情\n- **失败截图自动捕获**\n  * 失败时自动截图\n  * 截图命名: {test-name}-{timestamp}.png\n  * 截图路径: artifacts/screenshots/\n  * 关联报告: 截图嵌入HTML报告\n- **测试视频录制(可选)**\n  * CI失败时录制视频\n  * 视频长度: 失败前30秒\n  * 存储策略: 仅保留失败视频\n- **测试时间统计**\n  * 单测试执行时间\n  * 套件总执行时间\n  * 历史趋势对比\n- **CI集成和报告上传**\n  * GitHub Actions artifacts上传\n  * 测试失败PR评论\n  * 覆盖率报告(如适用)\n- **质量指标**\n  * 截图成功率: 100%失败用例\n  * 报告生成时间: ≤5秒\n  * 附件大小: 截图≤500KB/张\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查E2E测试报告配置，验证有失败截图机制(100%失败截图)，测试报告输出格式(HTML/JUnit)，CI集成配置，截图嵌入报告，视频录制失败用例'', ''context_files'': [''apps/mobile/e2e/config.json'', ''.github/workflows/e2e.yml'', ''apps/mobile/e2e/reports/''], ''metrics'': [''截图覆盖: 100%失败用例'', ''报告格式: HTML+JUnit+JSON'', ''截图大小: ≤500KB/张'', ''报告生成: ≤5秒'']}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(494,'ISSUE-T004~c6',NULL,replace('E2E并行测试与CI集成:\n- **测试隔离要求**\n  * 每个测试独立数据(testID: test-user-${timestamp})\n  * 测试后数据清理(无论通过/失败)\n  * 测试间无状态依赖\n  * 并发测试用户隔离(不同testUserId)\n- **多设备并行测试配置**\n  * iOS模拟器并发数: ≤3\n  * Android模拟器并发数: ≤2\n  * 设备池管理和分配\n- **测试分片策略**\n  * 按测试文件分片(shard)\n  * 按执行时间均衡分配\n- **CI/CD流水线集成**\n  * GitHub Actions工作流配置\n  * 定时触发(nightly builds)\n  * PR触发(e2e-required标签)\n- **测试环境自动搭建**\n  * 模拟器自动启动/关闭\n  * 测试服务器自动部署\n- **测试结果通知**\n  * Slack通知集成\n  * PR状态检查更新\n  * 失败测试自动重跑\n- **性能指标**\n  * 单测试执行时间≤2分钟\n  * 完整套件≤15分钟(并行后)\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查并行测试配置，验证有CI工作流配置E2E测试，支持多设备并行，有测试结果通知机制，有测试隔离实现(独立用户+数据清理)，单测试≤2分钟'', ''context_files'': [''.github/workflows/e2e.yml'', ''apps/mobile/e2e/parallel-config.js'', ''apps/mobile/e2e/support/test-isolation.ts''], ''metrics'': [''隔离验证: 独立testUserId+自动cleanup'', ''并发配置: iOS≤3, Android≤2'', ''执行时间: 单测试≤120000ms, 全套件≤15min'', ''通知机制: Slack+PR状态更新'']}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(495,'ISSUE-T004~c7',NULL,replace('确保测试长期稳定运行，控制Flaky Test:\n- **Flaky Test检测与处理**\n  * 检测标准: 同一测试在相同代码下失败率>5%\n  * 自动标记: CI中自动标记不稳定测试\n  * 隔离机制: flaky测试移至单独套件\n  * 修复SLA: 标记后3个工作日内修复\n- **测试重试策略**\n  * 自动重试: 失败自动重试2次\n  * 最终判定: 3次中1次通过即算通过\n  * 重试记录: 记录重试次数用于分析\n- **等待策略优化**\n  * 智能等待: 使用waitFor而非固定sleep\n  * 超时阈值: 元素等待≤10秒\n  * 轮询间隔: 200ms自适应轮询\n- **测试执行时间监控**\n  * 单测试时间上限: 2分钟\n  * 平均执行时间追踪\n  * 超时测试自动告警\n- **稳定性指标**\n  * 目标: Flaky rate < 2%\n  * 监控: 每周生成稳定性报告\n  * 告警: flaky rate>5%时Slack通知\n- **诊断工具**\n  * 失败截图自动保存\n  * 测试日志完整保留\n  * 设备状态快照\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查E2E测试稳定性保障，验证有flaky test检测机制(失败率>5%自动标记)，有重试配置，有智能等待策略(waitFor)，有执行时间监控，目标flaky rate<2%'', ''context_files'': [''apps/mobile/e2e/config.json'', ''apps/mobile/e2e/support/stability-monitor.ts'', ''.github/workflows/e2e-stability-report.yml''], ''metrics'': [''Flaky Rate目标: <2%'', ''重试配置: 自动重试2次'', ''等待策略: waitFor元素≤10秒'', ''监控频率: 每周稳定性报告'']}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(496,'ISSUE-UI001~c1',NULL,replace('建立完整的设计令牌体系:\n- 色彩系统：主色、辅色、功能色（成功、警告、错误、信息）\n- 字体规范：字号层级（标题/正文/辅助文字）、字重、行高\n- 间距系统：基础单位、内边距、外边距层级\n- 圆角、阴影、边框等视觉属性\n- 支持亮色/暗色主题切换\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/theme/theme.ts'', ''apps/mobile/src/theme/designTokens.ts''], ''prompt'': ''检查设计令牌实现，验证有 theme.ts 或 designTokens.ts 文件，包含 colors、typography、spacing、borderRadius 等完整定义，支持主题切换''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(497,'ISSUE-UI001~c2',NULL,replace('实现多功能 Button 组件:\n- 变体：实心(primary)、轮廓(outline)、幽灵(ghost)、文字(text)\n- 尺寸：大、中、小\n- 状态：正常、禁用、加载中\n- 图标支持：前置图标、后置图标\n- 颜色主题适配\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/Button/Button.tsx'', ''apps/mobile/src/components/Button/Button.test.tsx''], ''prompt'': ''检查 Button 组件实现，验证有 Button.tsx 组件文件，支持 variant、size、loading、disabled、icon 等 props，有对应的单元测试''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(498,'ISSUE-UI001~c3',NULL,replace('实现 Input 输入组件:\n- 类型：文本、密码、数字、邮箱、手机号\n- 状态：正常、错误、禁用、只读\n- 前缀/后缀支持：图标、文字\n- 清除按钮功能\n- 错误提示和字符计数\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/Input/Input.tsx'', ''apps/mobile/src/components/Input/Input.test.tsx''], ''prompt'': ''检查 Input 组件实现，验证有 Input.tsx 组件文件，支持 type、error、disabled、prefix、suffix、clearable 等 props，有对应的单元测试''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(499,'ISSUE-UI001~c4',NULL,replace('实现 Card 和 Modal 组件:\n- Card：可点击、带阴影、圆角、支持头部/内容/底部结构\n- Modal：遮罩层、动画过渡、点击遮罩关闭、手势滑动关闭\n- 支持自定义内容和操作按钮\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/Card/Card.tsx'', ''apps/mobile/src/components/Modal/Modal.tsx''], ''prompt'': ''检查 Card 和 Modal 组件实现，验证有 Card.tsx 和 Modal.tsx 文件，Card 支持 pressable、header/content/footer 结构；Modal 支持 visible 控制、动画、遮罩点击关闭''}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(500,'ISSUE-UI001~c5',NULL,replace('建立图标系统:\n- 使用统一的图标库（如 react-native-vector-icons 或自定义 SVG）\n- 图标分类：导航、操作、状态、场景\n- 支持尺寸和颜色自定义\n- 图片资源优化和缓存策略\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/Icon/Icon.tsx'', ''apps/mobile/src/assets/icons/index.ts''], ''prompt'': ''检查图标系统实现，验证有 Icon 组件或图标导出文件，支持 name、size、color props，确认使用了统一的图标库''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(501,'ISSUE-UI001~c6',NULL,replace('建立组件文档体系:\n- 配置 Storybook 或等效工具展示组件\n- 每个组件包含用法示例、Props 说明\n- 视觉回归测试基础\n- 设计系统文档网站\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''.storybook/main.js'', ''apps/mobile/src/components/README.md''], ''prompt'': ''检查组件文档实现，验证有 .storybook 配置或组件文档目录，包含 Button、Input、Card、Modal 等组件的使用示例和 Props 表格''}}',1,'sufficient','not_needed','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(502,'ISSUE-UI002~c1',NULL,replace('实现底部 Tab 导航栏:\n- Tab 项：首页、消息、发现、我的\n- 激活/未激活状态图标切换\n- 未读消息红点/角标显示\n- Tab 切换动画效果\n- 适配 iOS 底部安全区域\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查底部 Tab 导航实现，验证有 BottomTabNavigator 或等效组件，包含 Home、Messages、Discover、Profile 四个 Tab，支持 badge 显示和切换动画'', ''context_files'': [''apps/mobile/src/navigation/BottomTabNavigator.tsx'', ''apps/mobile/src/navigation/AppNavigator.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(503,'ISSUE-UI002~c2',NULL,replace('配置完整的路由系统:\n- 使用 React Navigation 配置导航栈\n- 认证栈与主应用栈分离\n- 嵌套导航结构（Tab + Stack）\n- 路由参数类型定义\n- 深链接（Deep Link）配置\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查导航结构实现，验证使用 @react-navigation/native 配置，有 AuthStack 和 MainStack 分离，路由参数有 TypeScript 类型定义，支持深链接'', ''context_files'': [''apps/mobile/src/navigation/AppNavigator.tsx'', ''apps/mobile/src/navigation/types.ts'', ''apps/mobile/src/navigation/linking.ts'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(504,'ISSUE-UI002~c3',NULL,replace('实现通用页面布局组件:\n- SafeAreaView 安全区域适配\n- 顶部导航栏（标题、返回按钮、操作按钮）\n- 内容滚动容器（ScrollView/FlatList）\n- 加载状态占位（Skeleton）\n- 空状态和错误状态页面\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查页面布局组件实现，验证有 ScreenContainer、Header、LoadingSkeleton、EmptyState、ErrorState 等组件，支持安全区域和滚动'', ''context_files'': [''apps/mobile/src/components/ScreenContainer/ScreenContainer.tsx'', ''apps/mobile/src/components/Header/Header.tsx'', ''apps/mobile/src/components/EmptyState/EmptyState.tsx'']}}',1,'sufficient','not_needed','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(505,'ISSUE-UI002~c4',NULL,replace('实现侧边抽屉菜单:\n- 从左侧滑出的抽屉导航\n- 用户头像和昵称展示\n- 菜单项列表（设置、帮助、反馈等）\n- 手势滑动打开/关闭\n- 遮罩层点击关闭\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查侧边抽屉导航实现，验证有 DrawerNavigator 组件，包含用户头像、菜单列表，支持手势滑动和遮罩点击关闭'', ''context_files'': [''apps/mobile/src/navigation/DrawerNavigator.tsx'', ''apps/mobile/src/components/DrawerMenu/DrawerMenu.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(506,'ISSUE-UI002~c5',NULL,replace('实现导航状态管理:\n- 基于认证状态的条件导航\n- 路由守卫（需要登录的页面）\n- 导航状态持久化\n- 返回按钮行为控制\n- 页面跳转动画配置\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查导航状态管理实现，验证有基于 auth 状态的导航控制，路由守卫实现，导航状态持久化存储'', ''context_files'': [''apps/mobile/src/navigation/AuthGuard.tsx'', ''apps/mobile/src/hooks/useAuthNavigation.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(507,'ISSUE-UI002~c6',NULL,replace('实现响应式布局:\n- 不同屏幕尺寸适配（手机/平板）\n- 横竖屏切换处理\n- 键盘弹出时布局调整\n- 底部 Tab 栏与输入法协调\n- 刘海屏/灵动岛适配\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查响应式布局实现，验证使用了 react-native-safe-area-context，有横竖屏适配处理，键盘避免遮挡输入框的处理'', ''context_files'': [''apps/mobile/src/hooks/useScreenDimensions.ts'', ''apps/mobile/src/components/KeyboardAvoidingView/KeyboardAvoidingView.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(508,'ISSUE-UI003~c1',NULL,replace('实现 Agent 状态展示:\n- 当前激活的 Agent 列表\n- Agent 状态显示（在线/忙碌/离线）\n- 快速切换 Agent 选择器\n- Agent 场景类型图标标识\n- Agent 活动统计（今日匹配数、对话数）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/components/AgentStatusCard.tsx'', ''apps/mobile/src/screens/Home/HomeScreen.tsx''], ''prompt'': ''检查 Agent 状态概览实现，验证有 AgentStatusCard 组件，显示 Agent 列表、状态、场景图标和统计数据，支持快速切换''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(509,'ISSUE-UI003~c2',NULL,replace('实现匹配结果展示模块:\n- 最新匹配结果列表\n- 匹配用户/Agent 头像和名称\n- 匹配度评分显示\n- 匹配时间戳\n- 点击进入聊天或详情\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/components/RecentMatches.tsx'', ''apps/mobile/src/screens/Home/components/MatchCard.tsx''], ''prompt'': ''检查匹配结果展示实现，验证有 MatchResultList 或 RecentMatches 组件，显示匹配用户头像、名称、匹配度和时间，支持点击进入''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(510,'ISSUE-UI003~c3',NULL,replace('实现首页快捷操作区:\n- 创建新 Agent 快捷入口\n- 发布需求（VisionShare）\n- 开始匹配（AgentDate）\n- 查看附近任务（AgentJob/AgentAd）\n- 快捷按钮网格布局\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/components/QuickActions.tsx'', ''apps/mobile/src/screens/Home/components/ActionButton.tsx''], ''prompt'': ''检查快捷操作入口实现，验证有 QuickActions 组件，包含创建 Agent、发布需求、开始匹配等快捷按钮，使用网格布局''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(511,'ISSUE-UI003~c4',NULL,replace('实现通知提醒展示:\n- 未读消息预览\n- 系统通知横幅\n- Agent 活动提醒\n- 可滑动删除单条通知\n- 一键清除全部\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/components/NotificationPreview.tsx'', ''apps/mobile/src/components/NotificationBanner/NotificationBanner.tsx''], ''prompt'': ''检查通知区域实现，验证有 NotificationBanner 或 NotificationPreview 组件，显示未读消息和系统通知，支持滑动删除和清除全部''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(512,'ISSUE-UI003~c5',NULL,replace('实现首页数据管理:\n- 下拉刷新功能\n- 首次加载骨架屏\n- 数据缓存策略\n- 错误重试机制\n- 自动刷新间隔配置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/HomeScreen.tsx'', ''apps/mobile/src/hooks/useHomeData.ts''], ''prompt'': ''检查首页数据加载实现，验证有 RefreshControl 下拉刷新，LoadingSkeleton 骨架屏，错误重试按钮，数据缓存逻辑''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(513,'ISSUE-UI003~c6',NULL,replace('实现个性化内容展示:\n- 推荐用户/Agent 卡片轮播\n- 基于场景的推荐内容\n- 热门活动或话题\n- 个性化问候语\n- 场景切换提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Home/components/RecommendationCarousel.tsx'', ''apps/mobile/src/screens/Home/components/FeaturedSection.tsx''], ''prompt'': ''检查个性化推荐实现，验证有 RecommendationCarousel 或 FeaturedSection 组件，显示推荐卡片轮播，有基于当前 Agent 场景的个性化内容''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(514,'ISSUE-UI004~c1',NULL,replace('消息UI:\n- 消息气泡组件\n- 文本/图片/视频消息\n- 消息状态显示(发送中/已发送/已读)\n- 消息操作菜单\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查消息组件，验证有MessageBubble组件支持不同类型消息，显示发送状态，支持长按菜单'', ''context_files'': [''apps/mobile/src/components/chat/MessageBubble.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(515,'ISSUE-UI004~c2',NULL,replace('输入UI:\n- 文本输入框\n- 表情选择器\n- 图片/文件选择\n- 发送按钮状态\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查输入组件，验证有ChatInput组件支持文本输入、表情、附件选择，发送按钮根据输入内容启用/禁用'', ''context_files'': [''apps/mobile/src/components/chat/ChatInput.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(516,'ISSUE-UI004~c3',NULL,replace('状态显示:\n- 用户头像组件\n- 在线/离线状态点\n- Agent/人类标识\n- 最后活跃时间\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查用户状态，验证有UserStatusIndicator组件显示头像、在线状态、Agent标识，支持last seen时间'', ''context_files'': [''apps/mobile/src/components/chat/UserStatusIndicator.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(517,'ISSUE-UI004~c4',NULL,replace('列表性能:\n- FlatList优化\n- 下拉加载历史\n- 无限滚动\n- 内存管理\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查聊天列表，验证有MessageList组件使用FlatList优化，支持下拉刷新和上拉加载，实现getItemLayout优化'', ''context_files'': [''apps/mobile/src/components/chat/MessageList.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(518,'ISSUE-UI004a~c1',NULL,replace('实现消息气泡 MessageBubble 组件:\n- 发送/接收消息样式区分\n- 文本、图片、文件消息类型支持\n- 消息状态指示（发送中、已发送、已读）\n- 时间戳显示\n- 长按菜单（复制、删除、举报）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/MessageBubble/MessageBubble.tsx'', ''apps/mobile/src/components/MessageBubble/MessageBubble.test.tsx''], ''prompt'': ''检查消息气泡组件实现，验证有 MessageBubble 组件，支持 isMe、type、status、timestamp props，有长按菜单功能''}}',1,'sufficient','required','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(519,'ISSUE-UI004a~c2',NULL,replace('实现聊天输入框 ChatInput 组件:\n- 多行文本输入\n- 输入高度自适应\n- 发送按钮状态（有内容时可发送）\n- 语音输入切换\n- 提及(@)用户功能\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/ChatInput/ChatInput.tsx'', ''apps/mobile/src/components/ChatInput/ChatInput.test.tsx''], ''prompt'': ''检查消息输入框实现，验证有 ChatInput 组件，支持多行输入、高度自适应、发送按钮、语音切换，有 @mention 功能''}}',1,'sufficient','required','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(520,'ISSUE-UI004a~c3',NULL,replace('实现附件发送功能:\n- 图片选择（相册/相机）\n- 文件选择器\n- 附件预览\n- 发送进度指示\n- 取消发送功能\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/AttachmentPicker/AttachmentPicker.tsx'', ''apps/mobile/src/components/AttachmentPicker/ImagePicker.ts''], ''prompt'': ''检查附件功能实现，验证有 AttachmentPicker 组件，支持图片选择和文件上传，有进度指示和预览功能''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(521,'ISSUE-UI004a~c4',NULL,replace('实现快捷回复功能（依赖 COM005）:\n- Agent 建议的回复选项\n- 快捷回复横向滚动列表\n- 点击快速填入输入框或直接发送\n- 基于对话上下文的智能建议\n- 用户可自定义快捷回复\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/QuickReplies/QuickReplies.tsx'', ''apps/mobile/src/screens/Chat/components/SuggestedReplies.tsx''], ''prompt'': ''检查快捷回复实现，验证有 QuickReplies 组件，显示 Agent 建议的回复选项，支持点击快速发送，基于对话上下文更新建议''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(522,'ISSUE-UI004a~c5',NULL,replace('实现人机切换界面元素（依赖 COM003）:\n- 当前对话者身份标识（Agent/真人）\n- 切换按钮/指示器\n- 切换确认对话框\n- 切换过渡动画\n- 身份标识持久显示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/SpeakerIndicator/SpeakerIndicator.tsx'', ''apps/mobile/src/screens/Chat/components/IdentitySwitcher.tsx''], ''prompt'': ''检查人机切换指示器实现，验证有 IdentitySwitcher 或 SpeakerIndicator 组件，显示当前对话者身份，有切换按钮和确认对话框''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(523,'ISSUE-UI004a~c6',NULL,replace('实现表情选择器:\n- Emoji 表情面板\n- 表情分类和搜索\n- 最近使用表情\n- 自定义贴纸支持\n- 面板展开/收起动画\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/EmojiPicker/EmojiPicker.tsx'', ''apps/mobile/src/components/EmojiPicker/EmojiData.ts''], ''prompt'': ''检查表情选择器实现，验证有 EmojiPicker 组件，支持表情分类、最近使用、搜索功能，有展开收起动画''}}',1,'sufficient','required','not_needed','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(524,'ISSUE-UI004b~c1',NULL,replace('实现带状态的头像组件:\n- 用户头像显示（圆形/圆角矩形）\n- 在线/离线/忙碌状态点\n- 状态点颜色区分\n- 头像边框样式（Agent/真人区分）\n- 头像点击展开详情\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查头像状态指示器实现，验证有 UserAvatar 或 StatusAvatar 组件，支持显示在线状态点和身份边框区分'', ''context_files'': [''apps/mobile/src/components/UserAvatar/UserAvatar.tsx'', ''apps/mobile/src/components/UserAvatar/UserAvatar.test.tsx'']}}',1,'sufficient','required','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(525,'ISSUE-UI004b~c2',NULL,replace('实现输入中状态显示:\n- "正在输入..." 动画提示\n- 对方 Agent 正在思考/生成回复\n- 输入状态实时同步\n- 动画效果（三个点跳动）\n- 状态超时自动隐藏\n','\n',char(10)),'functional','{''ai'': {''prompt'': "检查输入状态指示器实现，验证有 TypingIndicator 组件，显示 ''正在输入'' 动画，支持区分人类输入和 Agent 思考状态", ''context_files'': [''apps/mobile/src/components/TypingIndicator/TypingIndicator.tsx'', ''apps/mobile/src/components/TypingIndicator/TypingIndicator.test.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(526,'ISSUE-UI004b~c3',NULL,replace('实现身份标识组件:\n- Agent 标识徽章（机器人图标）\n- 真人用户标识\n- 认证标识（已验证用户）\n- 场景类型标识（VisionShare/Date/Job/Ad）\n- 徽章位置配置（头像右下角/名称旁边）\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查身份标识实现，验证有 IdentityBadge 组件，支持 Agent、Verified、SceneType 等徽章类型，可配置位置'', ''context_files'': [''apps/mobile/src/components/IdentityBadge/IdentityBadge.tsx'', ''apps/mobile/src/components/IdentityBadge/IdentityBadge.test.tsx'']}}',1,'sufficient','required','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(527,'ISSUE-UI004b~c4',NULL,replace('实现在线时间显示:\n- 最后在线时间格式化（刚刚、几分钟前、几小时前）\n- 相对时间自动更新\n- 在线状态实时更新\n- 时间格式本地化\n- 悬停/长按显示精确时间\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查在线时间显示实现，验证有 LastSeen 或 OnlineTime 组件，支持相对时间格式化和自动更新'', ''context_files'': [''apps/mobile/src/components/LastSeen/LastSeen.tsx'', ''apps/mobile/src/utils/timeFormat.ts'']}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(528,'ISSUE-UI004b~c5',NULL,replace('实现会话列表状态显示:\n- 会话列表项显示最后消息预览\n- 未读消息数角标\n- 会话优先级标识\n- 置顶会话标记\n- 静音会话标识\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查聊天列表状态实现，验证有 ConversationItem 组件，显示最后消息预览、未读数角标、置顶和静音标识'', ''context_files'': [''apps/mobile/src/components/ConversationItem/ConversationItem.tsx'', ''apps/mobile/src/screens/Messages/components/ChatListItem.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(529,'ISSUE-UI004b~c6',NULL,replace('实现用户信用展示组件:\n- 信用分星级/数字显示\n- 评分等级颜色区分\n- 信用徽章（高信用用户）\n- 点击查看信用详情\n- 实时更新信用分数\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查信用分展示实现，验证有 CreditScore 或 TrustBadge 组件，显示用户信用分和等级，支持点击查看详情'', ''context_files'': [''apps/mobile/src/components/CreditScore/CreditScore.tsx'', ''apps/mobile/src/components/TrustBadge/TrustBadge.tsx'']}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(530,'ISSUE-UI004c~c1',NULL,replace('实现历史消息加载:\n- 下拉/上拉加载更多历史消息（根据滚动方向）\n- 加载状态指示器\n- 分页请求管理\n- 加载失败重试\n- 到达最早消息提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Chat/ChatScreen.tsx'', ''apps/mobile/src/hooks/useChatMessages.ts'', ''apps/mobile/src/components/InvertedList/InvertedList.tsx''], ''prompt'': ''检查反向滚动加载实现，验证使用 FlatList 或 ScrollView 实现下拉加载历史消息，有 loading indicator 和重试机制''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(531,'ISSUE-UI004c~c2',NULL,replace('实现滚动位置保持:\n- 加载历史消息后保持当前视图位置\n- 跳转到指定消息\n- 搜索高亮消息滚动定位\n- 首次进入滚动到底部\n- 滚动位置记忆（返回后恢复）\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/hooks/useScrollPosition.ts'', ''apps/mobile/src/screens/Chat/utils/scrollUtils.ts''], ''prompt'': ''检查滚动位置管理实现，验证加载历史消息后位置保持逻辑，支持跳转到指定消息ID，首次进入自动滚动到底部''}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(532,'ISSUE-UI004c~c3',NULL,replace('实现新消息通知:\n- 底部"新消息"悬浮按钮\n- 未读消息数显示\n- 点击滚动到最新消息\n- 自动滚动控制（用户滚动浏览时暂停自动滚动）\n- 消息发送成功提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/ScrollToBottom/ScrollToBottom.tsx'', ''apps/mobile/src/screens/Chat/components/NewMessageBadge.tsx''], ''prompt'': ''检查新消息提示实现，验证有 NewMessageBadge 或 ScrollToBottom 组件，显示未读数，点击滚动到底部，有智能自动滚动控制''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(533,'ISSUE-UI004c~c4',NULL,replace('实现长列表性能优化:\n- 使用 FlatList 虚拟化渲染\n- 消息项高度预估\n- 图片懒加载\n- 内存管理（离开页面释放资源）\n- 大数据量流畅滚动\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Chat/components/MessageList.tsx'', ''apps/mobile/src/components/LazyImage/LazyImage.tsx''], ''prompt'': ''检查虚拟化实现，验证使用 FlatList 的 getItemLayout 或 estimatedItemSize 优化，有图片懒加载处理，大数据量下滚动流畅''}}',1,'sufficient','not_needed','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(534,'ISSUE-UI004c~c5',NULL,replace('实现消息时间显示:\n- 日期分隔线（今天、昨天、星期X、具体日期）\n- 消息时间戳（气泡内/外显示）\n- 相对时间（几分钟前）\n- 时间戳显示策略（连续消息只显示第一条时间）\n- 点击展开/收起详细时间\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/DateSeparator/DateSeparator.tsx'', ''apps/mobile/src/components/DateSeparator/DateSeparator.test.tsx''], ''prompt'': ''检查日期分隔实现，验证有 DateSeparator 组件，正确显示日期分隔线，消息时间戳显示策略合理，支持连续消息时间折叠''}}',1,'sufficient','required','not_needed','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(535,'ISSUE-UI004c~c6',NULL,replace('实现消息搜索功能:\n- 聊天内搜索输入框\n- 搜索结果高亮显示\n- 搜索结果导航（上一条/下一条）\n- 搜索结果数量显示\n- 点击结果跳转到对应消息\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/components/ChatSearch/ChatSearch.tsx'', ''apps/mobile/src/screens/Chat/components/SearchInChat.tsx''], ''prompt'': ''检查消息搜索实现，验证有 ChatSearch 组件，支持搜索输入、结果高亮、导航跳转，有搜索结果计数''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(536,'ISSUE-UI005~c1',NULL,replace('实现分步创建向导:\n- 步骤导航条（选择场景、基础配置、详细信息、确认）\n- 场景类型选择（VisionShare/AgentDate/AgentJob/AgentAd）\n- 每步数据验证\n- 上一步/下一步导航\n- 可保存草稿\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/CreateAgentWizard.tsx'', ''apps/mobile/src/screens/Agent/components/StepIndicator.tsx''], ''prompt'': ''检查 Agent 创建向导实现，验证有 CreateAgentWizard 组件，包含步骤条、场景选择、表单验证、草稿保存功能''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(537,'ISSUE-UI005~c2',NULL,replace('实现基础信息配置:\n- Agent 名称输入\n- 头像上传/选择\n- 描述/简介文本域\n- 可见性设置（公开/私有）\n- 表单验证和错误提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/components/AgentBasicInfoForm.tsx'', ''apps/mobile/src/components/AvatarPicker/AvatarPicker.tsx''], ''prompt'': ''检查基础信息表单实现，验证有 AgentBasicInfoForm 组件，包含名称、头像上传、描述、可见性设置，有完整表单验证''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(538,'ISSUE-UI005~c3',NULL,replace('实现场景特定配置（依赖 C006）:\n- VisionShare: 需求范围、价格设置\n- AgentDate: 交友偏好、匹配条件\n- AgentJob: 求职意向/招聘要求\n- AgentAd: 消费偏好/优惠类型\n- 动态表单根据场景变化\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/components/SceneConfigForm.tsx'', ''apps/mobile/src/screens/Agent/components/VisionShareConfig.tsx'', ''apps/mobile/src/screens/Agent/components/AgentDateConfig.tsx''], ''prompt'': ''检查场景配置实现，验证有 SceneConfigForm 组件，根据选择的场景类型动态显示不同配置项，支持 VisionShare/AgentDate/AgentJob/AgentAd 的配置''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(539,'ISSUE-UI005~c4',NULL,replace('实现 AI 行为设置:\n- 选择 LLM 模型（GPT/Claude/本地模型）\n- 温度/创造性参数调节滑块\n- 回复风格选择（正式/友好/幽默）\n- 自动回复开关\n- 人机切换触发条件\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/components/AIConfigSection.tsx'', ''apps/mobile/src/components/ModelSelector/ModelSelector.tsx''], ''prompt'': ''检查 AI 配置实现，验证有 AIConfigSection 组件，包含模型选择器、温度滑块、风格选择、自动回复开关''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(540,'ISSUE-UI005~c5',NULL,replace('实现 Agent 管理界面:\n- Agent 卡片列表（网格/列表视图）\n- Agent 状态切换（激活/暂停）\n- 编辑/删除操作\n- Agent 排序和筛选\n- 空状态提示\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/AgentListScreen.tsx'', ''apps/mobile/src/screens/Agent/components/AgentCard.tsx''], ''prompt'': ''检查 Agent 管理界面实现，验证有 AgentListScreen 组件，显示 Agent 卡片列表，支持状态切换、编辑、删除操作，有排序筛选功能''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(541,'ISSUE-UI005~c6',NULL,replace('实现配置预览功能:\n- Agent 资料预览\n- 对话风格测试窗口\n- 模拟对话测试\n- 配置变更历史\n- 一键恢复默认设置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Agent/components/AgentPreview.tsx'', ''apps/mobile/src/screens/Agent/components/TestChat.tsx''], ''prompt'': ''检查配置预览实现，验证有 AgentPreview 或 TestChat 组件，支持预览 Agent 资料、模拟对话测试、查看配置历史''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(542,'ISSUE-UI006~c1',NULL,replace('实现聊天会话列表:\n- 会话列表展示（头像、名称、最后消息、时间）\n- 未读消息数角标\n- 会话分组（置顶、普通）\n- 左滑操作（删除、置顶、标记已读）\n- 下拉刷新\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Messages/ConversationListScreen.tsx'', ''apps/mobile/src/screens/Messages/components/ConversationItem.tsx''], ''prompt'': ''检查会话列表实现，验证有 ConversationListScreen 组件，显示会话列表项、未读角标，支持左滑操作和下拉刷新''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(543,'ISSUE-UI006~c2',NULL,replace('实现系统通知界面:\n- 通知分类（系统、活动、匹配、安全）\n- 通知列表（图标、标题、内容、时间）\n- 通知详情查看\n- 一键标记全部已读\n- 通知设置入口\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Messages/NotificationCenter.tsx'', ''apps/mobile/src/screens/Messages/components/NotificationItem.tsx''], ''prompt'': ''检查系统通知实现，验证有 NotificationCenter 组件，支持通知分类、列表展示、详情查看、标记已读功能''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(544,'ISSUE-UI006~c3',NULL,replace('实现消息搜索:\n- 全局搜索入口\n- 搜索建议和历史\n- 搜索结果分类（联系人、消息内容）\n- 结果高亮显示\n- 点击跳转到对应会话\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Messages/MessageSearchScreen.tsx'', ''apps/mobile/src/components/SearchBar/SearchBar.tsx''], ''prompt'': ''检查消息搜索实现，验证有 MessageSearchScreen 或 SearchModal 组件，支持搜索建议、历史、结果分类和高亮''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(545,'ISSUE-UI006~c4',NULL,replace('实现会话管理:\n- 批量选择会话\n- 批量删除会话\n- 会话归档\n- 会话静音/取消静音\n- 清空聊天记录\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Messages/hooks/useConversationManage.ts'', ''apps/mobile/src/screens/Messages/components/BatchActionBar.tsx''], ''prompt'': ''检查会话管理实现，验证有批量选择模式、删除、归档、静音功能，支持清空聊天记录''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(546,'ISSUE-UI006~c5',NULL,replace('实现消息通知设置:\n- 消息通知开关\n- 声音/振动设置\n- 免打扰模式\n- 通知预览开关\n- 按会话类型设置\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Settings/MessageSettingsScreen.tsx'', ''apps/mobile/src/screens/Settings/components/NotificationToggle.tsx''], ''prompt'': ''检查消息设置实现，验证有 MessageSettingsScreen 组件，包含通知开关、声音振动设置、免打扰模式配置''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
INSERT INTO acceptance_criteria VALUES(547,'ISSUE-UI006~c6',NULL,replace('实现新建会话功能:\n- 新建聊天按钮\n- 联系人选择器\n- 搜索用户\n- 创建群聊选项\n- 最近联系人快捷选择\n','\n',char(10)),'functional','{''ai'': {''context_files'': [''apps/mobile/src/screens/Messages/NewChatScreen.tsx'', ''apps/mobile/src/components/ContactPicker/ContactPicker.tsx''], ''prompt'': ''检查新建会话实现，验证有 NewChatScreen 或 ContactPicker 组件，支持搜索用户、选择联系人、创建群聊''}}',1,'sufficient','required','required','not_needed','not_needed','pending','pending');
