INSERT INTO acceptance_criteria VALUES(578,'ISSUE-VS007~c1',NULL,replace('权限系统:\n- 相册读取权限申请\n- 权限状态管理\n- 部分访问支持(iOS14+)\n- 权限被拒绝处理\n- 权限引导说明\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查本地相册权限，验证有权限申请、状态管理、部分访问、拒绝处理和引导功能'', ''context_files'': [''apps/mobile/src/permissions/photoLibrary.ts'', ''apps/mobile/src/screens/Permissions/PhotoPermission.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(579,'ISSUE-VS007~c2',NULL,replace('分析引擎:\n- 本地照片批量处理\n- 端侧AI模型推理\n- 图像特征提取\n- 标签生成和索引\n- 处理进度显示\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查本地照片AI分析，验证有批量处理、端侧推理、特征提取、标签生成和进度显示'', ''context_files'': [''apps/mobile/src/services/ai/localImageAnalysis.ts'', ''apps/mobile/src/utils/onDeviceML.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(580,'ISSUE-VS007~c3',NULL,replace('索引系统:\n- 本地SQLite索引存储\n- 增量更新机制\n- 索引压缩优化\n- 索引备份和恢复\n- 索引版本管理\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查本地搜索索引，验证有SQLite存储、增量更新、压缩优化、备份恢复和版本管理'', ''context_files'': [''apps/mobile/src/storage/localSearchIndex.ts'', ''apps/mobile/src/services/indexing/localIndexer.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(581,'ISSUE-VS007~c4',NULL,replace('搜索功能:\n- 云端/本地数据源切换\n- 统一搜索结果展示\n- 数据来源标识\n- 混合结果排序\n- 搜索范围选择\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查统一搜索界面，验证有数据源切换、统一展示、来源标识和范围选择功能'', ''context_files'': [''apps/mobile/src/screens/VisionShare/UnifiedSearch.tsx'', ''apps/mobile/src/components/Search/SearchSourceTabs.tsx'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(582,'ISSUE-VS007~c5',NULL,replace('隐私功能:\n- 端侧处理不上传\n- 敏感照片排除\n- 加密索引存储\n- 隐私模式切换\n- 数据处理说明\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查本地照片隐私保护，验证有端侧处理、敏感排除、加密存储和隐私模式功能'', ''context_files'': [''apps/mobile/src/services/privacy/localPrivacy.ts'', ''apps/mobile/src/utils/encryptedStorage.ts'']}}',1,'sufficient','required','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(583,'ISSUE-VS007~c6',NULL,replace('优化功能:\n- 后台索引更新\n- 缩略图缓存管理\n- 搜索响应优化\n- 内存使用优化\n- 电池消耗优化\n','\n',char(10)),'functional','{''ai'': {''prompt'': ''检查性能优化缓存，验证有后台更新、缩略图缓存、响应优化和资源优化功能'', ''context_files'': [''apps/mobile/src/services/performance/searchOptimization.ts'', ''apps/mobile/src/utils/imageCache.ts'']}}',1,'sufficient','recommended','required','not_needed','required','pending','pending');
INSERT INTO acceptance_criteria VALUES(584,'US-AGENT-001~func',1,'用户首次创建 Agent 并配置基本信息和偏好','functional','## 前置准备\n- `pnpm dev` 启动后端和移动端\n- 在手机上用 Expo Go 扫码\n- 准备一个未注册的新手机号/邮箱\n\n## 验收步骤\n1. 打开 App，点击注册\n2. 完成注册流程（手机号+验证码）\n3. 进入引导页，填写昵称、头像\n4. 在 Agent 创建页选择感兴趣的场景（VisionShare、AgentDate、AgentJob、AgentAd）\n5. 选择沟通风格（直接/委婉/详细/简洁）\n6. 点击确认创建 Agent\n7. 验证：进入个人中心能看到 Agent 已存在，展示昵称/头像/场景\n\n## 人类质询点\n- 如果用户不选择任何场景，Agent 能创建吗？应该报错\n- 如果用户填了超长的昵称，会被截断或拒绝吗？\n- 注册后立即创建 Agent 的流程是否流畅，有没有多余步骤？\n- 用已存在的手机号再次注册会怎样？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(585,'US-AGENT-001~edge',1,'异常场景：重复创建、无效输入、网络中断','edge_case','1. 用同一手机号注册两次，第二次应提示"账号已存在"\n2. 在 Agent 创建时断网（关闭 WiFi/流量），应显示网络错误提示，恢复后能继续\n3. 上传超大图片作为头像（>5MB），应拒绝或压缩\n4. 不选择任何场景就提交，应有明确错误提示',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(586,'US-AGENT-002~func',2,'用户与 Agent 对话后成功创建需求和供给','functional','## 前置准备\n- 完成 US-AGENT-001（Agent 已创建）\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 打开 App，进入 Agent 对话界面\n2. 输入需求："我想找北京海淀区的程序员工作，期望薪资20k-30k"\n3. 观察 Agent 是否主动追问关键信息（如工作年限、技能栈等）\n4. 完成多轮对话\n5. 检查需求是否被结构化展示（关键词段被提取分类）\n6. 点击确认，验证需求已保存到对应场景\n7. 切换场景（如从 AgentJob 切换到 AgentDate），确认各场景需求独立\n\n## 人类质询点\n- Agent 追问的是"关键"信息还是瞎问？看追问是否有针对性\n- 如果用户输入模糊信息（"我想做有意思的工作"），Agent 能提炼吗？\n- 多轮对话中，Agent 是否记得之前的上下文？\n- 用户拒绝回答某项信息时，Agent 会跳过吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(587,'US-AGENT-002~edge',2,'异常场景：空输入、无意义输入、超长对话','edge_case','1. 发送空消息或纯表情，Agent 如何处理？\n2. 发送无关内容（"今天天气不错"），Agent 能否引导回正题？\n3. 连续对话 20 轮，需求提炼是否仍然准确？\n4. 对话中途退出再进入，对话历史是否保留？',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(588,'US-AGENT-011~func',3,'用户为每个场景分别配置公开和详细两级需求信息','functional','## 前置准备\n- 完成 US-AGENT-002（需求已创建）\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 进入需求配置页面\n2. 为 AgentJob 场景设置：\n   - 公开信息（如：求职意向-程序员）\n   - 详细信息（如：期望薪资20k-30k、技能栈）\n3. 设置该场景的披露策略（每次确认/自动披露）\n4. 切换到 AgentDate 场景，重复步骤 2-3\n5. 验证：不同场景的公开/详细信息独立存储\n6. 模拟另一个 Agent 查看，确认只能看到公开信息\n\n## 人类质询点\n- 公开信息和详细信息的边界是否清晰？有没有泄露风险？\n- 切换披露策略后，对已进行的对话是否立即生效？\n- 如果用户只设了公开信息没设详细信息，系统怎么处理？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(589,'US-AGENT-011~edge',3,'异常：披露策略切换后的行为一致性','edge_case','1. 设为"自动披露"后模拟其他 Agent 查看，应自动展示详细信息\n2. 设为"每次确认"后，对方尝试查看详细信息，应触发确认请求\n3. 修改已保存的需求配置，确认是否覆盖旧数据',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(590,'US-AGENT-012~func',4,'用户为每个场景分别配置公开和详细两级供给信息','functional','## 前置准备\n- 完成 US-AGENT-002\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 进入供给配置页面\n2. 为 AgentJob 设置供给：\n   - 公开：能提供的服务类型\n   - 详细：具体能力、经验、价格\n3. 设置展示策略\n4. 模拟对方 Agent 浏览，验证公开信息正确展示\n5. 验证详细信息未被泄露\n\n## 人类质询点\n- 供给和需求的配置流程是否一致且容易理解？\n- 对方只能看到公开信息吗？尝试用 API 直接请求详细信息接口确认被拒绝',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(591,'US-AGENT-012~edge',4,'异常：供给信息被未授权访问','edge_case','1. 用另一个账号（非本人）尝试访问详细信息接口，应返回 403\n2. 设置极短的展示策略有效期（如果支持），到期后确认信息不可见\n3. 清除缓存后验证供给配置是否持久化',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(592,'US-AGENT-007~func',5,'用户在四人群聊中成功切换"亲自聊"和"让 Agent 代聊"','functional','## 前置准备\n- 完成 US-AGENT-001、US-AGENT-008\n- 需要两个测试账号（用户 A 和用户 B），各有一个 Agent\n- 双方 Agent 已通过引荐进入四人群聊\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 用账号 A 进入四人群聊界面\n2. 观察当前聊天状态，确认 Agent 正在代聊\n3. 点击"亲自聊"按钮\n4. 发送消息，验证消息以用户身份展示（非 Agent 标识）\n5. 点击"让 Agent 聊"按钮\n6. 等待 Agent 自动回复，验证消息标识切换为 Agent\n7. 切换状态实时显示在聊天室（状态指示器更新）\n\n## 人类质询点\n- 切换后对方能立即感知吗？有延迟吗？\n- 切换后 Agent 之前说的草稿/建议是否保留？\n- 频繁切换（10 秒切换 5 次）会不会出问题？\n- 如果切换时对方也在发消息，会乱序吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(593,'US-AGENT-007~edge',5,'异常：切换中断、并发冲突','edge_case','1. 点击切换按钮时断网，恢复后状态是否正确同步？\n2. 用户和 Agent 几乎同时发消息，消息顺序是否正确？\n3. 在四人群聊中退出再重入，切换状态是否保留？',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(594,'US-AGENT-008~func',6,'每条消息清晰显示发送者身份（用户/Agent）','functional','## 前置准备\n- 完成 US-AGENT-007 的前置条件（四人群聊就绪）\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 进入四人群聊\n2. 用户 A 亲自发消息 → 显示用户 A 的头像和昵称\n3. 用户 A 的 Agent 发消息 → 显示 "A 的 Agent" 标识\n4. 用户 B 切换身份后发消息，标识同步更新\n5. 验证每条消息的头像和名称都与发送者匹配\n6. 对方切换身份时，自己的聊天界面标识实时更新\n\n## 人类质询点\n- Agent 消息和人类消息的视觉区分是否足够明显？\n- 如果 Agent 和人类用了相似昵称，能区分吗？\n- 历史消息滚动时，身份标识是否正确？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(595,'US-AGENT-008~edge',6,'异常：身份标识错乱','edge_case','1. 快速切换身份发消息，确认不会出现身份标识错误的消息\n2. 网络不稳定时重连，历史消息的身份标识是否正确\n3. 对方头像/昵称修改后，历史消息是否同步更新或保持不变（应保持不变）',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(596,'US-AGENT-014~func',7,'Agent 根据对话和信任水平决定是否披露详细信息','functional','## 前置准备\n- 完成 US-AGENT-007、US-AGENT-008、US-AGENT-011\n- 设置 AgentJob 场景，已配置公开和详细信息\n- 两个账号建立四人群聊\n\n## 验收步骤\n1. 将披露策略设为"每次确认模式"\n2. 对方 Agent 尝试查看详细信息\n3. 用户收到披露请求通知，显示对方想了解的信息内容\n4. 点击"同意"，确认信息已发送\n5. 再次请求时点击"否决"，确认信息未被发送\n6. 切换为"自动模式"，对方请求时应自动披露\n7. 在自动模式下，用户实时否决即将发生的披露，确认否决生效\n\n## 人类质询点\n- "每次确认"模式下，如果用户不回应，对方会一直等吗？有超时吗？\n- 自动模式下的底线信息（如薪资底线）是否真的不会透露？\n- 否决后对方收到什么提示？会不会暴露"有详细信息但我被否决了"？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(597,'US-AGENT-014~edge',7,'异常：披露策略被绕过','edge_case','1. 尝试通过 API 直接请求详细信息（不经过披露流程），应返回 403\n2. 在自动披露过程中断网，恢复后披露状态是否一致\n3. 用户否决后，对方 Agent 能否通过其他方式（如反复请求）绕开否决',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(598,'US-AGENT-009~func',8,'Agent 实时向用户发送私聊建议，仅自己可见','functional','## 前置准备\n- 完成 US-AGENT-007、US-AGENT-008\n- 四人群聊进行中\n\n## 验收步骤\n1. 在群聊中，让自己的 Agent 与对方 Agent 对话\n2. 观察侧边栏/独立区域是否出现私聊建议\n3. 验证建议内容包含：话题推荐、风险提示或对方意图分析\n4. 建议只有自己能看到（用另一台设备/另一个号查看群聊确认）\n5. 点击"一键采纳建议"（如推荐话题），验证消息以用户身份发送到群聊\n\n## 人类质询点\n- 建议是否真的"有用"，还是空话？\n- 建议的频率合理吗？不会刷屏干扰正常聊天吧？\n- 私聊建议会不会不小心泄露到群聊？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(599,'US-AGENT-009~edge',8,'异常：建议泄露、建议为空','edge_case','1. 在 Agent 生成建议时快速切换 Tab，建议是否仍然只有自己可见\n2. AI 服务不可用时（模拟断网或超时），建议模块是否优雅降级（不显示或显示降级提示）\n3. 群聊结束后，历史建议是否可查看',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(600,'US-AGENT-006~func',9,'Agent 请求引荐真人时，用户能接受或拒绝','functional','## 前置准备\n- 完成 US-AGENT-007、US-AGENT-008\n- 两个账号各自有 Agent，匹配度达到引荐阈值\n\n## 验收步骤\n1. 等待双方 Agent 对话达到引荐条件\n2. 用户 A 收到引荐通知\n3. 打开通知，查看：匹配理由、对方关键信息、信用分\n4. 点击"接受"\n5. 用户 B 也收到引荐请求并接受\n6. 验证：双方成功进入四人群聊\n7. 另测一次：用户 A 在收到引荐请求时点击"拒绝"\n8. 验证：引荐流程终止，对方收到礼貌通知\n\n## 人类质询点\n- 引荐通知是否及时？有没有明显延迟？\n- 拒绝后对方收到的提示是否礼貌且不暴露太多信息？\n- 一方接受一方拒绝的情况下，状态是否正确？\n- 引荐通知被用户忽略不处理，会超时吗？超时后怎么处理？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(601,'US-AGENT-006~edge',9,'异常：引荐请求丢失、双方同时拒绝','edge_case','1. 收到引荐通知时杀进程再打开，通知是否还在\n2. 双方同时点击拒绝，系统状态是否一致\n3. 一方接受但另一方长时间不回应（超时），引荐是否自动取消',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(602,'US-AGENT-005~func',10,'用户能按场景筛选并查看 Agent 对话历史','functional','## 前置准备\n- 完成 US-AGENT-007、US-AGENT-008\n- Agent 之间有过多轮对话\n\n## 验收步骤\n1. 进入对话记录页面\n2. 按场景（VisionShare / AgentDate / AgentJob / AgentAd）筛选\n3. 验证：只显示对应场景的对话记录\n4. 选择一条对话，查看双方 Agent 名称和匹配度评分\n5. 向上/向下滚动，验证聊天记录完整加载\n6. 验证分页加载正常（下拉加载更多）\n\n## 人类质询点\n- 历史对话加载速度快吗？大量对话时会不会卡？\n- 匹配度评分在历史记录中是否准确？\n- 如果 Agent 对话被删除了，记录还能看到吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(603,'US-AGENT-005~edge',10,'异常：历史记录缺失、加载异常','edge_case','1. 断网时尝试加载历史记录，应显示网络错误\n2. 查看一个月前的历史记录（如有），是否正确加载\n3. 用另一个账号尝试查看，确认只能看到自己的对话记录',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(604,'VS-001~func',11,'用户发布视觉需求，系统解析并推送给附近符合条件的用户','functional','## 前置准备\n- 完成 US-AGENT-011\n- 两个测试账号，在同一城市\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 打开 App，进入 VisionShare 场景\n2. 输入自然语言需求："我想看看现在三里屯人多不多"\n3. 系统解析出地点（三里屯）和意图（看人多不多）\n4. 确认发布的过滤条件（如信用分、距离）\n5. 点击发布\n6. 用另一账号确认收到推送通知\n7. 验证：推送通知包含需求方设置的过滤条件\n\n## 人类质询点\n- 地点解析准确吗？"三里屯附近"和"三里屯"有什么区别？\n- 如果地点无法识别（如"那个好玩的地方"），系统会怎样处理？\n- 附近没有人符合条件时会怎样？用户会得到通知吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(605,'VS-001~edge',11,'异常：无法解析地点、附近无匹配用户','edge_case','1. 输入无法解析的地点（如虚构地名），系统应提示无法识别\n2. 在偏远地区发布需求，附近无用户，应提示"暂无附近响应者"\n3. 发布后立即撤回，另一账号是否还能收到通知',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(606,'VS-002~func',12,'用户根据地域和信用过滤条件查看并接附近任务','functional','## 前置准备\n- 完成 VS-001（已有需求发布）\n- 两个测试账号在同一区域\n\n## 验收步骤\n1. 打开接单界面\n2. 验证：只显示符合地域过滤条件的任务（距离设置范围内）\n3. 验证：低于信用阈值的任务不显示\n4. 点击一个符合条件的任务\n5. 进入拍照界面\n6. 验证：任务状态变为"已接单"\n\n## 人类质询点\n- 距离计算准确吗？故意站在边界测试\n- 信用分过滤是否正确？用低分账号验证不出现\n- 接单后能不能取消？取消后任务状态如何？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(607,'VS-002~edge',12,'异常：位置异常、信用过滤绕过','edge_case','1. 关闭定位权限，接单界面如何表现\n2. 伪造 GPS 坐标到其他城市，是否仍显示本地任务\n3. 接单后断网再恢复，任务状态是否正确',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(608,'VS-003~func',13,'系统扫描本地相册并推荐匹配照片','functional','## 前置准备\n- 完成 VS-002（已接单任务）\n- 手机相册中包含与需求场景相关的照片\n\n## 验收步骤\n1. 进入本地相册检索页面\n2. AI 分析照片内容，筛选包含需求场景特征的照片\n3. 查看推荐的照片列表\n4. 确认照片确实与需求相关\n5. 选择照片并确认上传\n\n## 人类质询点\n- AI 推荐的照片准确率如何？有多少是误判？\n- 相册中有大量照片时，推荐速度如何？\n- 隐私敏感的照片（含人脸）被推荐了，用户会担心吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(609,'VS-003~edge',13,'异常：无匹配照片、相册为空','edge_case','1. 相册中无相关照片时，系统如何提示\n2. 相册权限被拒绝后，如何引导用户授权\n3. 只有一张模糊照片被推荐，质量是否校验',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(610,'VS-004~func',14,'照片上传前自动进行隐私脱敏','functional','## 前置准备\n- 完成 VS-003（已选择照片）\n- 准备包含人脸的照片\n\n## 验收步骤\n1. 选择一张含人脸的照片\n2. AI 自动检测并模糊人脸\n3. 脱敏后预览：确认人脸已模糊\n4. 检查 EXIF 信息：确认 GPS 等敏感信息已移除\n5. 确认后上传\n6. 验证：上传后的照片不包含原始 EXIF\n\n## 人类质询点\n- 模糊效果够不够？还能认出是谁吗？\n- EXIF 真的被清除了吗？下载上传后的照片检查\n- 脱敏失败怎么办？原始照片会直接上传吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(611,'VS-004~edge',14,'异常：脱敏失败、AI 服务不可用','edge_case','1. AI 人脸检测失败（侧脸、遮挡），照片是否被阻止上传\n2. AI 服务超时不可用，是否阻止上传或降级处理\n3. 同一张照片含多个人脸，是否全部被模糊',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(612,'VS-005~func',15,'用户支付积分查看照片，界面显示拍摄者信用','functional','## 前置准备\n- 完成 VS-001、VS-004（已有脱敏照片上传）\n- 确保用户有足够积分\n\n## 验收步骤\n1. 打开照片列表页\n2. 验证：每张照片显示缩略图、价格、拍摄者信用分\n3. 点击一张照片\n4. 确认支付积分\n5. 验证：支付后显示完整照片\n6. 验证：积分余额正确扣减\n\n## 人类质询点\n- 信用分显示是否醒目？用户能快速判断对方可信度吗？\n- 积分不足时怎么处理？\n- 支付后照片能反复查看吗？',1,'sufficient','not_needed','recommended','recommended','recommended','pending','pending');
INSERT INTO acceptance_criteria VALUES(613,'VS-005~edge',15,'异常：积分不足、支付中断','edge_case','1. 积分不足时尝试查看，应提示积分不足并引导充值\n2. 支付过程中断网，积分是否被误扣？照片能否正常查看？\n3. 信用分异常低（如低于阈值）的用户上传的照片，是否仍允许查看',2,'recommended','not_needed','not_needed','recommended','recommended','pending','pending');
INSERT INTO acceptance_criteria VALUES(614,'VS-006~func',16,'用户按地点和时间搜索历史照片','functional','## 前置准备\n- 完成 VS-005（已有照片数据）\n\n## 验收步骤\n1. 打开历史照片查询页面\n2. 按地点搜索（如"三里屯"）\n3. 验证：返回该地点的照片\n4. 按时间范围搜索（如"上周"）\n5. 验证：返回对应时间的照片\n6. 组合搜索（地点+时间），验证结果准确\n\n## 人类质询点\n- 搜索的模糊匹配程度如何？输入"三里"能找到"三里屯"吗？\n- 搜索速度快不快？大量数据时会不会慢？\n- 搜索结果能按相关性排序吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(615,'VS-006~edge',16,'异常：搜索无结果、搜索条件异常','edge_case','1. 搜索不存在的地点，应友好提示无结果\n2. 时间范围输入异常（如结束时间早于开始时间），如何处理\n3. 搜索词包含特殊字符（如 emoji），是否正常处理',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(616,'DATE-001~func',17,'用户配置交友偏好和个人信息','functional','## 前置准备\n- 完成 US-AGENT-011\n- `pnpm dev` 启动\n\n## 验收步骤\n1. 进入 AgentDate 场景配置页面\n2. 填写个人信息：年龄、性别、所在地、兴趣\n3. 设置期望条件：年龄范围、性别偏好、地区限制\n4. 设置隐私级别（公开/有限公开/私密）\n5. 保存配置\n6. 验证：配置已保存，重新打开仍能正确显示\n\n## 人类质询点\n- 必填项和非必填项区分清楚吗？\n- 隐私级别设置后，不同级别的实际效果是什么？\n- 修改配置后，已匹配的推荐会重新计算吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(617,'DATE-001~edge',17,'异常：配置不完整、极端偏好','edge_case','1. 只填必填项就保存，能成功吗？\n2. 设置极端偏好（如年龄范围 18-100），系统如何处理\n3. 清空已保存的配置，系统是否恢复为默认',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(618,'DATE-002~func',18,'Agent 根据画像和过滤规则自动推荐匹配对象','functional','## 前置准备\n- 完成 DATE-001\n- 多个测试账号已配置交友画像\n\n## 验收步骤\n1. 等待 Agent 自动扫描匹配\n2. 收到匹配推荐通知\n3. 打开推荐列表，查看推荐的用户\n4. 验证：推荐用户均符合过滤条件（地域、属性）\n5. 每个推荐有匹配度评分\n6. 点击一个推荐查看详情\n\n## 人类质询点\n- 推荐质量如何？匹配度分数合理吗？\n- 过滤条件真的生效了吗？故意配置不兼容的条件验证无推荐\n- 推荐数量合理吗？不会太多或太少？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(619,'DATE-002~edge',18,'异常：无匹配用户、过滤条件过严','edge_case','1. 设置极严的过滤条件（如特定城市+极窄年龄），确认无推荐\n2. 过滤条件修改后，推荐列表是否刷新\n3. Agent 推荐的用户已注销账号，推荐列表中是否移除',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(620,'DATE-003~func',19,'双方 Agent 先对话，匹配度高后请求引荐','functional','## 前置准备\n- 完成 DATE-002（已有推荐）\n- 完成 US-AGENT-007、US-AGENT-008\n- 两个账号各自接受推荐\n\n## 验收步骤\n1. 选择推荐列表中的一个用户\n2. 发起 Agent 间对话\n3. 观察双方 Agent 开始聊天（寒暄、了解对方）\n4. 用户可查看对话进展\n5. 当匹配度达标时，双方用户收到引荐请求\n6. 双方接受引荐后进入四人群聊\n\n## 人类质询点\n- Agent 间的对话质量如何？是真实有意义的交流吗？\n- 匹配度达标后，引荐请求是否及时？\n- 对话过程中用户想终止怎么办？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(621,'DATE-003~edge',19,'异常：Agent 对话卡住、引荐请求未到达','edge_case','1. Agent 对话中一方 AI 服务不可用，对话是否暂停并通知用户\n2. 匹配度达标但一方用户未收到引荐请求，检查通知机制\n3. 对话超过最大轮数仍未达标，是否自动终止并通知用户',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(622,'DATE-004~func',20,'双方接受引荐后进入四人群聊交友','functional','## 前置准备\n- 完成 DATE-003（引荐已完成）\n- US-AGENT-007（身份切换功能）\n\n## 验收步骤\n1. 双方接受引荐后，自动进入四人群聊\n2. 验证：四人群聊界面包含用户 A、A 的 Agent、用户 B、B 的 Agent\n3. 各成员正常发言\n4. Agent 提供交友话题建议（侧边栏）\n5. 用户可切换亲自聊/Agent 代聊\n6. 验证消息身份标识正确\n\n## 人类质询点\n- 四个人同时发言时，消息顺序是否清晰？\n- Agent 的话题建议有帮助吗？\n- 群聊体验流畅吗？有没有明显卡顿或消息丢失？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(623,'DATE-004~edge',20,'异常：成员离线、消息丢失','edge_case','1. 一方用户退出群聊，剩余三人状态如何\n2. 一方断网重连后，错过的消息是否补发\n3. 四人群聊中有人被举报，举报后的处理流程',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(624,'DATE-005~func',21,'约会完成后双方评分，影响信用分','functional','## 前置准备\n- 完成 DATE-004（已完成四人群聊交流）\n\n## 验收步骤\n1. 交流结束后，弹出评分界面\n2. 多维度评分：诚信度、礼貌度、响应度、满意度（1-5 星）\n3. 提交评分\n4. 验证：信用分根据评分结果发生变化\n5. 用另一账号评分，确认双向评分\n\n## 人类质询点\n- 评分界面友好吗？各维度的说明是否清楚？\n- 信用分变化的算法合理吗？评分后信用分应该有明显变化\n- 如果不评分能继续用 App 吗？评分是强制的吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(625,'DATE-005~edge',21,'异常：恶意评分、重复评分','edge_case','1. 连续给同一人打最低分，是否触发反作弊检查\n2. 尝试对同一次交流评分两次，应阻止\n3. 评分后撤销，是否支持',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(626,'JOB-001~func',22,'求职者配置 Agent：技能、经验、期望薪资','functional','## 前置准备\n- 完成 US-AGENT-011\n\n## 验收步骤\n1. 进入 AgentJob 场景，选择求职者角色\n2. 填写技能标签（如 Java、React 等）\n3. 填写工作经历\n4. 设置期望薪资范围\n5. 设置工作偏好（全职/兼职、远程/现场等）\n6. 保存配置\n7. 验证：配置已正确保存并可查看\n\n## 人类质询点\n- 技能标签的选择方式方便吗？搜索和选择流畅吗？\n- 工作经历的格式是否灵活？\n- 如果用户没有工作经历怎么办？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(627,'JOB-001~edge',22,'异常：信息不完整、虚假技能','edge_case','1. 只填基本信息就提交，系统要求补充哪些\n2. 填写明显不合理的薪资（如应届生要求月薪 10 万），系统是否有提示\n3. 修改已保存的技能标签，匹配结果是否重新计算',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(628,'JOB-002~func',23,'招聘方配置 Agent：发布职位需求','functional','## 前置准备\n- 完成 US-AGENT-012\n\n## 验收步骤\n1. 进入 AgentJob 场景，选择招聘方角色\n2. 填写职位信息（职位名称、职责描述）\n3. 设置薪资预算范围\n4. 设置硬性条件（学历、工作年限等）\n5. 设置软性偏好（性格、加分项）\n6. 保存并发布\n7. 验证：职位已发布并可被求职者 Agent 看到\n\n## 人类质询点\n- 职位发布流程流畅吗？必填项合理吗？\n- 硬性条件和软性偏好的区分是否清晰？\n- 发布后能否修改？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(629,'JOB-002~edge',23,'异常：职位信息不完整、薪资冲突','edge_case','1. 只填标题不填描述就发布，应提示补充\n2. 设置矛盾的硬性条件（如"必须应届"+"5年以上经验"），系统应提示\n3. 职位过期后自动下架还是保持？',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(630,'JOB-003~func',24,'Agent 间自动匹配职位和简历，双向过滤','functional','## 前置准备\n- 完成 JOB-001 和 JOB-002\n- 多个求职者和招聘方已配置\n\n## 验收步骤\n1. 招聘方 Agent 自动扫描符合条件的简历\n2. 求职者 Agent 自动匹配符合期望的职位\n3. 双方都满足过滤条件时，向双方推荐\n4. 验证：推荐给招聘方的简历符合硬性条件\n5. 验证：推荐给求职者的职位符合期望薪资\n6. 查看匹配度评分\n\n## 人类质询点\n- 双向过滤真的生效了吗？用不符合条件的组合验证不推荐\n- 匹配度分数合理吗？\n- 推荐数量合理吗？会不会推荐太多看不过来？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(631,'JOB-003~edge',24,'异常：单向匹配、过滤条件变更','edge_case','1. 求职者符合职位要求但职位不符合求职者期望，不应推荐\n2. 修改过滤条件后，已推荐的是否移除\n3. 一方配置信息为空时，匹配如何处理',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(632,'JOB-004~func',25,'双方 Agent 和用户在四人群聊中协商薪资','functional','## 前置准备\n- 完成 JOB-003 和 US-AGENT-007\n- 双方匹配成功\n\n## 验收步骤\n1. 匹配成功后进入四人群聊\n2. 双方 Agent 进行薪资范围协商\n3. 用户可切换亲自聊参与协商\n4. 达成一致后，Agent 引荐真人面试\n5. 验证：引荐后双方用户进入直接沟通\n\n## 人类质询点\n- Agent 协商薪资时是否保护了用户的底线（不泄露最低薪资）？\n- 协商过程清晰吗？用户能跟上节奏吗？\n- 引荐时机合理吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(633,'JOB-004~edge',25,'异常：协商僵局、薪资超出底线','edge_case','1. 双方薪资期望差距过大，Agent 是否能识别并及时终止\n2. Agent 协商中不小心透露了用户底线薪资，是否有防护\n3. 一方中途退出协商，另一方是否得到通知',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(634,'JOB-005~func',26,'面试完成后双方评分','functional','## 前置准备\n- 完成 JOB-004\n\n## 验收步骤\n1. 面试结束后弹出评分界面\n2. 双向评分\n3. 验证：信用分根据评分变化\n4. 查看信用分变化记录\n\n## 人类质询点\n- 与 DATE-005 的评分流程一致吗？\n- 招聘方对求职者的评分维度和求职者对招聘方的评分维度是否不同？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(635,'JOB-005~edge',26,'异常：未面试就评分','edge_case','1. 尝试在未进行任何交流的情况下评分，应不允许\n2. 对同一次面试重复评分，应阻止',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(636,'AD-001~func',27,'用户配置 Agent：品类、预算、品牌偏好','functional','## 前置准备\n- 完成 US-AGENT-011\n\n## 验收步骤\n1. 进入 AgentAd 场景\n2. 设置感兴趣的品类（如电子产品、旅游等）\n3. 设置预算范围\n4. 设置品牌偏好（如只关注某些品牌）\n5. 保存配置\n6. 验证：配置已保存\n\n## 人类质询点\n- 品类选择方式方便吗？支持搜索和浏览吗？\n- 预算范围设置合理吗？\n- 品牌偏好是必须的吗？可以不选吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(637,'AD-001~edge',27,'异常：无偏好设置、极端预算','edge_case','1. 不设置任何偏好，Agent 是否不会推送任何广告\n2. 设置极低预算（如 1 元），匹配结果如何\n3. 修改偏好后，已推送的广告是否重新筛选',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(638,'AD-002~func',28,'商家配置 Agent：目标客户、优惠、推广预算','functional','## 前置准备\n- 完成 US-AGENT-012\n\n## 验收步骤\n1. 进入 AgentAd 场景，选择商家角色\n2. 设置目标客户画像（品类、年龄、地区等）\n3. 创建优惠活动（折扣、优惠码等）\n4. 设置推广预算\n5. 保存并发布\n6. 验证：优惠可被符合条件的用户 Agent 看到\n\n## 人类质询点\n- 目标客户画像设置灵活吗？\n- 优惠活动创建方便吗？\n- 推广预算用完后的行为是什么？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(639,'AD-002~edge',28,'异常：目标客户描述为空、预算为零','edge_case','1. 不设置目标客户画像就发布优惠，应要求设置\n2. 推广预算设为 0，应拒绝或提示\n3. 优惠活动过期后是否自动下架',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(640,'AD-003~func',29,'Agent 间匹配用户需求和商家优惠，双向过滤','functional','## 前置准备\n- 完成 AD-001 和 AD-002\n\n## 验收步骤\n1. 用户 Agent 扫描符合条件的商家优惠\n2. 商家 Agent 扫描符合条件的用户需求\n3. 双向匹配通过后推送\n4. 验证：推送的广告符合用户偏好\n5. 验证：推送的用户符合商家目标画像\n6. 查看匹配度评分\n\n## 人类质询点\n- 推送的广告真的精准吗？还是什么类型的都有？\n- 双向过滤是否真的双向？用不匹配的组合验证不推送\n- 推送频率合理吗？会不会推送太多骚扰用户？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(641,'AD-003~edge',29,'异常：推送过多/过少、匹配质量差','edge_case','1. 设置极宽的用户偏好，验证推送数量是否有限制\n2. 推送的广告质量很差（完全不符合偏好），检查是否有最低匹配阈值\n3. 商家优惠已过期但仍被推送，验证优惠有效期检查',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(642,'AD-004~func',30,'Agent 与商家 Agent 谈判争取更好优惠','functional','## 前置准备\n- 完成 AD-003（已匹配）\n- US-AGENT-007\n\n## 验收步骤\n1. 匹配后进入四人群聊\n2. 用户 Agent 与商家 Agent 开始谈判\n3. 协商优惠条件（折扣力度、附加服务等）\n4. 用户可实时查看谈判进展\n5. 用户可接收 Agent 的私聊建议\n6. 达成双方满意的方案\n\n## 人类质询点\n- 谈判过程公平吗？Agent 有没有出卖用户利益？\n- 用户能介入谈判吗？\n- 谈判达成的方案真的比原始优惠好吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(643,'AD-004~edge',30,'异常：谈判僵局、商家拒绝让步','edge_case','1. 商家 Agent 完全不让步，用户 Agent 是否建议用户放弃\n2. 用户设置的价格底线被触碰时，Agent 是否正确反应\n3. 谈判超过最大轮数仍未达成，是否终止并通知用户',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(644,'AD-005~func',31,'一键购买后评价商家','functional','## 前置准备\n- 完成 AD-004（已达成优惠方案）\n\n## 验收步骤\n1. 在四人群聊中点击"一键购买"\n2. 跳转到商家页面\n3. 验证：优惠码自动应用\n4. 完成购买流程\n5. 购买完成后弹出评分界面\n6. 对商家评分\n7. 验证：信用分根据评分变化\n\n## 人类质询点\n- 一键购买跳转流畅吗？优惠码确实生效了吗？\n- 评分流程与约会/面试后评分一致吗？\n- 购买后不评分能继续用吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(645,'AD-005~edge',31,'异常：购买失败、优惠码无效','edge_case','1. 跳转商家页面后优惠码已过期，如何处理\n2. 购买过程中断，订单状态如何\n3. 商家页面不存在或商品信息变更，如何处理',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(646,'AS-001~func',32,'Agent 被创建后能读取主人画像、学习规则、生成本场景性格','functional','## 前置准备\n- `pnpm dev` 启动\n- 注册新用户\n\n## 验收步骤\n1. 创建新用户并创建 Agent\n2. 选择场景（如 VisionShare）\n3. 进入 Agent 管理页面，查看 Agent 的性格和行为准则\n4. 验证：Agent 的性格已根据场景生成（如 VisionShare 的 Agent 更注重地理相关）\n5. 验证：Agent 已读取主人的基础画像\n6. 验证：Agent 已学习本场景的过滤规则\n\n## 人类质询点\n- Agent 的性格描述是否具体且与场景相关？\n- 如果主人画像为空，Agent 怎么处理？\n- 不同场景的 Agent 性格有明显区别吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(647,'AS-001~edge',32,'异常：主人画像缺失、场景规则加载失败','edge_case','1. 主人未完善画像就创建 Agent，Agent 性格是否正常生成\n2. 场景规则加载失败时，Agent 是否有默认行为准则\n3. 同时创建多个场景的 Agent，各 Agent 是否独立',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(648,'AS-002~func',33,'Agent 解析主人自然语言输入，提炼成结构化需求','functional','## 前置准备\n- 完成 AS-001\n\n## 验收步骤\n1. 进入 Agent 对话界面\n2. 用自然语言告诉 Agent 需求\n3. 观察 Agent 主动追问关键信息\n4. 完成多轮对话\n5. 查看 Agent 提炼的结构化需求（queryable/readable/private 三层）\n6. 确认存储\n7. 验证：存储后触发了实时匹配（看到匹配结果推送）\n\n## 人类质询点\n- 三层字段（queryable/readable/private）的划分合理吗？\n- Agent 追问的问题是否都是关键信息？\n- 确认后匹配是否真的被触发？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(649,'AS-002~edge',33,'异常：需求提炼失败、三层字段为空','edge_case','1. AI 提炼服务不可用时，需求是否能被手动创建\n2. 主人拒绝提供某些信息时，需求结构是否仍完整\n3. 需求确认后修改，匹配是否重新触发',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(650,'AS-003~func',34,'Agent 理解主人供给能力，记录为供给档案','functional','## 前置准备\n- 完成 AS-001\n\n## 验收步骤\n1. 进入 Agent 对话界面\n2. 用自然语言告诉 Agent 自己的供给能力\n3. Agent 提取三层字段\n4. 验证：供给档案已创建\n5. 验证：供给状态为激活（等待匹配查询）\n6. 用另一账号尝试查询该供给，验证可被匹配\n\n## 人类质询点\n- 供给和需求的使用体验是否一致？\n- 供给档案的结构清晰吗？\n- 供给激活后多久能收到匹配？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(651,'AS-003~edge',34,'异常：供给信息为空、激活失败','edge_case','1. 供给信息不完整就确认，应提示补充\n2. 供给激活失败是否有错误提示\n3. 停用后再激活供给，状态是否正确',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(652,'AS-004~func',35,'Agent 批量读取候选公开信息，计算匹配度并排序','functional','## 前置准备\n- 完成 AS-002 或 AS-003\n- 多个测试账号已创建需求或供给\n\n## 验收步骤\n1. 主人表达需求或供给\n2. Agent 收到系统返回的候选列表\n3. Agent 批量读取候选公开信息\n4. 计算匹配度分数\n5. 按分数排序推荐给用户\n6. 验证：排序结果合理（高分在前）\n7. 用户可查看每个候选的匹配理由\n\n## 人类质询点\n- 匹配度算法准确吗？排序结果是否合理？\n- 批量读取候选的速度如何？大量候选时会不会慢？\n- 匹配理由是否具体有用？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(653,'AS-004~edge',35,'异常：无候选、匹配算法出错','edge_case','1. 系统中无符合条件的候选，Agent 如何通知用户\n2. 匹配算法出错时，用户是否得到友好提示\n3. 候选数量极大（如 1000 个），Agent 是否能高效筛选',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(654,'AS-005~func',36,'Agent 自主决定与符合条件的候选 Agent 发起对话','functional','## 前置准备\n- 完成 AS-004\n- 多个测试账号有匹配的候选列表\n\n## 验收步骤\n1. Agent 根据过滤规则筛选候选\n2. Agent 自主向一个候选 Agent 发起对话请求\n3. 观察：对话成功建立\n4. Agent 同时向多个候选发起对话\n5. 验证：每个对话独立进行\n6. 用户可查看各对话进展\n\n## 人类质询点\n- Agent 选择与谁对话的策略合理吗？\n- 同时与多个候选对话，会不会混乱？\n- 发起对话失败（对方不在线/拒绝）怎么处理？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(655,'AS-005~edge',36,'异常：对方拒绝对话、同时对话数过多','edge_case','1. 候选 Agent 的隐私设置不允许主动对话，发起方是否得到通知\n2. 同时与 10 个以上候选对话，是否有上限\n3. Agent 对话建立后候选被删除，对话是否终止',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(656,'AS-006~func',37,'Agent 被其他 Agent 联系后评估是否值得交流','functional','## 前置准备\n- 完成 AS-005\n\n## 验收步骤\n1. 另一个 Agent 主动发起对话\n2. 被联系的 Agent 检查匹配度\n3. Agent 评估是否值得交流\n4. 值得交流 → 开始对话；不值得 → 礼貌拒绝\n5. 向主人汇报对话进展\n6. 用户可查看 Agent 的评估理由\n\n## 人类质询点\n- Agent 的评估标准合理吗？\n- 汇报进展的频率和内容合适吗？\n- 拒绝时是否礼貌且不会得罪对方？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(657,'AS-006~edge',37,'异常：大量 Agent 同时联系','edge_case','1. 10 个 Agent 同时联系，是否会排队处理或全部回应\n2. 匹配度刚好在临界值（如阈值是 70，匹配度 69），Agent 如何处理\n3. Agent 评估过程中 AI 服务不可用',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(658,'AS-007~func',38,'Agent 根据信任水平决定是否向对方披露详细信息','functional','## 前置准备\n- 完成 AS-006\n\n## 验收步骤\n1. 对方 Agent 在对话中请求详细信息\n2. Agent 分析当前信任水平（基于对话轮数、匹配度等）\n3. 根据披露策略执行：\n   - 每次确认模式 → 请求主人确认\n   - 自动模式 → 自动披露\n4. 验证：已披露信息被记录\n5. 验证：信任水平低时拒绝披露\n\n## 人类质询点\n- 信任水平的计算方式透明吗？用户能理解吗？\n- 自动模式下，用户能否否决？\n- 披露的信息是否都是主人设置的可披露范围？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(659,'AS-007~edge',38,'异常：披露策略被绕过、信任计算错误','edge_case','1. 通过 API 直接请求未披露的信息，应返回 403\n2. 信任水平突然变化（如对方被举报），已披露信息是否撤回\n3. 披露记录是否正确（已披露 vs 未披露清晰区分）',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(660,'AS-008~func',39,'Agent 实时分析对话，向主人发送私下建议','functional','## 前置准备\n- 完成 AS-006\n\n## 验收步骤\n1. Agent 与其他 Agent 对话中\n2. Agent 实时分析对方意图和态度\n3. 向主人发送策略建议、风险提示或话题推荐\n4. 主人收到私聊建议（仅自己可见）\n5. 提供一键采纳功能\n6. 采纳后以主人身份发送到群聊\n\n## 人类质询点\n- 建议是否及时？有没有滞后？\n- 建议内容实用吗？\n- 一键采纳后消息发送的时机合理吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(661,'AS-008~edge',39,'异常：建议为空、AI 服务降级','edge_case','1. AI 对话分析服务不可用时，建议模块是否优雅降级\n2. 短时间内生成大量建议，是否有频率控制\n3. 对话结束后建议是否停止',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(662,'AS-009~func',40,'匹配度达标后 Agent 请求主人确认引荐','functional','## 前置准备\n- 完成 AS-006、AS-008\n\n## 验收步骤\n1. Agent 对话中匹配度达到引荐阈值\n2. Agent 向主人展示引荐请求：对方信息 + 信用分 + 匹配理由\n3. 主人可选择接受或拒绝\n4. 接受 → 双方 Agent 请求各自主人确认\n5. 双方均接受 → 引荐成功，进入四人群聊\n6. 拒绝 → 引荐终止\n\n## 人类质询点\n- 引荐阈值合理吗？不会太低（随便引荐）或太高（永远引荐不了）\n- 引荐请求的展示信息是否充分？\n- 引荐被拒后 Agent 是否礼貌处理？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(663,'AS-009~edge',40,'异常：引荐请求超时、一方接受一方拒绝','edge_case','1. 引荐请求长时间不回应，是否超时自动取消\n2. 一方接受但另一方拒绝，状态是否一致\n3. 引荐过程中一方信用分突然降低，引荐是否被取消',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(664,'AS-VS-001~func',41,'Agent 解析主人地点意图，设置过滤条件并寻找响应者','functional','## 前置准备\n- 完成 AS-002\n- 在 VisionShare 场景\n\n## 验收步骤\n1. 主人告诉 Agent 想看某地实时情况\n2. Agent 解析地点意图和过滤条件\n3. Agent 筛选信用高、距离近的候选响应者\n4. 发布视觉需求\n5. 验证：需求推送到符合条件的附近用户\n\n## 人类质询点\n- 地点解析准确吗？\n- Agent 筛选候选的标准透明吗？\n- 推送的时机合理吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(665,'AS-VS-001~edge',41,'异常：无法解析地点、无候选响应者','edge_case','1. 地点无法解析，Agent 是否引导主人重新输入\n2. 附近无符合条件的响应者，Agent 是否通知主人\n3. 主人修改需求后，Agent 是否重新筛选推送',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(666,'AS-VS-002~func',42,'Agent 判断主人是否适合响应附近视觉任务','functional','## 前置准备\n- 完成 AS-001（VisionShare 场景）\n- 附近有视觉需求\n\n## 验收步骤\n1. Agent 检测到附近有视觉需求\n2. 检查主人位置和相册是否匹配\n3. 推荐可接任务给主人\n4. 主人选择接单\n5. Agent 处理照片的隐私脱敏\n6. 脱敏后照片上传\n7. 验证：照片可被需求方查看\n\n## 人类质询点\n- 推荐的任务真的适合主人吗？\n- 脱敏处理是否可靠？\n- 上传后积分收入是否展示？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(667,'AS-VS-002~edge',42,'异常：无匹配照片、脱敏失败','edge_case','1. 主人相册无匹配照片，Agent 是否引导拍摄\n2. 照片脱敏失败，是否阻止上传\n3. 接单后主人不想拍了，能否取消',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(668,'AS-DATE-001~func',43,'Agent 在符合过滤条件的用户中寻找高匹配度对象','functional','## 前置准备\n- 完成 AS-004\n- AgentDate 场景\n\n## 验收步骤\n1. Agent 应用地域和属性过滤\n2. 批量评估候选用户的匹配度\n3. 精选 Top 候选推荐给用户\n4. 验证：推荐用户均符合过滤条件\n5. 验证：推荐有匹配度评分和理由\n\n## 人类质询点\n- Top 候选的选择标准合理吗？\n- 推荐质量如何？匹配度分数可信吗？\n- 推荐数量和频率合理吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(669,'AS-DATE-001~edge',43,'异常：过滤后无候选','edge_case','1. 过滤条件过严导致无候选，Agent 是否建议放宽条件\n2. 所有候选匹配度都很低，Agent 是否仍推荐\n3. 新增用户后，推荐列表是否自动刷新',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(670,'AS-DATE-002~func',44,'Agent 与对方 Agent 聊天评估性格匹配度','functional','## 前置准备\n- 完成 AS-DATE-001、AS-005\n\n## 验收步骤\n1. Agent 与对方 Agent 开始寒暄破冰\n2. 通过对话评估性格匹配度\n3. 双方感觉合适后请求引荐\n4. 向主人汇报评估结果\n\n## 人类质询点\n- 对话自然吗？像在交友还是在面试？\n- 性格匹配度评估合理吗？\n- 引荐请求的时机合适吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(671,'AS-DATE-002~edge',44,'异常：对话不投机、匹配度无法提升','edge_case','1. 多轮对话后匹配度仍然很低，Agent 是否主动终止\n2. 对方 Agent 行为异常（如刷屏），是否终止并通知\n3. 对话中涉及敏感话题，Agent 如何处理',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(672,'AS-JOB-001~func',45,'求职者 Agent 匹配职位并与 HR Agent 协商','functional','## 前置准备\n- 完成 AS-004\n- AgentJob 场景，求职者角色\n\n## 验收步骤\n1. Agent 应用求职者的过滤条件\n2. 同时与多个 HR Agent 沟通\n3. 协商薪资，保护主人底线\n4. 向主人汇报协商进展\n5. 推荐最合适的职位\n\n## 人类质询点\n- Agent 真的保护了主人的薪资底线吗？\n- 与多个 HR Agent 同时沟通是否混乱？\n- 推荐的职位确实符合期望吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(673,'AS-JOB-001~edge',45,'异常：薪资底线被触碰','edge_case','1. HR 给出的薪资范围低于主人底线，Agent 是否拒绝\n2. HR 试图打探底线信息，Agent 是否拒绝透露\n3. 所有 HR 都不符合条件，Agent 是否建议调整期望',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(674,'AS-JOB-002~func',46,'招聘方 Agent 筛选简历并与候选人 Agent 初筛','functional','## 前置准备\n- 完成 AS-004\n- AgentJob 场景，招聘方角色\n\n## 验收步骤\n1. Agent 批量评估候选简历\n2. 同时与多个候选人 Agent 初筛对话\n3. 评估候选人是否符合职位要求\n4. 向主人推荐最合适的候选人\n\n## 人类质询点\n- 简历评估标准合理吗？\n- 初筛对话有效吗？能过滤掉明显不合适的候选人吗？\n- 推荐数量合理吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(675,'AS-JOB-002~edge',46,'异常：简历信息不足、初筛无法判断','edge_case','1. 候选人简历信息很少，Agent 是否要求补充\n2. 初筛对话无法判断是否合适，Agent 是否建议真人面试\n3. 候选人大量不符合硬性条件，Agent 是否提醒招聘方调整要求',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(676,'AS-AD-001~func',47,'消费者 Agent 同时与多个商家 Agent 谈判比价','functional','## 前置准备\n- 完成 AS-004\n- AgentAd 场景，消费者角色\n\n## 验收步骤\n1. Agent 应用消费者的过滤条件\n2. 同时与多个商家 Agent 谈判\n3. 对比各家优惠方案\n4. 向主人推荐最优方案\n\n## 人类质询点\n- 比价结果可信吗？推荐确实是最优的吗？\n- 同时与多个商家谈判是否混乱？\n- 推荐方案包含的信息完整吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(677,'AS-AD-001~edge',47,'异常：所有商家方案都不好','edge_case','1. 所有商家方案都不符合主人预算，Agent 是否建议等待或调整\n2. 商家给出虚假优惠，Agent 能否识别\n3. 商家优惠有时效限制，Agent 是否及时通知主人',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(678,'AS-AD-002~func',48,'商家 Agent 寻找潜在客户并推销优惠','functional','## 前置准备\n- 完成 AS-004\n- AgentAd 场景，商家角色\n\n## 验收步骤\n1. Agent 评估用户需求与优惠的匹配度\n2. 向匹配的用户推送优惠\n3. 与用户 Agent 协商优惠条件\n4. 达成双方满意的方案\n\n## 人类质询点\n- 推销的精准度如何？\n- 协商过程是否公平？\n- 达成方案对主人有吸引力吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(679,'AS-AD-002~edge',48,'异常：无匹配用户、协商失败','edge_case','1. 没有符合目标画像的用户，Agent 是否通知商家\n2. 用户 Agent 拒绝所有优惠条件，Agent 是否建议调整\n3. 推广预算用完但无成交，Agent 是否提醒商家',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(680,'US-AGENT-010~func',49,'双方真人交流后互相评分，影响信用分','functional','## 前置准备\n- 完成任意场景的四人群聊交流（DATE-004 或 JOB-004）\n\n## 验收步骤\n1. 交流结束后弹出评分界面\n2. 多维度评分：诚信度、礼貌度、响应度、满意度（1-5星）\n3. 提交评分\n4. 验证：信用分根据评分变化\n5. 用另一账号评分，确认双向评分\n\n## 人类质询点\n- 评分后信用分变化是否合理？\n- 各维度评分的说明是否清楚？\n- 不评分能继续使用 App 吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(681,'US-AGENT-010~edge',49,'异常：恶意评分、重复评分','edge_case','1. 尝试给同一人连续打最低分，是否触发反作弊\n2. 对同一次交流评分两次，应阻止\n3. 未进行任何交流就尝试评分，应不允许',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(682,'US-AGENT-013~func',50,'通过 Agent 浏览对方的公开需求和供给','functional','## 前置准备\n- 完成 US-AGENT-002\n- 多个测试账号已配置需求/供给\n\n## 验收步骤\n1. 进入浏览页面\n2. Agent 展示对方的公开需求和供给概要\n3. 验证：只能看到公开信息（详细信息被隐藏）\n4. 每个条目显示匹配度评估\n5. 点击查看匹配理由\n\n## 人类质询点\n- 公开信息是否真的不包含私密内容？\n- 匹配度评估准确吗？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(683,'US-AGENT-013~edge',50,'异常：尝试查看详细信息','edge_case','1. 点击尝试查看详细信息，应触发披露流程或被拒绝\n2. 通过 API 直接请求详细信息接口，应返回 403',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(684,'US-AGENT-015~func',51,'用户在匹配过程中随时退出','functional','## 前置准备\n- 进入任意匹配流程（推荐列表或四人群聊）\n\n## 验收步骤\n1. 在匹配列表页点击退出\n2. 验证：匹配流程终止\n3. Agent 礼貌结束对话\n4. 在四人群聊中点击退出\n5. 验证：群聊状态更新，对方收到通知\n\n## 人类质询点\n- 退出流程顺畅吗？有确认步骤吗？\n- 退出后对方收到的通知是否礼貌？\n- 退出后能否重新加入？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(685,'US-AGENT-015~edge',51,'异常：频繁退出加入','edge_case','1. 退出后立即重新加入，是否允许\n2. 频繁退出加入（5次以内），是否有限制\n3. 退出后匹配数据是否保留',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(686,'US-AGENT-016~func',52,'用户在对话界面举报不当行为','functional','## 前置准备\n- 进入四人群聊或对话界面\n\n## 验收步骤\n1. 在对话界面找到举报入口\n2. 选择举报类型\n3. 上传证据（消息截图等）\n4. 提交举报\n5. 验证：举报已提交并收到确认\n\n## 人类质询点\n- 举报入口好找吗？\n- 举报类型分类清楚吗？\n- 举报后多久有反馈？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(687,'US-AGENT-016~edge',52,'异常：恶意举报','edge_case','1. 尝试举报不存在的消息，应阻止\n2. 短时间内频繁举报，是否触发审核\n3. 举报后撤销，是否支持',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(688,'US-AGENT-017~func',53,'用户注销某场景的 Agent','functional','## 前置准备\n- 用户有多个场景的 Agent\n\n## 验收步骤\n1. 进入 Agent 管理页面\n2. 选择一个场景的 Agent\n3. 点击注销\n4. 确认注销\n5. 验证：该场景 Agent 已注销\n6. 验证：历史交易记录仍保留\n\n## 人类质询点\n- 注销确认流程清楚吗？有二次确认吗？\n- 历史交易记录真的保留了吗？\n- 注销后能否重新创建同场景 Agent？',1,NULL,NULL,NULL,NULL,NULL,'pending','pending');
INSERT INTO acceptance_criteria VALUES(689,'US-AGENT-017~edge',53,'异常：注销后重新创建','edge_case','1. 注销后立即重新创建同场景 Agent，是否允许\n2. 注销所有场景的 Agent 后，账号是否仍然可用\n3. 注销过程中有进行中的匹配，如何处理',2,NULL,NULL,NULL,NULL,NULL,'pending','pending');
