INSERT INTO nitpick_findings VALUES(1,'NP-1',92,1049,'reviewed-to-implemented','code_quality','critical','3 types missing from types/chat.ts: ParticipantStatusInfo, ParticipantIdentity, UserOnlineStatus. All new components import these types from types/chat.ts but they are never defined there. TypeScript compiler reports 8 TS2305 errors across 6 source files.','tsc output shows 8 errors: IdentityBadge.tsx, ParticipantStatusBar.tsx, ParticipantStatusCard.tsx(2), StatusChangeNotification.tsx, UserStatusIndicator.tsx, plus 2 in test files. All TS2305 Module has no exported member.','Add missing types to types/chat.ts: ParticipantIdentity (agent|human), UserOnlineStatus (online|offline|away), ParticipantStatusInfo interface.','apps/mobile/src/types/chat.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-19 08:22:58.928945','2026-04-19 10:54:41.004117');
INSERT INTO nitpick_findings VALUES(2,'NP-2',92,1049,'reviewed-to-implemented','test_coverage','critical','SenderIndicator.tsx (317 lines, 2 exported components with complex animation logic) has no test file at all.','Component exists at apps/mobile/src/components/Chat/SenderIndicator.tsx but no test file at apps/mobile/src/components/Chat/__tests__/SenderIndicator.test.tsx','Create SenderIndicator.test.tsx covering: each SenderType variant, transition with HandoffStatus states, SenderChangeIndicator, animate=false fallback.','apps/mobile/src/components/Chat/SenderIndicator.tsx',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-19 08:22:58.930046','2026-04-19 10:54:41.004835');
INSERT INTO nitpick_findings VALUES(3,'NP-3',92,1049,'reviewed-to-implemented','code_quality','warning','StatusChangeNotification receives fromIdentity prop but never uses it. Aliased to _fromIdentity on line 42, never referenced.','Line 42: fromIdentity: _fromIdentity - unused variable','Either remove fromIdentity prop or use it to show contextual transition info.','apps/mobile/src/components/Chat/StatusChangeNotification.tsx:42',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-19 08:22:58.930655','2026-04-19 10:54:41.005171');
INSERT INTO nitpick_findings VALUES(4,'NP-4',92,1049,'reviewed-to-implemented','code_quality','warning','StatusChangeNotification uses 5 hardcoded hex colors (#FEF3C7, #FDE68A, #92400E) instead of theme tokens. All other components correctly use theme.colors.*.','Styles lines 98-128: backgroundColor #FEF3C7, borderColor #FDE68A, color #92400E (3x)','Add notification colors to theme or use existing semantic tokens.','apps/mobile/src/components/Chat/StatusChangeNotification.tsx',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-19 08:22:58.931160','2026-04-19 10:54:41.005471');
INSERT INTO nitpick_findings VALUES(5,'NP-5',92,1049,'reviewed-to-implemented','verification','warning','OnlineStatus.test.tsx was modified in this commit (clearAllMocks->resetAllMocks, container->UNSAFE_root) but still fails 10/10 with host component detection error from @testing-library/react-native.','git diff shows changes. Test output: 10 failed, 10 total. Error: Unable to find element with testID text during host component detection.','Fix was incomplete. Real issue is @testing-library/react-native mock compatibility. Fix mock or skip tests as tech debt.','apps/mobile/src/__tests__/components/OnlineStatus.test.tsx',NULL,'dismissed',NULL,NULL,NULL,'2026-04-19 08:22:58.931620','2026-04-19 10:54:41.005749');
INSERT INTO nitpick_findings VALUES(6,'NP-6',84,1050,'reviewed-to-implemented','test_coverage','critical','33/112 integration tests fail (3/6 suites): auth.integration, user.integration, error.integration. Tests assert against API endpoints and response formats that do not match the actual server implementation.','Test output: FAIL auth.integration.test.ts, FAIL user.integration.test.ts, FAIL error.integration.test.ts. Tests: 33 failed, 79 passed, 112 total.','Fix test assertions to match actual API routes and response format, OR implement the expected API endpoints.','apps/server/src/tests/integration/',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.816237',NULL);
INSERT INTO nitpick_findings VALUES(7,'NP-7',84,1050,'reviewed-to-implemented','test_coverage','critical','Tests reference /api/v1/auth/register endpoint which does not exist. 4 auth tests test registration (success, invalid email, weak password, duplicate email) but the auth route only has /login, /refresh, /logout, /logout-all, /me.','grep router.post / routes/v1/auth.ts shows only /login, /refresh, /logout, /logout-all. ApiPaths.auth.register = /api/v1/auth/register is defined in helpers but no route handles it.','Either implement POST /api/v1/auth/register route or remove/update the registration tests.','apps/server/src/tests/integration/auth.integration.test.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.817324',NULL);
INSERT INTO nitpick_findings VALUES(8,'NP-8',84,1050,'reviewed-to-implemented','code_quality','critical','createTestUser helper stores plaintext password as passwordHash instead of bcrypt hash. Login route uses bcrypt.compare() which always returns false for plaintext, causing all login-dependent tests to fail with 401.','auth.ts:151 stores passwordHash: user.password || "hashed-password" (plaintext). auth route uses bcrypt.compare(password, user.passwordHash) which fails for non-hashed values.','Use bcrypt.hash() to hash the password before storing: passwordHash: await bcrypt.hash(user.password, 10)','apps/server/src/tests/helpers/auth.ts:151',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.817891',NULL);
INSERT INTO nitpick_findings VALUES(9,'NP-9',84,1050,'reviewed-to-implemented','test_coverage','critical','User integration tests expect admin CRUD routes at /api/v1/users/:id and /api/v1/users (list), but actual user routes use /me pattern (GET/PUT/DELETE /api/v1/users/me). No admin-only list endpoint exists.','Tests call ApiPaths.users.list (/api/v1/users) and ApiPaths.users.detail(id) (/api/v1/users/:id). Actual routes: /me, /privacy, /avatar, /password, /phone, /email, /devices, /block.','Update tests to match actual /me-based user API routes, or implement admin CRUD endpoints.','apps/server/src/tests/integration/user.integration.test.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.818368',NULL);
INSERT INTO nitpick_findings VALUES(10,'NP-10',84,1050,'reviewed-to-implemented','verification','warning','Auth login test expects body.data.accessToken but actual API response structure is body.data.tokens.accessToken (tokens nested under data.tokens, not directly under data).','Login route returns ApiResponse.success({user: {...}, tokens: {accessToken, refreshToken, expiresIn}}). Test asserts body.data.accessToken but should be body.data.tokens.accessToken.','Update test assertions: body.data.tokens.accessToken instead of body.data.accessToken.','apps/server/src/tests/integration/auth.integration.test.ts:92-94',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.818814',NULL);
INSERT INTO nitpick_findings VALUES(11,'NP-11',84,1050,'reviewed-to-implemented','verification','warning','validateErrorResponse returns false for login empty body test despite status being 400. The error response format from the API may not match what the validator expects (possibly middleware interference in the response pipeline).','Test: Request.post(login, {}) returns status 400 (correct) but validateErrorResponse(response) returns false. ApiResponse.error format: {success:false, message:string, errorCode:string, meta:{statusCode:number}}.','Debug the actual response body in the failing test. The security middleware pipeline (ddosProtection, ipFilter, securityProtection) may modify the error response format.','apps/server/src/tests/helpers/validator.ts:120-127',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.819241',NULL);
INSERT INTO nitpick_findings VALUES(12,'NP-12',84,1050,'reviewed-to-implemented','runtime_behavior','warning','Multiple setInterval/setTimeout calls in middleware (ddosProtection, rateLimiter, clarificationService, securityMonitor) prevent Jest from exiting cleanly, causing open handle warnings. jest.config has forceExit:true as workaround.','Jest output: 4 open handles from setInterval in ddosProtection.ts:187, rateLimiter.ts:65, clarificationService.ts:97, securityMonitor.ts:178.','Use a shared timer manager that can be cleaned up in test teardown, or lazy-initialize timers only when not in test environment.','apps/server/src/middleware/ddosProtection.ts:187',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:32:00.819641',NULL);
INSERT INTO nitpick_findings VALUES(13,'NP-13',77,1054,'reviewed-to-implemented','consistency','critical','Dual data model: CreditScoreService class methods use new CreditScore/CreditHistory/CreditFactor models, but standalone functions updateCreditScore() and recalculateCreditScore() use the old CreditRecord model. Data splits across two incompatible schemas.','creditScoreService.ts line 630: prisma.creditRecord.create(), line 697: prisma.creditRecord.create(). vs class methods line 289: prisma.creditScore.findUnique(), line 352: prisma.creditHistory.create(). grep shows 2 usages of prisma.creditRecord vs 14 usages of prisma.creditScore/creditHistory/creditFactor.','Migrate standalone functions updateCreditScore() and recalculateCreditScore() to use the new CreditScore/CreditHistory models instead of CreditRecord. Or remove the standalone functions and use the class methods throughout.','apps/server/src/services/creditScoreService.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:44:04.149605',NULL);
INSERT INTO nitpick_findings VALUES(14,'NP-14',77,1054,'reviewed-to-implemented','consistency','critical','Shared package CreditLevel type uses "average" but server uses "general". Also score thresholds differ: shared has 800/600/400/0 vs server has 900/750/600/0. Mobile/frontend using shared types will show wrong levels and thresholds.','packages/shared/src/types/credit.ts line 15: CreditLevel type = excellent|good|average|poor. Line 21: average: {min:400,max:599}. apps/server/src/types/credit.ts line 11: GENERAL=general, 600-749. apps/server/src/config/creditLevels.ts: EXCELLENT 900-1000, GOOD 750-899, GENERAL 600-749, POOR 0-599.','Align shared CREDIT_LEVEL_THRESHOLDS and CreditLevel type with server definitions. Change "average" to "general" and update thresholds to 900/750/600/0.','packages/shared/src/types/credit.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:44:04.150876',NULL);
INSERT INTO nitpick_findings VALUES(15,'NP-15',77,1054,'reviewed-to-implemented','verification','critical','POST /api/v1/credit/recalculate for all-users is a no-op: returns fake success "Recalculation job started" without triggering any job. AC4 requires this endpoint to recalculate all users credit scores.','apps/server/src/routes/credit.ts line 193-202: else branch returns {message: "Recalculation job started for all users", note: "This may take a while"} but only has a TODO comment. No actual job is triggered.','Implement the batch recalculation by calling creditUpdateJob or iterating users with creditScoreService.updateCreditScore().','apps/server/src/routes/credit.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:44:04.151397',NULL);
INSERT INTO nitpick_findings VALUES(16,'NP-16',77,1054,'reviewed-to-implemented','code_quality','warning','replyRateBonus hardcoded to 0 with TODO comment. Reply rate tracking is not implemented in recalculateCreditScore.','creditScoreService.ts line 688: const replyRateBonus = 0; // TODO: Implement reply tracking','Implement reply tracking to calculate the bonus, or remove the variable and add a comment explaining this is intentionally deferred.','apps/server/src/services/creditScoreService.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:44:04.151850',NULL);
INSERT INTO nitpick_findings VALUES(17,'NP-17',83,1055,'reviewed-to-implemented','test_coverage','critical','class-validator dependency missing from apps/server/package.json — imported by src/config/security.ts but not installed, causing 8 test suites to cascade-fail with ''Cannot find module class-validator''. Affected tests: encryption, keyManagement, mask, pii, and others importing security.ts.','grep class-validator apps/server/package.json returns empty. pnpm --filter server test 2>&1 shows 8 suites failing with ''Cannot find module class-validator from src/config/security.ts''. Example cascade: security.ts -> mask.ts -> pii.test.ts','Add class-validator and class-transformer to apps/server/package.json dependencies and run pnpm install.','apps/server/package.json',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:48:10.316476',NULL);
INSERT INTO nitpick_findings VALUES(18,'NP-18',83,1055,'reviewed-to-implemented','test_coverage','critical','Incomplete @bridgeai/shared mock — missing AgentAdRole, AgentDateRole, AgentJobRole, HandoffErrorCode, ProfileCompletionResult exports. consumerDemand.test.ts has 17 test failures because AgentAdRole.CONSUMER is undefined at runtime.','grep AgentAdRole apps/server/src/__mocks__/@bridgeai/shared.ts returns 0 matches. AgentAdRole is defined in packages/shared/src/types/agentAdConsumer.ts. consumerDemand.test.ts error: ''Cannot read properties of undefined (reading CONSUMER)'' at consumerDemandService.ts:807','Add missing exports to apps/server/src/__mocks__/@bridgeai/shared.ts: AgentAdRole, AgentDateRole, AgentJobRole, HandoffErrorCode, ProfileCompletionResult, UpdateL1ProfileRequest.','apps/server/src/__mocks__/@bridgeai/shared.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:48:10.317836',NULL);
INSERT INTO nitpick_findings VALUES(19,'NP-19',83,1055,'reviewed-to-implemented','runtime_behavior','warning','Module-level setInterval/setTimeout in ddosProtection.ts (line 187) and securityMonitor.ts (line 178) cause Jest open handle warnings. While forceExit:true handles this, tests importing these modules get noisy timeout errors.','Jest output shows: ''Timeout at Object.<anonymous> (src/middleware/ddosProtection.ts:187:1)'' and ''Timeout at initializeSecurityMonitoring (src/services/securityMonitor.ts:178:5)''. Tests pass but generate handle leak warnings.','Either mock these modules in tests that import them transitively, or add jest.useFakeTimers() in setup.ts to suppress timer-related handles.','apps/server/src/middleware/ddosProtection.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:48:10.318484',NULL);
INSERT INTO nitpick_findings VALUES(20,'NP-20',83,1055,'reviewed-to-implemented','code_quality','info','ts-jest deprecation warning: ''isolatedModules'' config option in jest.config.js is deprecated and will be removed in ts-jest v30.0.0. Should be moved to tsconfig.json.','ts-jest[config] (WARN): The ts-jest config option isolatedModules is deprecated and will be removed in v30.0.0. Please use isolatedModules: true in tsconfig.json instead.','Add isolatedModules: true to apps/server/tsconfig.json compilerOptions and remove the ts-jest isolatedModules config from jest.config.js.','apps/server/jest.config.js',NULL,'open',NULL,NULL,NULL,'2026-04-19 08:48:10.318996',NULL);
INSERT INTO nitpick_findings VALUES(21,'NP-21',78,1060,'reviewed-to-implemented','code_quality','critical','handoffAuth.test.ts still has broken import paths (../../src/ prefix) - RBAC commit only partially fixed test imports','Cannot find module ../../src/services/rbacService from src/middleware/__tests__/handoffAuth.test.ts. Lines 17-18 use ../../src/middleware/handoffAuth and ../../src/services/rbacService. Lines 21,29 jest.mock() calls also use ../../src/ paths. Commit message says Fix test file import paths but only fixed rbac.test.ts and rbacService.test.ts, missed handoffAuth.test.ts and socket.test.ts. TypeScript error: TS2307 Cannot find module ../../src/services/rbacService. Test FAIL: 4 test suites affected.','Change imports in handoffAuth.test.ts from ../../src/ to ../../ paths: line 17 → ../handoffAuth, line 18 → ../../services/rbacService, lines 21,29 → ../../services/rbacService and ../requestContext','apps/server/src/middleware/__tests__/handoffAuth.test.ts',NULL,'open',NULL,NULL,NULL,'2026-04-19 09:07:05.269610',NULL);
INSERT INTO nitpick_findings VALUES(22,'NP-22',78,1060,'reviewed-to-implemented','consistency','warning','Two requireRole implementations with same signature but different behavior - auth.ts (sync, JWT-based) vs rbac.ts (async, DB-based)','src/middleware/auth.ts:149 exports requireRole checking req.user.role (single JWT field, sync). src/middleware/rbac.ts:18 exports requireRole querying rbacService.getUserRoles() from DB (async). admin/index.ts:14 uses auth.ts version for general admin routes. admin/rbac.ts:11 uses rbac.ts version for RBAC management routes. JWT-based check can become stale if user role changes between logins.','Unify on the DB-based requireRole from rbac.ts for all admin routes, or rename auth.ts version to requireRoleJWT to disambiguate. The JWT-based version can give stale results when roles change.','apps/server/src/middleware/auth.ts:149, apps/server/src/middleware/rbac.ts:18',NULL,'open',NULL,NULL,NULL,'2026-04-19 09:07:05.270340',NULL);
INSERT INTO nitpick_findings VALUES(23,'NP-23',13,1070,'implemented-to-accepted','code_quality','warning','Supply extraction API routes are not registered in the application','routes/ai/supply.ts file exists (444 lines) but is not imported in routes/ai/index.ts. The routes/ai/index.ts only imports llmRoutes and visionRoutes. Supply routes are dead code - endpoints are unreachable.','Import and mount supply routes in routes/ai/index.ts','apps/server/src/routes/ai/index.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:30:20.025691','2026-04-20 10:12:08.730076');
INSERT INTO nitpick_findings VALUES(24,'NP-24',13,1070,'implemented-to-accepted','code_quality','warning','SupplyExtractionService not exported from AI services barrel file','services/ai/supplyExtractionService.ts exists (708 lines) but is not exported from services/ai/index.ts','Add export for SupplyExtractionService in services/ai/index.ts','apps/server/src/services/ai/index.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:30:20.027461','2026-04-20 10:44:21.343703');
INSERT INTO nitpick_findings VALUES(25,'NP-25',13,1070,'implemented-to-accepted','test_coverage','warning','Unit test failure: should handle missing fields gracefully','Test expects fieldsFailed to contain pricing but implementation only adds capabilities. Empty pricing object {} not detected as failed.','Update getFailedFields to check for empty pricing object','apps/server/src/services/ai/supplyExtractionService.ts:604',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:30:20.027915','2026-04-20 10:44:21.343706');
INSERT INTO nitpick_findings VALUES(26,'NP-26',13,1070,'implemented-to-accepted','test_coverage','warning','Unit test failure: should return false when required field is missing','validateMapping returns true for empty string title - falsy values pass required check','Update validateMapping to reject empty strings for required fields','apps/server/src/services/ai/mappers/supplyToL2Mapper.ts:745',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:30:20.028325','2026-04-20 10:44:21.343707');
INSERT INTO nitpick_findings VALUES(27,'NP-27',13,1070,'implemented-to-accepted','code_quality','warning','Lint error: unused imports in supplyQualityAssessor.ts','Capability and PricingInfo imported but never used','Remove unused imports','apps/server/src/services/ai/assessors/supplyQualityAssessor.ts:13',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:30:20.028763','2026-04-20 10:12:08.730432');
INSERT INTO nitpick_findings VALUES(28,'NP-A003a-R2-1',6,1071,'implemented-to-accepted','test_coverage','critical','POST /api/v1/users/avatar endpoint is completely untested in users.test.ts. The test file has 7 tests covering GET/PUT/DELETE /me but zero tests for POST /avatar.','users.test.ts has describe blocks for GET /me (2 tests), PUT /me (1 test), DELETE /me (4 tests). No describe block or test for POST /avatar. upload.test.ts tests /upload/avatar but not /users/avatar.','Add tests for POST /api/v1/users/avatar covering: file upload success, avatarUrl bypass path, file type rejection, file size limit exceeded, and no-file/no-url error.','apps/server/src/routes/__tests__/users.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042418');
INSERT INTO nitpick_findings VALUES(29,'NP-A003a-R2-2',6,1071,'implemented-to-accepted','verification','critical','PUT /api/v1/users/me lacks input validation for profile fields. No Zod schema, no length limits, no HTML sanitization for name/bio/website.','users.ts line 65: const { name, displayName, bio, website, location } = req.body; - directly destructures req.body without validation middleware.','Add validation middleware or Zod schema for profile update fields: max string lengths, URL format for website, sanitize HTML/script content in bio/name.','apps/server/src/routes/users.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042422');
INSERT INTO nitpick_findings VALUES(30,'NP-A003a-R2-3',6,1071,'implemented-to-accepted','test_coverage','critical','File type and size rejection not tested for avatar upload. Neither users.test.ts nor upload.test.ts test multer fileFilter rejection or fileSize limit scenarios.','upload.test.ts: 5 tests covering upload success, no file, auth failure for /avatar and success/no file for /image. Zero tests for invalid MIME type or files > 5MB.','Add tests for multer fileFilter rejection and file size limit exceeded for both /users/avatar and /upload/avatar endpoints.','apps/server/src/routes/__tests__/upload.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042423');
INSERT INTO nitpick_findings VALUES(31,'NP-A003a-R2-4',6,1071,'implemented-to-accepted','code_quality','critical','Old avatar files not cleaned up on new upload or account deletion. storageService.deleteFile() exists but is never called from userService.','storageService.ts:366 exports deleteFile() but zero callers in userService. userService.ts updateAvatar() and deleteUser() do not call storageService.deleteFile().','Delete old avatar file before updating with new one in updateAvatar(). Clean up avatar storage when user account is deleted in deleteUser().','apps/server/src/services/userService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042424');
INSERT INTO nitpick_findings VALUES(32,'NP-A003a-R2-5',6,1071,'implemented-to-accepted','verification','critical','Avatar URL bypass (req.body.avatarUrl) accepts arbitrary URLs without validation. Could accept javascript:, file:, or any arbitrary URL scheme.','users.ts line 111-113: } else { avatarUrl = req.body.avatarUrl; } - directly uses req.body.avatarUrl without URL parsing, scheme whitelist, or sanitization.','Validate avatarUrl with URL parsing, whitelist http/https schemes, sanitize input, optionally verify the URL points to a valid image.','apps/server/src/routes/users.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042426');
INSERT INTO nitpick_findings VALUES(33,'NP-A003a-R2-6',6,1071,'implemented-to-accepted','runtime_behavior','critical','userService.ts uses Prisma model fields not in schema.prisma. TypeScript compilation fails with 19 errors for missing fields: displayName, bio, website, location, emailVerified, phoneVerified, privacySettings.','tsc --noEmit produces TS2339 errors for 7 missing fields. schema.prisma User model only has: id, email, passwordHash, name, avatarUrl, phone, status, createdAt, updatedAt.','Either add missing fields to User model in schema.prisma and migrate, or remove non-existent field references from userService.ts.','apps/server/src/services/userService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20T17:34:01.467084','2026-04-20 10:33:19.042427');
INSERT INTO nitpick_findings VALUES(34,'NP-34',6,4,'implemented-to-accepted','code_quality','critical','userService.ts uses Prisma model fields that don''t exist in schema.prisma. Fields like emailVerified, displayName, bio, website, location, phoneVerified, privacySettings are missing from the User model.','TypeScript compilation errors in userService.ts lines 65-104: Property ''emailVerified''/''displayName''/''bio''/''website''/''location''/''phoneVerified''/''privacySettings'' does not exist on type ''{ id: string; email: string; name: string | null; status: UserStatus; passwordHash: string; avatarUrl: string | null; phone: string | null; createdAt: Date; updatedAt: Date; }''','Add missing fields to User model in prisma/schema.prisma: emailVerified (Boolean), displayName (String?), bio (String?), website (String?), location (String?), phoneVerified (Boolean), privacySettings (Json). Then run prisma generate.','apps/server/src/services/userService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.822971','2026-04-20 10:33:19.042428');
INSERT INTO nitpick_findings VALUES(35,'NP-35',6,4,'implemented-to-accepted','verification','critical','Avatar URL bypass (req.body.avatarUrl) accepts arbitrary URLs without validation. Could accept javascript: or data: URLs leading to XSS.','apps/server/src/routes/users.ts:113: avatarUrl = req.body.avatarUrl; No validation of URL format or scheme.','Add URL validation: only allow https:// URLs from allowed domains, or remove the avatarUrl bypass entirely and require file upload only.','apps/server/src/routes/users.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.823829','2026-04-20 10:33:19.042429');
INSERT INTO nitpick_findings VALUES(36,'NP-36',6,4,'implemented-to-accepted','code_quality','critical','Old avatar files not cleaned up on new upload or account deletion. storageService.deleteFile() exists but is never called when avatar is updated or user is deleted.','apps/server/src/services/userService.ts:147-149: updateAvatar() just calls updateUser() without cleanup. deleteUser() deletes user records but not avatar files.','Before updating avatar, fetch old avatarUrl and call storageService.deleteFile(). Before deleting user, clean up avatar file.','apps/server/src/services/userService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.824381','2026-04-20 10:33:19.042430');
INSERT INTO nitpick_findings VALUES(37,'NP-37',6,4,'implemented-to-accepted','verification','critical','PUT /api/v1/users/me lacks input validation for profile fields. No Zod schema, no length limits, no type checking.','apps/server/src/routes/users.ts:65: const { name, displayName, bio, website, location } = req.body; No validation before passing to userService.updateUser().','Add Zod schema validation: name (1-100 chars), displayName (0-50 chars), bio (0-500 chars), website (valid URL), location (0-200 chars).','apps/server/src/routes/users.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.824890','2026-04-20 10:33:19.042431');
INSERT INTO nitpick_findings VALUES(38,'NP-38',6,4,'implemented-to-accepted','test_coverage','critical','POST /api/v1/users/avatar endpoint has no tests in users.test.ts. The test file only covers GET /me, PUT /me, and DELETE /me routes.','apps/server/src/routes/__tests__/users.test.ts has no describe block for ''POST /api/v1/users/avatar''. Only 7 tests exist, covering GET/PUT/DELETE /me.','Add test cases for avatar upload: successful upload, no file provided, invalid file type, file too large, avatarUrl bypass.','apps/server/src/routes/__tests__/users.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.825335','2026-04-20 10:33:19.042432');
INSERT INTO nitpick_findings VALUES(39,'NP-39',6,4,'implemented-to-accepted','test_coverage','critical','File type and size rejection not tested for avatar upload. Neither users.test.ts nor upload.test.ts tests multer fileFilter rejection.','upload.test.ts only tests successful uploads. No test for .exe or .pdf file rejection, no test for 5MB+ file rejection.','Add test cases: upload .exe file (should return 400), upload .pdf file (should return 400), upload 6MB file (should return 413).','apps/server/src/routes/__tests__/upload.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:43:32.825770','2026-04-20 10:33:19.042433');
INSERT INTO nitpick_findings VALUES(40,'NP-40',5,3,'implemented-to-accepted','consistency','critical','AC与Issue标题完全不匹配：Issue标题为"用户基础资料管理"，但5个AC全部是关于匹配/聊天功能（AS-004-AC-2批量读取候选、AS-004-AC-3计算匹配度、AS-005-AC-1过滤候选、AS-005-AC-2发起对话请求、AS-005-AC-3多候选独立对话）。这说明Issue拆分或AC映射有严重问题。','Issue title: 用户基础资料管理; ACs: AS-004-AC-2, AS-004-AC-3, AS-005-AC-1, AS-005-AC-2, AS-005-AC-3','重新审核Issue的范围定义。如果"用户资料管理"和"匹配聊天"是不同功能，应该拆分为独立Issue。检查是否有Issue承担了过多不相关的AC。','apps/server/src/services/userService.ts, apps/server/src/routes/users.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 09:43:37.130571',NULL);
INSERT INTO nitpick_findings VALUES(41,'NP-41',5,3,'implemented-to-accepted','code_quality','critical','userPrivacy.ts中的路由永远不会被调用：路由定义在 /api/v1/users/me/privacy 和 /api/v1/users/me/security，但这些路由在 apps/server/src/routes/v1/index.ts 中从未被mount。grep搜索"userPrivacy"在server/src下无任何结果。','grep -r "userPrivacy" apps/server/src/ → No matches found; v1/index.ts中只mount了userRoutes, 无userPrivacy相关导入','在 apps/server/src/routes/v1/index.ts 中添加: import userPrivacyRoutes from "../userPrivacy"; router.use("/users", userPrivacyRoutes); 或删除未使用的userPrivacy.ts文件。','apps/server/src/routes/userPrivacy.ts, apps/server/src/routes/v1/index.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 09:43:37.131291',NULL);
INSERT INTO nitpick_findings VALUES(42,'NP-42',5,3,'implemented-to-accepted','code_quality','critical','隐私设置存在两套重复实现，字段名完全不同且互不兼容：(1) userService.ts使用 profileVisibility/onlineStatusVisible/phoneVisible/emailVisible/allowSearchByPhone/allowSearchByEmail; (2) userPrivacy.ts使用 profileVisibility/onlineStatusVisibility/phoneVisibility/emailVisibility/allowSearchByPhone/allowSearchByEmail/showLastSeen。mobile端PrivacySettingsScreen.tsx使用userService的字段格式，但userPrivacy.ts是移动端API的预期格式。','userService.ts PrivacySettings: onlineStatusVisible (boolean); userPrivacy.ts privacySettingsSchema: onlineStatusVisibility (enum: everyone/friends/nobody); Mobile PrivacySettingsScreen uses onlineStatusVisible (boolean)','统一隐私设置的数据模型。选择一个作为标准并在所有地方使用。建议使用userPrivacy.ts的更完整schema，并更新userService.ts和mobile端。','apps/server/src/services/userService.ts, apps/server/src/routes/userPrivacy.ts, apps/server/src/types/privacy.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 09:43:37.131776',NULL);
INSERT INTO nitpick_findings VALUES(43,'NP-43',5,3,'implemented-to-accepted','verification','warning','移动端隐私设置和安全设置界面未连接API：PrivacySettingsScreen.tsx第58行和SecuritySettingsScreen.tsx第67/88/112行均为 "TODO: Implement API call"，仅显示alert提示"成功"但未实际调用后端API。',replace('PrivacySettingsScreen.tsx:58: // TODO: Implement API call to save privacy settings\nSecuritySettingsScreen.tsx:67,88,112: // TODO: Implement API call','\n',char(10)),'实现实际的API调用。隐私设置应调用 PUT /api/v1/users/privacy，安全设置应调用 POST /api/v1/users/password, POST /api/v1/users/phone, POST /api/v1/users/email。注意：这些路由在users.ts中定义了，但userPrivacy.ts中的路由（/me/privacy等）未挂载。','apps/mobile/src/screens/settings/PrivacySettingsScreen.tsx, apps/mobile/src/screens/settings/SecuritySettingsScreen.tsx',NULL,'open',NULL,NULL,NULL,'2026-04-20 09:43:37.132211',NULL);
INSERT INTO nitpick_findings VALUES(44,'NP-44',5,3,'implemented-to-accepted','verification','warning','移动端API客户端层文件缺失：子Issue A003b实现了 apps/mobile/src/api/user/index.ts 和 apps/mobile/src/api/user/types.ts，但这些文件在master上不存在。分支issue/ISSUE-A003b有这些文件，但未合并到master。','ls apps/mobile/src/api/user/index.ts → File does not exist; git show issue/ISSUE-A003b:apps/mobile/src/api/user/index.ts → 有内容','将A003b分支的mobile API客户端文件合并到master，或从issue/ISSUE-A003b分支 cherry-pick 相关提交。','apps/mobile/src/api/user/index.ts, apps/mobile/src/api/user/types.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 09:43:37.132612',NULL);
INSERT INTO nitpick_findings VALUES(45,'NP-45',3,1,'implemented-to-accepted','code_quality','critical','JWT secret uses insecure fallback value ''your-secret-key'' in production path','apps/server/src/services/auth/jwt.ts:11: const JWT_SECRET = process.env.JWT_SECRET || ''your-secret-key''; // Falls back to known value in production','Remove the fallback - throw an error if JWT_SECRET is not set, similar to apps/server/src/middleware/auth.ts:26-27 which correctly requires JWT_SECRET','apps/server/src/services/auth/jwt.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.813575','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(46,'NP-46',3,1,'implemented-to-accepted','code_quality','critical','Hardcoded verification code ''123456'' bypasses authentication in production path','apps/server/src/services/authService.ts:215: if (verificationCode && verificationCode !== ''123456'') // Line 287 also has same hardcoded value','Remove hardcoded verification code. Implement proper verification code generation and storage (e.g., Redis with TTL, or database with expiry)','apps/server/src/services/authService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.814324','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(47,'NP-47',3,1,'implemented-to-accepted','code_quality','critical','No rate limiting on forgot-password endpoint enables enumeration attacks','apps/server/src/routes/auth.ts:243-267 - forgot-password route has NO rateLimiter middleware, while loginLimiter and registerLimiter are applied to other auth endpoints','Add rate limiter to /forgot-password endpoint similar to loginLimiter (5 attempts per 15 minutes)','apps/server/src/routes/auth.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.814835','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(48,'NP-48',3,1,'implemented-to-accepted','code_quality','critical','req.token used in auth routes but not defined in AuthenticatedRequest type','apps/server/src/routes/auth.ts:178: if (req.token) { await blacklistService.blacklistToken(req.token); } but AuthenticatedRequest interface at apps/server/src/middleware/auth.ts:9-15 does not define ''token'' property','Extend Request type to include req.token or use extractToken() from jwt.ts module to get the token for blacklisting','apps/server/src/middleware/auth.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.815325','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(49,'NP-49',3,1,'implemented-to-accepted','test_coverage','critical','Integration tests excluded from default test run (testPathIgnorePatterns=''integration'')','apps/server/jest.config.ts - testPathIgnorePatterns includes ''integration'' by default. Running ''pnpm test'' skips integration tests','Include integration tests in default run or ensure CI/CD runs them separately. Consider renaming integration tests to __integration__ or similar to avoid Jest''s default ignore patterns','apps/server/jest.config.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:45:27.815729','2026-04-20 09:49:02.239891');
INSERT INTO nitpick_findings VALUES(50,'NP-50',3,1,'implemented-to-accepted','code_quality','warning','Mobile app has 301 lint errors and 31 warnings preventing CI pass','npm run lint output: ''✖ 332 problems (301 errors, 31 warnings)'' including unused variables (isFatal, modelName) and explicit any types','Fix lint errors before merging. Common issues: @typescript-eslint/no-unused-vars and @typescript-eslint/no-explicit-any','apps/mobile/src/utils/onDeviceML.ts, apps/mobile/src/utils/sentry.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.816146','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(51,'NP-51',3,1,'implemented-to-accepted','runtime_behavior','warning','OAuth exchange codes stored in in-memory Map, lost on server restart','apps/server/src/services/oauthService.ts:107: const exchangeCodes = new Map<string, IOAuthExchangeCode>(); - This in-memory storage means users with pending OAuth flows will fail after server restart','Store exchange codes in Redis or database with TTL for persistence across restarts','apps/server/src/services/oauthService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 09:45:27.816523','2026-04-20 18:12:38.024825');
INSERT INTO nitpick_findings VALUES(52,'NP-52',3,1,'implemented-to-accepted','code_quality','info','logout-all endpoint has unimplemented TODO for revoking all user tokens','apps/server/src/routes/auth.ts:221: // TODO: Implement revoke all user tokens from database','Implement the token revocation using the refresh token storage (revokeAllUserRefreshTokens function exists in refreshToken.ts)','apps/server/src/routes/auth.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:45:27.816971','2026-04-20 09:49:02.240202');
INSERT INTO nitpick_findings VALUES(53,'NP-53',7,5,'implemented-to-accepted','test_coverage','critical','ValidationError instanceof check fails - 8 validation tests fail due to prototype chain issue',replace('Test output: expect(jest.fn()).toHaveBeenCalledWith(...expected)\nExpected: Any<ValidationError>\nReceived: [Error: Validation failed for body...]\n\ninstanceof checks:\n  instanceof ValidationError: false\n  instanceof AppError: true\n  constructor: AppError','\n',char(10)),'The Object.setPrototypeOf(this, ValidationError.prototype) call in ValidationError constructor does not properly set the prototype chain in transpiled code. Fix by ensuring proper class inheritance setup or use a different approach.','apps/server/src/errors/AppError.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.107123','2026-04-20 10:16:17.182182');
INSERT INTO nitpick_findings VALUES(54,'NP-54',7,5,'implemented-to-accepted','code_quality','critical','XSS regex detection has global flag state bug - detection fails on repeated calls',replace('XSS_PATTERNS defined with /gi flag, containsXSS() calls pattern.test() without resetting lastIndex.\n\nTest: pattern.test(''<script>alert(1)</script>'')\n  Call 1: true\n  Call 2: false (lastIndex not reset)','\n',char(10)),'Use RegExp.prototype[Symbol.match]() instead of test(), or clone patterns with new RegExp(pattern.source, pattern.flags.replace(''g'', '''')), or use pattern.source to create fresh RegExp for each check.','apps/server/src/middleware/security.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.107853','2026-04-20 10:16:17.182189');
INSERT INTO nitpick_findings VALUES(55,'NP-55',7,5,'implemented-to-accepted','verification','critical','SQL injection detection patterns have multiple bypasses',replace('Test results:\n  Backtick injection: false (not detected)\n  Double dash comment: false (not detected)\n  Subquery: false (not detected)\n  Prisma injection: false (not detected)','\n',char(10)),'Add patterns for backtick-quoted injection, double-dash comments (--), subqueries, and Prisma ORM operators. Consider using parameterized queries as primary defense instead of pattern matching.','apps/server/src/middleware/security.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.108365','2026-04-20 10:16:17.182191');
INSERT INTO nitpick_findings VALUES(56,'NP-56',7,5,'implemented-to-accepted','verification','critical','sanitizeString() function has multiple XSS bypass vulnerabilities',replace('Bypass tests:\n  Mixed case: JaVaScRiPt: -> alert(1)\n  Unicode: unicode chars -> alert(1)\n  Tab/newline: java\tscript: -> java\tscript:alert(1)\n  Nested: javascrjavascriptipt: -> javascrjavascriptipt:alert(1)\n  Event space: onclick =alert(1) -> onclick =alert(1)\n  Img onerror: onerror=alert(1) (onerror preserved!)\n  SVG onload: onload=alert(1) (onload preserved!)','\n',char(10)),'sanitizeString only removes < and > but leaves event handlers intact. Need to: 1) Use DOMPurify or similar, 2) Remove all event handler patterns, 3) Normalize unicode/whitespace','apps/server/src/middleware/validation.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.108808','2026-04-20 10:16:17.182193');
INSERT INTO nitpick_findings VALUES(57,'NP-57',7,5,'implemented-to-accepted','test_coverage','critical','l2Validation test suite fails to run - L2FieldType import returns undefined',replace('TypeError: Cannot read properties of undefined (reading ''TEXT'')\n  at src/utils/__tests__/l2Validation.test.ts:23\n\n@bridgeai/shared/dist/index.d.ts contains 0 references to L2FieldType','\n',char(10)),'Verify @bridgeai/shared package is properly built and linked. Check exports chain: schemas/l2/types.ts -> schemas/l2/index.ts -> types.ts -> index.ts. The L2FieldType enum exists in source but is not being exported in the built declaration file.','apps/server/src/utils/__tests__/l2Validation.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.109239','2026-04-20 10:16:17.182195');
INSERT INTO nitpick_findings VALUES(58,'NP-58',7,5,'implemented-to-accepted','test_coverage','critical','Image security test for sensitive content detection fails - returns 0 violations',replace('expect(result.violations.length).toBeGreaterThan(0)\nExpected: > 0\nReceived: 0','\n',char(10)),'Verify the AI image analysis service is properly mocked in tests, or implement the actual content detection integration.','apps/server/src/services/security/__tests__/imageSecurity.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.109686','2026-04-20 10:16:17.182197');
INSERT INTO nitpick_findings VALUES(59,'NP-59',7,5,'implemented-to-accepted','code_quality','warning','17 routes handle POST/PUT/PATCH requests without input validation','Routes without validate() middleware: auth.ts, users.ts, upload.ts, agents.ts, agentProfile.ts, agentLocationRoutes.ts, merchants.ts, reviews.ts, offers.ts, consumerDemand.ts, disclosure.ts, notificationPreferences.ts, notifications.ts, geoFenceRoutes.ts, oauth.ts, job/*, dating/*','Add validation middleware to all routes that accept user input. Create corresponding Zod schemas in src/schemas/ for each route.','apps/server/src/routes/',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:48:23.110075','2026-04-20 10:16:17.182198');
INSERT INTO nitpick_findings VALUES(60,'NP-60',7,5,'implemented-to-accepted','test_coverage','warning','Mobile validation uses simple regex instead of shared Zod schemas',replace('Mobile validation.ts uses simple regex:\n  emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/\n  isValidPassword = (p) => p.length >= 6\n\nServer uses Zod with stricter rules (max 255 chars, toLowerCase, min 8 with upper/lower/digit)','\n',char(10)),'Use @bridgeai/shared Zod schemas in mobile app for consistent validation across platforms.','apps/mobile/src/utils/validation.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:48:23.110472','2026-04-20 09:50:12.227787');
INSERT INTO nitpick_findings VALUES(61,'NP-61',7,5,'implemented-to-accepted','code_quality','warning','Multiple lint errors in schema and validation files',replace('Lint errors found:\n  - @typescript-eslint/no-explicit-any (multiple warnings in security.ts)\n  - @typescript-eslint/no-unused-vars: CreditLevel, logger, ExemptionRule, EmailMessage, EncryptedData, getUserCreditScore, notificationService\n  - import/order issues in multiple schema files','\n',char(10)),'Clean up unused imports and fix import ordering. The unused vars suggest incomplete implementation or refactoring leftovers.','apps/server/src/schemas/',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:48:23.110911','2026-04-20 09:50:12.228155');
INSERT INTO nitpick_findings VALUES(62,'NP-62',4,2,'implemented-to-accepted','code_quality','critical','handoffAuth.test.ts 存在错误的 mock 路径导致测试无法运行','jest.mock(''../../src/services/rbacService'') 在文件 src/middleware/__tests__/handoffAuth.test.ts:21 报错：Cannot find module ''../../src/services/rbacService''。正确路径应为 ''../../services/rbacService''。同样的问题也存在于 rbac.test.ts。','将 jest.mock(''../../src/services/rbacService'') 改为 jest.mock(''../../services/rbacService'')，并修正 handoffAuth.ts 的导入路径从 ''../../src/middleware/handoffAuth'' 改为 ''../handoffAuth''。','apps/server/src/middleware/__tests__/handoffAuth.test.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:49:05.176889','2026-04-20 09:52:22.874308');
INSERT INTO nitpick_findings VALUES(63,'NP-63',4,2,'implemented-to-accepted','verification','critical','用户注册端点缺失 - authService.registerUser 无路由可达','旧版 routes/auth.ts 包含 POST /api/v1/auth/register 调用 registerUser()。新版 routes/v1/auth.ts 已移除此端点，导致新用户无法注册。全局搜索未发现任何路由调用 registerUser()。','在 routes/v1/auth.ts 中添加 POST /register 端点调用 authService.registerUser()，或确认注册逻辑已迁移到其他位置。','apps/server/src/routes/v1/auth.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:49:05.177703','2026-04-20 10:22:50.946044');
INSERT INTO nitpick_findings VALUES(64,'NP-64',4,2,'implemented-to-accepted','verification','critical','密码重置端点缺失 - requestPasswordReset 和 resetPassword 无路由','旧版 routes/auth.ts 包含 POST /api/v1/auth/forgot-password 和 POST /reset-password。新版 routes/v1/auth.ts 已移除这两个端点。authService 中对应的函数存在但无路由可达。','在 routes/v1/auth.ts 中添加 POST /forgot-password 和 POST /reset-password 端点。','apps/server/src/routes/v1/auth.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:49:05.178235','2026-04-20 10:22:50.946047');
INSERT INTO nitpick_findings VALUES(65,'NP-65',4,2,'implemented-to-accepted','runtime_behavior','critical','登录锁定机制使用内存存储，多实例部署时无法共享状态','authService.ts:35 使用 new Map<string, { count: number; lockedUntil: number }>() 进行内存锁定追踪。注释已标注 NOTE: DB fields for lockout not in current schema。分布式部署下各实例锁定状态不共享，攻击者可绕过锁定。','将登录锁定状态持久化到数据库（prisma），或使用 Redis 等共享存储。在 schema 中添加 LoginAttempt 表记录 userId、attemptCount、lockedUntil。','apps/server/src/services/authService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:49:05.178682','2026-04-20 10:22:50.946049');
INSERT INTO nitpick_findings VALUES(66,'NP-66',4,2,'implemented-to-accepted','ac_quality','critical','验收标准与实现内容严重不匹配','Issue 标题为 ''JWT认证与API安全''，但 AC 列表包含 AS-002-AC-3(确认后存储并触发实时匹配)、AS-003-AC-1/2/3(供给能力理解/三层字段提取/激活供给)、AS-004-AC-1(创建结构化记录)。这些 AC 描述的是供给-需求匹配功能，与 JWT 认证无关。','重新评估 ISSUE-A002 的范围：为 JWT 认证创建新的 AC，或将当前 AC 重新分配给正确的 Issue。','ISSUE-A002 数据库记录',NULL,'resolved','become_issue',NULL,NULL,'2026-04-20 09:49:05.179108','2026-04-20 10:22:50.946050');
INSERT INTO nitpick_findings VALUES(67,'NP-67',4,2,'implemented-to-accepted','test_coverage','warning','auth/routes.test.ts 缺少成功登录的测试用例','routes.test.ts 测试了 email missing(400)、user not found(401)、invalid password(401)，但缺少对 successful login 返回 200 + tokens 的测试验证。','添加测试用例：用正确密码 mock 登录，验证返回 200 状态码及 tokens.accessToken、tokens.refreshToken 字段存在且非空。','apps/server/src/__tests__/auth/routes.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:49:05.179561','2026-04-20 10:22:50.946051');
INSERT INTO nitpick_findings VALUES(68,'NP-68',4,2,'implemented-to-accepted','test_coverage','warning','authService.test.ts 缺少 loginUser 函数测试','authService.test.ts 仅测试了 validatePasswordStrength、generateAccessToken、generateRefreshToken、verifyToken、hashPassword、comparePassword。没有测试 loginUser 本身（包括锁定逻辑）。','添加 loginUser 的单元测试，覆盖：成功登录返回 tokens、失败密码递增计数、超过5次触发锁定、验证码登录流程。','apps/server/src/services/auth/__tests__/authService.test.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 09:49:05.179979','2026-04-20 10:22:50.946052');
INSERT INTO nitpick_findings VALUES(69,'NP-69',10,15,'implemented-to-accepted','ac_quality','critical','AC与实现严重不匹配：所有4个AC均未在代码中实现。Issue自称''核心框架''，实际实现了NLP提取→L2映射→验证流程，但AC描述的功能来自其他父Issue（AS-VS-002、AS-DATE-001），与核心框架实现无关。','AS-VS-002-AC-3(处理隐私脱敏并上传): 代码中无隐私脱敏逻辑，确认端点只有TODO注释。AS-DATE-001-AC-1(应用地域和属性过滤): batch端点无任何过滤逻辑。AS-DATE-001-AC-2(批量评估匹配度): batch端点只提取demand，不评估匹配度。AS-DATE-001-AC-3(精选Top候选): batch端点无排序或Top选择逻辑。','重新评估：要么更新AC以匹配核心框架实际提供的能力（实体提取、意图分类、L2映射、验证），要么将当前实现作为依赖库，明确哪些AC在下游实现。','apps/server/src/services/ai/demandExtractionService.ts',NULL,'adopted','become_ac',NULL,NULL,'2026-04-20 09:58:07.382733','2026-04-20 10:00:12.166238');
INSERT INTO nitpick_findings VALUES(70,'NP-70',10,15,'implemented-to-accepted','code_quality','critical','AI002a相关文件中存在13个lint错误（3个可自动修复）。extraction.ts: 未使用的import(WebSocketServer/L2Schema/MappingResult/ValidationReport/extractL2FromL3/ExtractionResult)，未使用变量(feedback/corrections)。extractionValidator.ts: 未使用的import(L2ValidationError/L2ValidationResult)，import顺序问题。','pnpm exec eslint apps/server/src/services/ai/demandExtractionService.ts ... 输出: 13 errors, 31 warnings','使用 eslint --fix 自动修复 import/order 规则，其余手动删除未使用import和变量。','apps/server/src/routes/ai/extraction.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:58:07.383525','2026-04-20 10:00:12.166849');
INSERT INTO nitpick_findings VALUES(71,'NP-71',10,15,'implemented-to-accepted','verification','warning','无worktree：.issuetree/worktrees/ISSUE-AI002a/目录为空，DB中worktree_path为null。代码实现在master分支而非独立worktree，nitpick在主分支执行。','ls -la .issuetree/worktrees/ISSUE-AI002a/ 显示目录为空。git show master:... 确认代码在主分支。状态历史显示从accepted进入nitpicking。','建议确认issue是否应使用worktree流程，当前实现已直接在主分支，后续应建立规范流程。',NULL,NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 09:58:07.384047','2026-04-20 10:00:12.167255');
INSERT INTO nitpick_findings VALUES(72,'NP-72',11,17,'implemented-to-accepted','test_coverage','critical','AgentDate/AgentJob/AgentAd canHandle 场景检测全部失败 - 关键词匹配阈值过高','测试 ''想找对象，希望对方25-30岁'' (1个关键词匹配: 找对象), 18个总关键词，阈值公式: matchCount/5.4 > 0.3 才通过。测试期望 canHandle=true，但实际返回 false。同样测试 ''招聘Java开发工程师，5年经验'' 和 ''买iPhone 15，预算8000'' 也失败。sceneDetector.test.ts:27,33,39 均返回 ''unknown'' 而非预期场景。','方案1: 降低 canHandle 置信度阈值从 0.3 降到 0.15，使 1-2 个关键词匹配即可通过。方案2: 在 detectionKeywords 中为每个场景增加 2-3 个高权重核心关键词（如 AgentDate 增加 ''相亲''、''约会''，AgentJob 增加 ''工作''、''招聘''，AgentAd 增加 ''买''、''购买''），降低阈值到 0.15。','apps/server/src/services/ai/extractors/baseExtractor.ts:64, agentDateExtractor.ts:17-22',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.262494','2026-04-20 10:31:09.662789');
INSERT INTO nitpick_findings VALUES(73,'NP-73',11,17,'implemented-to-accepted','code_quality','critical','VisionShareExtractor 位置信息提取失败 - 无法解析中文地址和室内外偏好','测试 ''在上海浦东新区拍外景人像'' 期望 location.city=''上海''，实际返回 undefined。测试 ''在摄影棚内拍产品照'' 期望 indoor=true，实际返回 undefined。VisionShareExtractor 无 city/indoor 提取逻辑（sceneExtractors.test.ts:44,63 失败）。','实现 extractLocation 方法：1) 添加 city 提取正则，匹配 ''XX市''/''XX区''/''XX县'' 等行政区划后缀；2) 添加 indoor/outdoor 关键词检测（''摄影棚''/''室内'' → indoor=true, ''外景''/''户外'' → indoor=false）。','apps/server/src/services/ai/extractors/visionShareExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.263458','2026-04-20 10:31:09.662797');
INSERT INTO nitpick_findings VALUES(74,'NP-74',11,17,'implemented-to-accepted','test_coverage','critical','VisionShareExtractor 验证逻辑失效 - 不完整数据被标记为 valid=true','测试 ''想拍写真''（缺少摄影类型）期望 validation.valid=false，但实际返回 true。同时期望 missingFields 包含 ''photographyType'' 也失败(sceneExtractors.test.ts:57)。','检查 VisionShareExtractor.validate() 实现，确保 requiredFields 中 photographyType 为必填，缺失时返回 valid=false 和 missingFields 列表。','apps/server/src/services/ai/extractors/visionShareExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.264106','2026-04-20 10:31:09.662798');
INSERT INTO nitpick_findings VALUES(75,'NP-75',11,17,'implemented-to-accepted','test_coverage','critical','AgentJobExtractor 薪资提取未实现','测试 ''期望薪资20K-30K'' 期望 salaryExpectation.min=20000, max=30000, period=''monthly''，实际返回 undefined(sceneExtractors.test.ts:162)。extractSalaryExpectation 方法存在但未正确实现。','实现 extractSalaryExpectation 方法，添加正则匹配 ''XXK-XXK''、''XXk-XXk''、''XX元/xx''、''XX元/月'' 等格式，转换为 min/max/period 结构化数据。','apps/server/src/services/ai/extractors/agentJobExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.264609','2026-04-20 10:31:09.662799');
INSERT INTO nitpick_findings VALUES(76,'NP-76',11,17,'implemented-to-accepted','code_quality','warning','AgentJobExtractor 福利提取精度不足 - 返回 ''年假'' 而非 ''带薪年假''','测试 ''提供五险一金、带薪年假、双休'' 期望 benefits 包含 ''年假''，但实际提取为 ''年假'' 而非 ''带薪年假''，断言失败(sceneExtractors.test.ts:185)。','修复 extractBenefits 中对 ''带薪年假'' 的整体匹配，应优先匹配完整短语再考虑部分匹配，或在 benefits 列表中对 ''年假'' 做上下文判断。','apps/server/src/services/ai/extractors/agentJobExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.265087','2026-04-20 10:31:09.662801');
INSERT INTO nitpick_findings VALUES(77,'NP-77',11,17,'implemented-to-accepted','test_coverage','warning','AgentAdExtractor 紧急程度判断逻辑反转','测试 ''不急，可以慢慢选'' 期望 urgency=''low''，实际返回 ''high'' (sceneExtractors.test.ts:238)。''不急''/''慢慢'' 等负面紧迫性关键词未被正确处理。','在 AgentAdExtractor.extractUrgency() 中添加负面紧迫性关键词检测：''不急''/''慢慢''/''不着急''/''以后再说'' → urgency=''low''，优先级高于正面紧迫性关键词。','apps/server/src/services/ai/extractors/agentAdExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.265565','2026-04-20 10:31:09.662802');
INSERT INTO nitpick_findings VALUES(78,'NP-78',11,17,'implemented-to-accepted','test_coverage','warning','澄清问题生成返回通用回退文本而非具体问题','AgentDate 测试期望 ''伴侣'' 相关问题，实际返回通用文本 ''请提供关于 "partnerCriteria" 的更多信息''(sceneExtractors.test.ts:118)。AgentAd 测试期望 ''产品'' 相关问题，实际返回 ''请问您想购买什么商品？'' 已正确实现。VisionShare ''摄影类型'' 期望返回 ''摄影类型'' 相关问题，实际返回 ''请问您需要什么类型的摄影服务？'' 也部分正确。','AgentDateExtractor.getClarificationQuestion() 中添加 ''partnerCriteria'' → ''请问您对理想伴侣有什么要求？'' 映射，使其与 ''partnerPreferences'' 区分或合并。','apps/server/src/services/ai/extractors/agentDateExtractor.ts:319-331',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.265991','2026-04-20 10:31:09.662803');
INSERT INTO nitpick_findings VALUES(79,'NP-79',11,17,'implemented-to-accepted','code_quality','warning','Extractor 代码中大量未使用的函数参数','AgentDateExtractor: 1个未使用参数(context) + 1个未使用参数(entities)；AgentJobExtractor: 1个未使用(context) + 4个未使用(entities)；AgentAdExtractor: 1个未使用(context) + 2个未使用(entities)；VisionShareExtractor: 1个未使用(context) + 2个未使用(entities)。ESLint 报 11 个 @typescript-eslint/no-unused-vars 错误。','将所有未使用的参数前缀改为 ''_''（如 ''_context''、''_entities''），符合项目 eslint 规则（允许 /^_/u 匹配模式）。','apps/server/src/services/ai/extractors/agentDateExtractor.ts, agentJobExtractor.ts, agentAdExtractor.ts, visionShareExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:00:13.266406','2026-04-20 10:31:09.662804');
INSERT INTO nitpick_findings VALUES(80,'NP-80',13,22,'implemented-to-accepted','code_quality','critical','Supply extraction API routes exist but are not registered in the application','routes/ai/supply.ts exists (407 lines) but is not imported in routes/ai/index.ts (only mounts llmRoutes and visionRoutes), not in aiRoute.ts, and not in routes/index.ts. The entire route file is dead code.','Add: router.use("/supply", supplyRoutes); to routes/ai/index.ts. Create and import supplyRoutes from "./supply" in routes/ai/index.ts.','apps/server/src/routes/ai/supply.ts, apps/server/src/routes/ai/index.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:07:56.426304','2026-04-20 10:44:21.343709');
INSERT INTO nitpick_findings VALUES(81,'NP-81',13,22,'implemented-to-accepted','code_quality','critical','SupplyExtractionService not exported from AI services barrel file','services/ai/index.ts exports DemandExtractionService, LLMRouter, LLMService etc. but has no export for SupplyExtractionService. The routes/ai/supply.ts imports it from the direct path rather than from the barrel.','Add SupplyExtractionService export to services/ai/index.ts alongside other AI service exports.','apps/server/src/services/ai/index.ts',NULL,'duplicate',NULL,NULL,24,'2026-04-20 10:07:56.427150',NULL);
INSERT INTO nitpick_findings VALUES(82,'NP-82',13,22,'implemented-to-accepted','test_coverage','critical','Test suite fails to run: Cannot find module ../../utils/logger from supplyQualityAssessor.ts','Jest output: Cannot find module ../../utils/logger from src/services/ai/assessors/supplyQualityAssessor.ts. Test Suites: 1 failed, 0 passed.','Fix the import path in supplyQualityAssessor.ts. The correct relative path from src/services/ai/assessors/ to src/utils/logger is ../../../utils/logger (3 levels up, not 2).','apps/server/src/services/ai/assessors/supplyQualityAssessor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:07:56.427746','2026-04-20 10:44:21.343710');
INSERT INTO nitpick_findings VALUES(83,'NP-83',13,22,'implemented-to-accepted','test_coverage','critical','Unit test failure: should handle missing fields gracefully','Jest output: Expected value: pricing, Received array: [capabilities]. Test at supplyExtractionService.test.ts:165 expects fieldsFailed toContain pricing but the LLM mock returns capabilities instead. Tests: 1 failed, 20 passed.','Fix the test expectation or the service behavior so the mock LLM response produces pricing as a failed field.','apps/server/src/services/ai/__tests__/supplyExtractionService.test.ts:165',NULL,'duplicate',NULL,NULL,25,'2026-04-20 10:07:56.428281',NULL);
INSERT INTO nitpick_findings VALUES(84,'NP-84',13,22,'implemented-to-accepted','code_quality','critical','Unused imports in supplyQualityAssessor.ts (ESLint errors)','ESLint output: 13:18 error ''Capability'' is defined but never used. 13:30 error ''PricingInfo'' is defined but never used. 13:43 error ''QualityMetrics'' is defined but never used.','Remove unused imports Capability, PricingInfo, QualityMetrics from line 13 of supplyQualityAssessor.ts.','apps/server/src/services/ai/assessors/supplyQualityAssessor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:07:56.428774','2026-04-20 10:44:21.343711');
INSERT INTO nitpick_findings VALUES(85,'NP-85',14,24,'implemented-to-accepted','test_coverage','critical','Scene Extractors 测试失败：12 个测试用例失败，涉及多个场景提取器的核心功能',replace('Test Suites: 1 failed, 1 total\nTests: 12 failed, 24 passed, 36 total\n\n失败的测试包括：\n1. VisionShareExtractor: 位置信息提取失败、澄清问题格式错误、数据验证失败、室内外检测失败\n2. AgentDateExtractor: 场景检测置信度不足、澄清问题格式错误\n3. AgentJobExtractor: 薪资期望提取失败、福利提取失败、场景检测置信度不足\n4. AgentAdExtractor: 紧迫性检测失败、澄清问题格式错误、场景检测置信度不足','\n',char(10)),'修复场景提取器的实现，确保所有测试用例通过','apps/server/src/services/ai/__tests__/sceneExtractors.test.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:08:55.250964','2026-04-20 10:14:24.879576');
INSERT INTO nitpick_findings VALUES(86,'NP-86',14,24,'implemented-to-accepted','test_coverage','critical','SupplyExtractionService 测试失败：缺失字段处理测试未通过',replace('Test Suites: 1 failed, 1 total\nTests: 1 failed, 20 passed, 21 total\n\n● SupplyExtractionService › extract › should handle missing fields gracefully\n  expect(received).toContain(expected)\n  Expected value: "pricing"\n  Received array: ["capabilities"]','\n',char(10)),'修复缺失字段处理逻辑，确保 pricing 字段在缺少时被正确标记为失败','apps/server/src/services/ai/__tests__/supplyExtractionService.test.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:08:55.251771','2026-04-20 10:14:24.880742');
INSERT INTO nitpick_findings VALUES(87,'NP-87',14,24,'implemented-to-accepted','ac_quality','critical','Acceptance Criterion 质量不足：只有 1 个 AC，且描述模糊不可测试',replace('AC: AS-AD-001-AC-2\nDescription: "对比各家优惠方案推荐最优"\n- 无 verification_method 定义\n- 无 coverage 覆盖指标\n- 描述模糊，无法设计明确测试','\n',char(10)),'更新 AC 描述，明确验证方法和期望结果',NULL,NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:08:55.252276','2026-04-20 10:14:24.881224');
INSERT INTO nitpick_findings VALUES(88,'NP-88',12,20,'implemented-to-accepted','code_quality','critical','ReferenceError in completionService.ts:372 - Cannot access "suggestions" before initialization','Test output: ReferenceError: Cannot access suggestions before initialization at SupplyCompletionService.complete (src/services/ai/completionService.ts:372:50) - 8 test cases failed','Fix line 372: change const suggestions = this.generateSuggestions(suggestions.length > 0 ? supply : supply); to const suggestions = this.generateSuggestions(supply);','apps/server/src/services/ai/completionService.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 10:10:54.668578',NULL);
INSERT INTO nitpick_findings VALUES(89,'NP-89',12,20,'implemented-to-accepted','test_coverage','warning','No integration tests for supply API routes','Only unit tests exist for services. No integration tests for POST /api/v1/ai/extract-supply or /extract-supply/bulk endpoints','Add integration tests that actually start the server and test the HTTP endpoints','apps/server/src/routes/ai/supply.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 10:10:54.669487',NULL);
INSERT INTO nitpick_findings VALUES(90,'NP-90',12,20,'implemented-to-accepted','code_quality','warning','Unused variable "logger" in baseSupplyExtractor.ts','Lint output: error logger is defined but never used in apps/server/src/services/ai/extractors/supply/baseSupplyExtractor.ts:6','Remove unused import or use the logger','apps/server/src/services/ai/extractors/supply/baseSupplyExtractor.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 10:10:54.670064',NULL);
INSERT INTO nitpick_findings VALUES(91,'NP-91',12,20,'implemented-to-accepted','code_quality','warning','Unused import "Capability" and "ExperienceInfo" in visionShareSupplyExtractor.ts','Lint output: error Capability is defined but never used in apps/server/src/services/ai/extractors/supply/visionShareSupplyExtractor.ts:13','Remove unused imports','apps/server/src/services/ai/extractors/supply/visionShareSupplyExtractor.ts',NULL,'open',NULL,NULL,NULL,'2026-04-20 10:10:54.670549',NULL);
INSERT INTO nitpick_findings VALUES(92,'NP-92',20,29,'implemented-to-accepted','code_quality','critical','AgentAdExtractor 误判: 关键词 "找" 过于宽泛，导致 "我想找工作" 被识别为广告场景','Test input: "我想找工作" returns canHandle=true confidence=0.4. Detection keywords include "找" which matches in "找工作". Confidence threshold is 0.15, so canHandle=true. The keyword list contains "找" (too generic, overlaps with job-seeking "找工作").','Remove "找" from detectionKeywords, or add negative filters for job-related terms. More precise: keep only "想购", "求购", "购买" instead of standalone "找".','apps/server/src/services/ai/extractors/agentAdExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:22:50.077024','2026-04-20 10:46:57.161218');
INSERT INTO nitpick_findings VALUES(93,'NP-93',20,29,'implemented-to-accepted','code_quality','critical','AgentAdExtractor 产品名提取缺少后缀: "iPhone 15 Pro" 只提取到 "iPhone 15"','Test input: "想购iPhone 15 Pro" extracts product.name="iPhone 15" instead of "iPhone 15 Pro". Pattern: /iPhone\s*(\d+)/i only captures the number group. name() function returns "iPhone ${m[1]}" = "iPhone 15". The " Pro" suffix is not captured.','Update pattern to: /(?:iPhone\s*(\d+(?:\s+Pro)?))/i to capture optional suffixes like "Pro".','apps/server/src/services/ai/extractors/agentAdExtractor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:22:50.078122','2026-04-20 10:46:57.161220');
INSERT INTO nitpick_findings VALUES(94,'NP-94',20,29,'implemented-to-accepted','test_coverage','critical','AgentBehaviorService 垃圾内容检测失效: "BUY NOW!!! BUY NOW!!! BUY NOW!!!" 被放行','Test input: "BUY NOW!!! BUY NOW!!! BUY NOW!!!" should be rejected as spam but is allowed. isSpam() checks: (1) repeated single chars: not triggered; (2) capsRatio > 0.7: actual ~52% (13/25 chars), below threshold; (3) URL count > 3: not triggered. Pattern of repeated promotional phrases is not detected.','Add detection for repeated phrase patterns OR lower caps threshold from 0.7 to 0.5. Also add "buy now" as prohibited content keyword.','apps/server/src/services/agentBehaviorService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:22:50.078779','2026-04-20 10:46:57.161222');
INSERT INTO nitpick_findings VALUES(95,'NP-95',20,29,'implemented-to-accepted','code_quality','critical','AgentBehaviorService 违规计数逻辑缺陷: "inappropriate content" 不触发任何检测导致限制不生效','Test "should also lift restrictions": after 3x "inappropriate content" messages, isRestricted=false. Analysis: "inappropriate content" contains none of the prohibited keywords (spam/scam/phishing/malware/hate speech/harassment/illegal), and has low caps ratio (~20%), so all checks pass. No violations recorded, restriction never applied.','Add "inappropriate" to prohibitedContent list, OR lower caps ratio threshold from 0.7 to 0.5, OR add additional spam/content violation indicators.','apps/server/src/services/agentBehaviorService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:22:50.079340','2026-04-20 10:46:57.161223');
INSERT INTO nitpick_findings VALUES(96,'NP-96',20,29,'implemented-to-accepted','code_quality','critical','AgentBehaviorService 违规时错误码错误: 限制用户发群组消息返回 UNAUTHORIZED 而非 CONTENT_VIOLATION','Test: restricted agent sending GROUP message gets error.code=UNAUTHORIZED. The check correctly blocks non-DIRECT messages from restricted agents, but uses AgentProtocolErrorCode.UNAUTHORIZED. The semantic reason is CONTENT_VIOLATION (restricted agent violated policy), not UNAUTHORIZED.','Use AgentProtocolErrorCode.CONTENT_VIOLATION when restricted agent attempts unauthorized message type, not UNAUTHORIZED.','apps/server/src/services/agentBehaviorService.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:22:50.079882','2026-04-20 10:28:48.870882');
INSERT INTO nitpick_findings VALUES(97,'NP-97',20,29,'implemented-to-accepted','code_quality','critical','AgentBehaviorService 速率限制测试返回 UNAUTHORIZED 而非 RATE_LIMITED','Test: 61st DIRECT message returns UNAUTHORIZED instead of RATE_LIMITED. After ~10 violations from rate limit breaches, agent is suspended (suspendThreshold=10). The suspended check at top of checkBehavior() returns UNAUTHORIZED before the rate limit check is evaluated.','Increase suspendThreshold from 10 to 20, OR decrease DIRECT maxRequests from 60 to 10, OR record rate limit violations with lower severity so they do not accumulate to suspension level.','apps/server/src/services/agentBehaviorService.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:22:50.080931','2026-04-20 10:28:48.871230');
INSERT INTO nitpick_findings VALUES(98,'NP-98',20,29,'implemented-to-accepted','verification','warning','Issue 标题与验收标准不一致: 标题为 "Agent创建与基础配置" 但 AC 描述高级功能','Issue title: "Agent创建与基础配置". ACs: US-AGENT-014-AC-3 (披露反审中止), US-AGENT-009-AC-1/2/3 (私聊建议), US-AGENT-006-AC-1 (引荐通知). These ACs describe advanced features (AI suggestions, disclosure control) not basic agent creation.','Rename issue to reflect actual scope, e.g. "Agent 地则推荐与建议功能", OR split ACs into separate issues.','apps/server/src/routes/agents.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:22:50.081577','2026-04-20 10:28:48.871481');
INSERT INTO nitpick_findings VALUES(99,'NP-99',20,29,'implemented-to-accepted','verification','info','lint 检查未成功执行: turbo filter 名称错误','Command "pnpm run lint --filter=server" returned "No package found with name server in workspace". Could not verify lint compliance for agent-related files.','Use correct turbo filter name: check pnpm-workspace.yaml for actual workspace package names.','package.json',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:22:50.082140','2026-04-20 10:28:48.871727');
INSERT INTO nitpick_findings VALUES(100,'NP-100',15,28,'implemented-to-accepted','code_quality','critical','supplyQualityAssessor.ts has wrong logger import path, breaking all tests','Test suite failed: Cannot find module ''../../utils/logger'' from ''src/services/ai/assessors/supplyQualityAssessor.ts''. The file is at src/services/ai/assessors/supplyQualityAssessor.ts, which requires ../../../utils/logger (3 levels up) not ../../utils/logger (2 levels up). Compare: agentNegotiationService.ts (src/services/ai/agentNegotiationService.ts) correctly uses ../../utils/logger because it is only 2 levels deep.','Change import in supplyQualityAssessor.ts from ''../../utils/logger'' to ''../../../utils/logger''','apps/server/src/services/ai/assessors/supplyQualityAssessor.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.650918','2026-04-20 10:57:13.112787');
INSERT INTO nitpick_findings VALUES(101,'NP-101',15,28,'implemented-to-accepted','verification','critical','AS-PROTO-001-AC-1 not implemented: NegotiationMessage does not include creditScore','NegotiationMessage interface (line 86-101 in agentNegotiationService.ts) has fields: id, roomId, senderId, senderType, content, messageType, timestamp, metadata. No creditScore field. Socket handler (src/socket/handlers/agentNegotiation.ts line 124-133) emits messages with only: id, senderId, senderType, content, messageType, timestamp. AC says ''每条消息包含发送者类型和信用分'', but creditScore is not included in any emitted message.','Add creditScore field to NegotiationMessage interface and include it in socket message emission','apps/server/src/services/ai/agentNegotiationService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.652036','2026-04-20 10:57:13.112790');
INSERT INTO nitpick_findings VALUES(102,'NP-102',15,28,'implemented-to-accepted','test_coverage','warning','supplyToL2Mapper.validateMapping() test fails: empty required field not detected','Test ''should return false when required field is missing'' fails: expect(isValid).toBe(false) but received true. Test creates supply with title='''' and schema requiring title. The validateMapping() method (line 746) only checks result.data[field.id] truthiness, but L2Data field values are objects {textValue, sourceField, confidence}, so even empty string maps to a truthy object. Should check the actual field value content.','Update validateMapping to check if field values are meaningful (non-empty strings/arrays) rather than just checking existence','apps/server/src/services/ai/mappers/supplyToL2Mapper.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.652659','2026-04-20 10:57:13.112792');
INSERT INTO nitpick_findings VALUES(103,'NP-103',15,28,'implemented-to-accepted','test_coverage','warning','supplyExtractionService: empty pricing object not detected as failed field','Test ''should handle missing fields gracefully'' fails: expect(result.fieldsFailed).toContain(''pricing'') but received [''capabilities''] only. The test passes pricing: {} (empty object). getFailedFields (line 613) checks !(extraction.pricing || extraction.pricing_info) which evaluates to false for {} since {} is truthy. An empty pricing object should be treated as a failed field.','Update getFailedFields to check Object.keys(extraction.pricing || {}).length > 0 instead of just truthiness check','apps/server/src/services/ai/supplyExtractionService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.653218','2026-04-20 10:57:13.112793');
INSERT INTO nitpick_findings VALUES(104,'NP-104',15,28,'implemented-to-accepted','code_quality','warning','Unused imports causing lint errors in AI service files','Lint errors: agentNegotiationService.ts:21 unused import demandExtractionService; supplyQualityAssessor.ts:13 unused import Capability; supplyToL2Mapper.ts:9 unused import ExperienceInfo','Remove unused imports from these files','apps/server/src/services/ai/agentNegotiationService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.653704','2026-04-20 10:57:13.112794');
INSERT INTO nitpick_findings VALUES(105,'NP-105',15,28,'implemented-to-accepted','runtime_behavior','warning','clarificationService test times out due to setInterval in constructor','clarificationService.test.ts fails with Timeout error: setInterval in InMemorySessionStore constructor (line 98) causes Jest to hang waiting for timer callbacks. The service creates a cleanup interval in the constructor which Jest cannot properly clean up.','Refactor InMemorySessionStore to not start timers in constructor, or properly mock setInterval in tests','apps/server/src/services/ai/clarificationService.ts',NULL,'resolved','fix_inline',NULL,NULL,'2026-04-20 10:25:14.654171','2026-04-20 10:57:13.112795');
INSERT INTO nitpick_findings VALUES(106,'NP-106',15,28,'implemented-to-accepted','verification','info','L2 field validation relies on LLM output interpretation for demand-discount matching','AS-AD-002-AC-1 (evaluate demand-discount matching) is implemented via LLM-generated ''match'' score in compareOffers. The LLM prompt (buildComparisonPrompt line 953) instructs AI to score match 0-100, but the score is entirely dependent on LLM interpretation without deterministic validation.','Consider adding deterministic rule-based matching validation alongside LLM evaluation','apps/server/src/services/ai/agentNegotiationService.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:25:14.655111','2026-04-20 10:30:11.591158');
INSERT INTO nitpick_findings VALUES(107,'NP-107',15,28,'implemented-to-accepted','verification','info','Issue worktree is empty despite nitpicking status','The worktree at .issuetree/worktrees/ISSUE-AI003c is empty (no commits). The worktree_path in DB is null. The code for AI003c appears to exist in master branch (supplyQualityAssessor.ts, supplyToL2Mapper.ts, agentNegotiationService.ts), not in the issue worktree. The issue reached ''accepted'' status without any worktree-based implementation.','Investigate whether this issue was implemented outside the normal worktree workflow, or if implementation was merged from a different branch',NULL,NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:25:14.655841','2026-04-20 10:30:11.591536');
INSERT INTO nitpick_findings VALUES(108,'NP-108',7,30,'implemented-to-accepted','code_quality','critical','sanitizeString() HTML tag stripping is broken - removes individual <> chars instead of full tags. Input ''<script>alert(1)</script>'' becomes ''scriptalert(1)/script'' instead of ''alert(1)''. 3 validation tests fail.','validation.ts:166 uses /[<>]/g which strips individual angle bracket chars. Test output: expect(''alert(1)'').toBe(''scriptalert(1)/script'')','Replace /[<>]/g with /<[^>]*>/g to strip entire HTML tags, or use a proper HTML sanitization library like DOMPurify.','apps/server/src/middleware/validation.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:29:30.102650',NULL);
INSERT INTO nitpick_findings VALUES(109,'NP-109',7,30,'implemented-to-accepted','verification','critical','NoSQL injection detection has global flag lastIndex bug - pattern.test() alternates true/false on repeated calls. NoSQL injection attacks succeed 50% of the time.','security.ts:295 calls NOSQL_INJECTION_PATTERNS.some(pattern => pattern.test(value)) on /gi-flagged module-level patterns. Verified: test(''$where is here'') returns true,false,true,false on successive calls.','Apply the same cloning guard used in containsXSS/containsSQLInjection: new RegExp(pattern.source, pattern.flags.replace(''g'', '''')). Or use the String.prototype.search() method which ignores lastIndex.','apps/server/src/middleware/security.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:29:30.103518',NULL);
INSERT INTO nitpick_findings VALUES(110,'NP-110',7,30,'implemented-to-accepted','code_quality','warning','Symbol.match usage is inverted - checks input[Symbol.match] (String) but Symbol.match lives on RegExp.prototype. Code always falls to fallback path.','security.ts:39 checks typeof input[Symbol.match] === ''function'' but String.prototype[Symbol.match] is undefined. The fallback path works correctly, so this is functionally harmless but misleading.','Either fix to pattern[Symbol.match](input) or remove the dead code branch and just use the cloning approach directly.','apps/server/src/middleware/security.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:29:30.104057',NULL);
INSERT INTO nitpick_findings VALUES(111,'NP-111',7,30,'implemented-to-accepted','code_quality','warning','POST /api/v1/auth/change-password route missing Zod validation middleware. No password strength validation on newPassword field.','routes/auth.ts:299 - router.post(''/change-password'', ...) has no validate() middleware, only manual if checks. Contrast with register (line 61), login (line 112), reset-password (line 273) which all have validate() middleware.','Add a changePasswordSchema to authSchemas.ts with oldPassword and newPassword fields (newPassword should match resetPasswordSchema strength requirements), and add validate({ body: changePasswordSchema }) middleware.','apps/server/src/routes/auth.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:29:30.104507',NULL);
INSERT INTO nitpick_findings VALUES(112,'NP-112',7,30,'implemented-to-accepted','consistency','warning','AppError subclasses have inconsistent Object.setPrototypeOf - only ValidationError and MulterUploadError have it, other subclasses (NotFoundError, UnauthorizedError, ForbiddenError, ConflictError, RateLimitError) are missing it.','AppError.ts:58 has Object.setPrototypeOf for ValidationError, AppError.ts:124 for MulterUploadError. NotFoundError (line 68), UnauthorizedError (line 78), ForbiddenError (line 88), ConflictError (line 98), RateLimitError (line 109) are missing it.','Add Object.setPrototypeOf(this, ClassName.prototype) to all AppError subclasses for consistency, or move it to the base AppError constructor.','apps/server/src/errors/AppError.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:29:30.104924',NULL);
INSERT INTO nitpick_findings VALUES(113,'NP-113',4,31,'implemented-to-accepted','verification','critical','注册端点缺失（NP-63 重新打开）：authService.registerUser() 函数存在但无路由可达','src/routes/v1/auth.ts 只有 5 个端点: login, refresh, logout, logout-all, me。无 POST /register 路由。authService.ts 中 registerUser() (line 241) 和 registerUserSchema 从未被调用。','添加 POST /api/v1/auth/register 路由，调用 registerUser() 并返回用户信息和 tokens。','apps/server/src/routes/v1/auth.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:33:09.043799','2026-04-20 10:37:05.149933');
INSERT INTO nitpick_findings VALUES(114,'NP-114',4,31,'implemented-to-accepted','verification','critical','密码重置端点缺失（NP-64 重新打开）：requestPasswordReset() 和 resetPassword() 存在但无路由可达','src/routes/v1/auth.ts 无 POST /forgot-password 或 POST /reset-password 路由。authService.ts 中 requestPasswordReset() (line 466) 和 resetPassword() (line 497) 从未被调用。userSchemas.ts 中 resetPasswordSchema 和 setNewPasswordSchema 从未被使用。','添加 POST /api/v1/auth/forgot-password 和 POST /api/v1/auth/reset-password 路由。','apps/server/src/routes/v1/auth.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:33:09.044612','2026-04-20 10:37:05.150332');
INSERT INTO nitpick_findings VALUES(115,'NP-115',4,31,'implemented-to-accepted','runtime_behavior','critical','登录锁定机制被绕过（NP-65 重新打开）：auth.ts 的 /login 路由直接执行 bcrypt.compare，未调用包含锁定逻辑的 loginUser()','src/routes/v1/auth.ts:22-38 的 /login 路由直接用 bcrypt.compare 验证密码，完全绕过了 authService.ts:30-35 的 loginAttempts Map 锁定逻辑。loginUser() 函数中的锁定检查根本不会被执行。','将锁定逻辑添加到 /login 路由中，或重构让 /login 调用带锁定的验证函数。','apps/server/src/routes/v1/auth.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:33:09.045194','2026-04-20 10:37:05.150595');
INSERT INTO nitpick_findings VALUES(116,'NP-116',4,31,'implemented-to-accepted','verification','critical','注册端点缺失（NP-63 重新打开）：authService.registerUser() 函数存在但无路由可达','src/routes/v1/auth.ts 只有 5 个端点: login, refresh, logout, logout-all, me。无 POST /register 路由。authService.ts 中 registerUser() (line 241) 从未被调用。','添加 POST /api/v1/auth/register 路由，调用 registerUser() 并返回用户信息和 tokens。','apps/server/src/routes/v1/auth.ts',NULL,'duplicate',NULL,NULL,113,'2026-04-20 10:34:05.793658',NULL);
INSERT INTO nitpick_findings VALUES(117,'NP-117',4,31,'implemented-to-accepted','verification','critical','密码重置端点缺失（NP-64 重新打开）：requestPasswordReset() 和 resetPassword() 存在但无路由可达','src/routes/v1/auth.ts 无 POST /forgot-password 或 POST /reset-password 路由。authService.ts 中 requestPasswordReset() (line 466) 和 resetPassword() (line 497) 从未被调用。userSchemas.ts 中的 resetPasswordSchema 和 setNewPasswordSchema 从未被使用。','添加 POST /api/v1/auth/forgot-password 和 POST /api/v1/auth/reset-password 路由。','apps/server/src/routes/v1/auth.ts',NULL,'duplicate',NULL,NULL,114,'2026-04-20 10:34:05.794511',NULL);
INSERT INTO nitpick_findings VALUES(118,'NP-118',4,31,'implemented-to-accepted','runtime_behavior','critical','登录锁定机制被绕过（NP-65 重新打开）：auth.ts 的 /login 路由直接执行 bcrypt.compare，未调用包含锁定逻辑的 loginUser()','src/routes/v1/auth.ts:22-38 的 /login 路由直接用 bcrypt.compare 验证密码，完全绕过了 authService.ts:30-35 的 loginAttempts Map 锁定逻辑。loginUser() 函数中的锁定检查根本不会被执行。','将锁定逻辑添加到 /login 路由中，或重构让 /login 调用带锁定的验证函数。','apps/server/src/routes/v1/auth.ts',NULL,'duplicate',NULL,NULL,115,'2026-04-20 10:34:05.795055',NULL);
INSERT INTO nitpick_findings VALUES(119,'NP-119',4,31,'implemented-to-accepted','code_quality','critical','硬编码开发验证码后门：ALLOW_DEV_VERIFICATION_CODE=true 时，任何人都可以用验证码 123456 登录','src/services/authService.ts:50-57: if (process.env.ALLOW_DEV_VERIFICATION_CODE === ''true'' && code === ''123456'') return true;','移除此开发后门代码，或确保环境变量在生产环境强制为 false。','apps/server/src/services/authService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.795510','2026-04-20 10:37:05.147225');
INSERT INTO nitpick_findings VALUES(120,'NP-120',4,31,'implemented-to-accepted','runtime_behavior','critical','认证端点缺少严格的速率限制：auth 路由未应用 strictAuthLimiter，只使用宽松的全局 100req/15min 限制','src/routes/v1/index.ts 挂载 /api/v1/auth 时未应用任何速率限制。rateLimitConfigs.auth (5req/15min) 定义但未使用。','在 auth 路由上应用 strictAuthLimiter 或自定义严格限制。','apps/server/src/routes/v1/index.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.795959','2026-04-20 10:37:05.147733');
INSERT INTO nitpick_findings VALUES(121,'NP-121',4,31,'implemented-to-accepted','code_quality','warning','JWT_SECRET 重复定义三次，authService.ts 存在遗留的独立 jwt.sign/jwt.verify 代码路径','jwt.ts:13-16, authService.ts:25-28, middleware/auth.ts:26-29 各自独立加载 JWT_SECRET。authService.ts:9 单独 import jsonwebtoken，直接调用 jwt.sign() (line 168) 和 jwt.verify() (lines 195, 418, 482, 505)，生成不带 jti 的 legacy token。','统一使用 auth/jwt.ts 中的 generateTokens/verifyToken，废弃 authService.ts 中的直接 jwt 调用。','apps/server/src/services/authService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.796400','2026-04-20 10:37:05.148013');
INSERT INTO nitpick_findings VALUES(122,'NP-122',4,31,'implemented-to-accepted','consistency','warning','Refresh token 过期时间配置不一致','auth/jwt.ts:18 默认 7d，authService.ts:169 默认 30d，auth/refreshToken.ts:11 默认 7d。使用不同的环境变量名 JWT_REFRESH_EXPIRES_IN vs REFRESH_TOKEN_EXPIRES_IN。','统一使用同一个配置源和默认值。','apps/server/src/services/auth/jwt.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.796847','2026-04-20 10:37:05.148264');
INSERT INTO nitpick_findings VALUES(123,'NP-123',4,31,'implemented-to-accepted','code_quality','warning','jwt.sign() 和 jwt.verify() 未指定 algorithm 选项，存在 algorithm confusion 攻击风险','jwt.ts 的 sign() 和 verify() 调用未指定 algorithms: [''HS256'']。','在 jwt.verify() 中添加 algorithms: [''HS256'']，在 jwt.sign() 中指定 algorithm: ''HS256''。','apps/server/src/services/auth/jwt.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.797272','2026-04-20 10:37:05.148503');
INSERT INTO nitpick_findings VALUES(124,'NP-124',4,31,'implemented-to-accepted','code_quality','warning','findRefreshToken() 返回包含 passwordHash 的完整用户记录，但 /refresh 路由不使用这些数据','refreshToken.ts:47-52 include: { user: true } 获取用户所有字段包括 passwordHash。auth.ts:85 调用 findRefreshToken() 但只使用 token 数据。','移除 include: { user: true }，或只 select 需要的字段。','apps/server/src/services/auth/refreshToken.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.797701','2026-04-20 10:37:05.148803');
INSERT INTO nitpick_findings VALUES(125,'NP-125',4,31,'implemented-to-accepted','test_coverage','warning','auth/routes.test.ts 缺少成功登录的测试用例（NP-67 重新打开）','routes.test.ts 只测试了错误情况（缺少字段、用户不存在、密码错误、无 token、refresh 缺失/无效）。无任何测试验证正确凭据登录返回 user + tokens 的场景。','添加 should return user and tokens for valid credentials 测试用例。','apps/server/src/__tests__/auth/routes.test.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.798108','2026-04-20 10:37:05.149086');
INSERT INTO nitpick_findings VALUES(126,'NP-126',4,31,'implemented-to-accepted','test_coverage','warning','authService.test.ts 缺少 loginUser() 函数测试（NP-68 重新打开）','authService.test.ts 只测试 validatePasswordStrength 和 password hashing。authService.ts:291 的 loginUser() 函数（包含锁定的核心登录逻辑）完全无单元测试覆盖。','为 loginUser() 添加测试，覆盖成功登录、错误密码、账户锁定、验证码登录等场景。','apps/server/src/services/auth/__tests__/authService.test.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:34:05.798517','2026-04-20 10:37:05.149631');
INSERT INTO nitpick_findings VALUES(127,'NP-127',4,31,'implemented-to-accepted','code_quality','info','blacklistToken() 写入两个冗余的 Redis key，但只有一个被读取','blacklist.ts:35-39 同时写入 BLACKLIST_PREFIX 和 BLACKLIST_JTI_PREFIX 两个 key，但 isJtiBlacklisted() 和 isTokenBlacklisted() 只读取 BLACKLIST_PREFIX。BLACKLIST_JTI_PREFIX 的数据永远不会被使用。','移除 BLACKLIST_JTI_PREFIX 的写入，或删除整个 BLACKLIST_JTI_PREFIX 逻辑。','apps/server/src/services/auth/blacklist.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:34:05.798955','2026-04-20 10:37:05.150833');
INSERT INTO nitpick_findings VALUES(128,'NP-128',4,31,'implemented-to-accepted','code_quality','info','logout-all 路由使用不必要的动态 import','auth.ts:159: const { revokeAllUserRefreshTokens } = await import(''../../services/auth/refreshToken''); 但该函数已在文件顶部静态导入。动态 import 增加延迟。routes.test.ts 接受 500 错误作为可能的响应。','移除动态 import，直接使用顶部静态导入的 revokeAllUserRefreshTokens。','apps/server/src/routes/v1/auth.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:34:05.799407','2026-04-20 10:37:05.151074');
INSERT INTO nitpick_findings VALUES(129,'NP-129',11,37,'implemented-to-accepted','test_coverage','critical','6 unit tests failing across 4 test suites: clarificationService (1), sceneDetector (2), agentAdExtractor (2), visionShareExtractor (1)','Test Suites: 4 failed, 7 passed, 11 total. Tests: 6 failed, 163 passed, 169 total. Failures: (1) clarificationService.test.ts:108 - expects clarifying got completed; (2) sceneDetector.test.ts:33 - detectScene("想找一份Java开发工作") returns unknown not agentjob; (3) sceneDetector.test.ts:98 - getExtractorForText("需要摄影服务") returns undefined; (4) agentAdExtractor.test.ts:23 - canHandle("我想找工作") returns true not false; (5) agentAdExtractor.test.ts:30 - product name "iPhone 15" not "iPhone 15 Pro"; (6) visionShareExtractor.test.ts:62 - city returns "北京" not "北京市"','Fix all 6 test failures: (1) Update clarification test to expect completed when user answers all fields in one response; (2-3) Lower SceneDetector confidence threshold from 0.5 to 0.4 or add job keywords; (4) Narrow AgentAdExtractor detectionKeywords - remove overly generic terms; (5) Fix iPhone regex to capture Pro/Max/etc suffixes; (6) Fix city extraction to preserve 市 suffix consistently with district','apps/server/src/services/ai/extractors/__tests__/',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:54:55.007959');
INSERT INTO nitpick_findings VALUES(130,'NP-130',11,37,'implemented-to-accepted','runtime_behavior','warning','InMemorySessionStore setInterval never cleared - causes Jest open handle warnings and prevents clean test exit','Jest detected 2 open handles: setInterval(() => this.cleanup(), 5 * 60 * 1000) at clarificationService.ts:98. Created in InMemorySessionStore constructor with no corresponding clearInterval call anywhere in the codebase.','Store the interval ID in a class property, add a destroy() method to InMemorySessionStore that calls clearInterval, and call it in test afterAll hooks. This is a resource leak that will cause problems in long-running processes too.','apps/server/src/services/ai/clarificationService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:54:55.009091');
INSERT INTO nitpick_findings VALUES(131,'NP-131',11,37,'implemented-to-accepted','code_quality','warning','Two duplicate BaseSceneExtractor classes with incompatible interfaces: base.ts (LLM-based) vs baseExtractor.ts (regex-based)','base.ts defines BaseSceneExtractor with Demand/DemandExtractionRequest types. baseExtractor.ts defines BaseSceneExtractor with SceneExtractedData types. Both exported from index.ts. SceneType defined twice with different values. Two sets of extractors per scene (agentJob.ts vs agentJobExtractor.ts, etc). Tests use the regex-based ones, while agentJob.ts/agentAd.ts use the LLM-based ones.','Consolidate to one base class and one extractor per scene. Decide on LLM vs regex approach and remove the other. This duplication creates confusion about which implementation is authoritative and doubles maintenance burden.','apps/server/src/services/ai/extractors/base.ts',NULL,'adopted','become_ac',NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:54:55.009628');
INSERT INTO nitpick_findings VALUES(132,'NP-132',11,37,'implemented-to-accepted','code_quality','warning','Unused import SceneSpecificExtractor in clarificationService.ts','eslint: clarificationService.ts:9 - SceneSpecificExtractor is imported but never used. The lint error: "SceneSpecificExtractor is defined but never used."','Remove the unused import on line 9 of clarificationService.ts.','apps/server/src/services/ai/clarificationService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:55:13.153851');
INSERT INTO nitpick_findings VALUES(133,'NP-133',11,37,'implemented-to-accepted','verification','warning','VisionShareExtractor city extraction strips 市 suffix but district keeps 区 suffix - inconsistent behavior','visionShareExtractor.ts:135 strips 市: cityCandidate[1].replace(/[市县城省]$/, ""). But line 127 adds 区: districtName + "区". Result: user says "在北京市朝阳区" but gets city="北京", district="朝阳区". Test at line 62 expects city="北京市".','Either preserve 市 suffix consistently (match user input) or strip from both city and district. Current behavior is inconsistent - city loses suffix but district keeps it.','apps/server/src/services/ai/extractors/visionShareExtractor.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:54:55.010095');
INSERT INTO nitpick_findings VALUES(134,'NP-134',11,37,'implemented-to-accepted','code_quality','info','AgentAdExtractor detectionKeywords includes overly generic keywords causing false positive matches','detectionKeywords at line 22-23 includes "需要" and "推荐" - common Chinese verbs that appear in many non-shopping contexts. Test proves the issue: "我想找工作" incorrectly matches AgentAd extractor with canHandle=true.','Remove or qualify overly broad keywords. Replace "需要" with more specific shopping-related phrases like "需要购买", remove "推荐" (too generic for shopping detection).','apps/server/src/services/ai/extractors/agentAdExtractor.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20T18:50:35.474926','2026-04-20 10:54:55.010514');
INSERT INTO nitpick_findings VALUES(135,'NP-135',13,40,'reviewed-to-implemented','code_quality','warning','12 @typescript-eslint/no-explicit-any warnings across supplyExtractionService.ts (7), supply routes (5). While no errors, max-warnings=0 causes lint failure.','eslint output: 12 warnings (0 errors) for no-explicit-any across supplyExtractionService.ts, supply.ts route. Codebase pattern: demandExtractionService.ts also has 1 such warning.','Replace `any` with proper types or use more specific types like `Record<string, unknown>`. Alternatively, these are consistent with other AI services in the codebase.','apps/server/src/services/ai/supplyExtractionService.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:59:48.838879','2026-04-20 11:01:54.723099');
INSERT INTO nitpick_findings VALUES(136,'NP-136',13,40,'reviewed-to-implemented','code_quality','warning','Semantic inconsistency: getExtractedFields() reports pricing:{} as extracted (truthy check on line 598), while getFailedFields() correctly detects it as failed (empty-object check on lines 617-625). Same empty pricing appears in both fieldsExtracted and fieldsFailed arrays.','supplyExtractionService.ts:598 checks `if (extraction.pricing || extraction.pricing_info)` which is truthy for {}. Lines 617-625 check `Object.keys(extraction.pricing).length > 0` which is 0 for {}. Result: pricing in BOTH lists.','Align getExtractedFields with getFailedFields: also check Object.keys(extraction.pricing).length > 0 before adding to fieldsExtracted, so empty pricing is not reported as extracted.','apps/server/src/services/ai/supplyExtractionService.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 10:59:48.840192','2026-04-20 11:01:54.722520');
INSERT INTO nitpick_findings VALUES(137,'NP-137',13,40,'reviewed-to-implemented','verification','info','POST /extract-supply/sync endpoint returns mock success response without actually persisting data. Comment says 目前返回模拟成功响应. The endpoint validates input with Zod schema but does not interact with any data store.','supply.ts lines 351-379: endpoint accepts supply_id and data, logs the request, then returns {success: true, synced_at, fields_updated} without any database write.','Either implement the actual sync logic or remove/mark the endpoint as stub to avoid confusion. If keeping as stub, add a TODO comment and consider returning 501 Not Implemented.','apps/server/src/routes/ai/supply.ts',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 10:59:48.840882','2026-04-20 11:01:54.723496');
INSERT INTO nitpick_findings VALUES(138,'NP-138',20,41,'implemented-to-accepted','code_quality','critical','Duplicate named export ''ExtractionOptions'' prevents server from starting','apps/server/src/services/ai/index.ts:24 and :100 both export ExtractionOptions (from demandExtractionService and supplyExtractionService respectively). Build error: Multiple exports with the same name ExtractionOptions. Running pnpm run dev fails immediately with TransformError.','Rename one of the exports, e.g., ExtractionOptions from supplyExtractionService should be SupplyExtractionOptions, or alias at export: export { ExtractionOptions as DemandExtractionOptions } and export { ExtractionOptions as SupplyExtractionOptions }.','apps/server/src/services/ai/index.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.049171','2026-04-20 11:05:57.413987');
INSERT INTO nitpick_findings VALUES(139,'NP-139',20,41,'implemented-to-accepted','code_quality','critical','Express route ordering bug breaks /search, /sort-options, /recommended, /filter-suggestions, and /history endpoints','In apps/server/src/routes/agents.ts, GET /:id is defined at line 200, but GET /search (line 322), GET /sort-options (line 405), GET /recommended (line 428), GET /filter-suggestions (line 471), and GET /:id/history (line 282) are all defined AFTER /:id. Express matches routes in declaration order, so e.g. GET /agents/search would match /:id with id=search instead of the /search handler.','Move all /search, /sort-options, /recommended, /filter-suggestions, and /:id/history route definitions to BEFORE the /:id route (line 200).','apps/server/src/routes/agents.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.049940','2026-04-20 11:05:57.414573');
INSERT INTO nitpick_findings VALUES(140,'NP-140',20,41,'implemented-to-accepted','test_coverage','critical','agentBehaviorService tests have incorrect test data causing 3/3 behavior tests to fail','Running pnpm test -- --testPathPattern=agentBehaviorService: (1) should reject message exceeding rate limit sends 61 identical Hello messages; the anomaly detector repetition check (maxSimilarMessages=5) triggers CONTENT_VIOLATION by message 5, suspending the agent by message 9. By the time rate limit is checked, agent is already UNAUTHORIZED. (2) liftRestriction and clearViolations tests use content bad content / bad which does NOT match any prohibited keyword, so 0 violations are recorded and agent is never restricted.','Fix test data: for rate limit test, use varied message content to avoid repetition triggers. For restriction tests, use content like spam or inappropriate to trigger content violations.','apps/server/src/services/__tests__/agentBehaviorService.test.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.050437','2026-04-20 11:05:57.414886');
INSERT INTO nitpick_findings VALUES(141,'NP-141',20,41,'implemented-to-accepted','code_quality','critical','templateService test crashes due to missing mock export','Running pnpm test -- --testPathPattern=templateService crashes with TypeError: (0, shared_2.getSceneConfig) is not a function. The Jest mock at apps/server/src/__mocks__/@bridgeai/shared.ts does not export getSceneConfig, so when templateService.ts imports it the mock returns undefined.','Add export function getSceneConfig(sceneId: any): any { return undefined; } to the mock, or update moduleNameMapper to use the real shared package for templateService tests.','apps/server/src/__mocks__/@bridgeai/shared.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.050881','2026-04-20 11:05:57.415161');
INSERT INTO nitpick_findings VALUES(142,'NP-142',20,41,'implemented-to-accepted','runtime_behavior','warning','Agent search and recommended routes perform full table scan without DB-level pagination','In apps/server/src/routes/agents.ts lines 358 and 439, both GET /agents/search and GET /agents/recommended call prisma.agent.findMany() with no where clause and no pagination, loading ALL agents into memory then paginating in JS.','Add database-level pagination: add where clause based on user context, apply limit/take at Prisma level (e.g., take: limitNum, skip: skip), or add cursor-based pagination.','apps/server/src/routes/agents.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.051333','2026-04-20 11:05:57.415421');
INSERT INTO nitpick_findings VALUES(143,'NP-143',20,41,'implemented-to-accepted','code_quality','warning','Agent creation endpoint lacks input schema validation','In apps/server/src/routes/agents.ts line 145, POST /agents passes req.body directly to agentService.createAgent() without validating against createAgentSchema. Malformed requests with missing required fields will fail at the database layer with cryptic errors.','Use createAgentSchema.parse(req.body) or createAgentSchema.safeParse(req.body) before calling the service.','apps/server/src/routes/agents.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:01:15.051750','2026-04-20 11:05:57.415671');
INSERT INTO nitpick_findings VALUES(144,'NP-144',20,41,'implemented-to-accepted','test_coverage','info','Server test suite has 15 failing test suites out of 33 total (45% failure rate)','Running pnpm test in apps/server: 18 PASS, 15 FAIL. Key failures: templateService (TypeError), authService, oauthService, connectionService, locationSearchService, chat/participantService, clarificationService, sceneDetector, visionShareExtractor, completionService, roomHandler, handoffHandler, users, chat routes, consumerDemand, abtest.','Prioritize fixing the critical crashes first, then address the behavioral test failures.','apps/server',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 11:01:15.052147','2026-04-20 11:05:57.415917');
INSERT INTO nitpick_findings VALUES(145,'NP-145',15,44,'implemented-to-accepted','verification','critical','Socket handler only includes creditScore in 1 of 5 negotiation:message emissions, violating AS-PROTO-001-AC-1 (every message must include creditScore). While agentNegotiationService.ts correctly adds creditScore to all NegotiationMessage objects, the socket handler manually picks fields and strips creditScore in: merchant submitOffer (line 178), consumer askQuestion broadcast (line 318), comparison report (line 386), and confirmation broadcast (line 519). Only the consumer introduction (line 131) includes creditScore.','grep for ''creditScore'' in agentNegotiation.ts socket handler shows only 1 match at line 131. Lines 178-187, 318-328, 386-396, 454-462, 519-529 all emit negotiation:message without creditScore field.','Add creditScore field to all 5 negotiation:message emission points in the socket handler, or refactor to spread the full message object (e.g., message: { ...msg } instead of manually picking fields).','apps/server/src/socket/handlers/agentNegotiation.ts',NULL,'adopted','fix_inline',NULL,NULL,'2026-04-20 11:07:56.885106','2026-04-20 11:10:17.574750');
INSERT INTO nitpick_findings VALUES(146,'NP-146',15,44,'implemented-to-accepted','runtime_behavior','warning','clarificationService singleton at line 604 creates InMemorySessionStore with active setInterval that is never cleaned up. The test afterEach only stops cleanup on the test-local service instance, not the module-level singleton. Jest detects this as an open handle preventing clean test exit.','Jest output: ''Jest has detected the following 1 open handle potentially keeping Jest from exiting: Timeout at new InMemorySessionStore (src/services/ai/clarificationService.ts:100:30) at new ClarificationService (src/services/ai/clarificationService.ts:159:41) at Object.<anonymous> (src/services/ai/clarificationService.ts:604:37)''','Either: (1) Don''t create singleton at module level in test environment (check process.env.NODE_ENV), or (2) Export a factory function instead of a singleton, or (3) Pass cleanupIntervalMs=0 to the singleton constructor to disable the interval.','apps/server/src/services/ai/clarificationService.ts:604',NULL,'dismissed',NULL,NULL,NULL,'2026-04-20 11:07:56.885943','2026-04-20 11:10:17.575338');
INSERT INTO nitpick_findings VALUES(147,'NP-C004-1',1,76,'implemented-to-accepted','verification','critical','No implementation to verify: worktree is empty, no acceptance criteria, no tasks, and no nitpick findings exist for this issue','Worktree .issuetree/worktrees/ISSUE-C004/ is empty (0 bytes, only . and .. entries). DB query: 0 tasks, 0 acceptance_criteria, 0 nitpick_findings for issue_id=1. current_task_id=76 references non-existent task (max task ID in DB is 49). No git commit history for ISSUE-C004 worktree.','Create or locate the implementation for the 属性过滤系统 (attribute filtering system). The issue transitioned implementing->stuck on 2026-04-19. The implementation may have been attempted in another worktree or needs to be restarted from scratch.','.issuetree/worktrees/ISSUE-C004/',NULL,'open',NULL,NULL,NULL,'2026-04-20 12:42:06',NULL);
INSERT INTO nitpick_findings VALUES(148,'NP-C004-2',1,76,'implemented-to-accepted','consistency','critical','Attribute filtering implementation exists in OTHER issues but not ISSUE-C004: attributeFilterService.ts and attributeFilter types found in ISSUE-INF002, ISSUE-CR003, ISSUE-INT002a, ISSUE-INT003 worktrees, but not in ISSUE-C004 or master','grep for attributeFilterService.ts: 22 files across 5 worktrees (ISSUE-INF002, ISSUE-UI002, ISSUE-CR003, ISSUE-INT002a, ISSUE-INT003), zero files on master or in ISSUE-C004. IssueTree.md shows C004 depends on C002b and is referenced by M001a.','Clarify whether: (1) ISSUE-C004 implementation should be created from scratch, (2) implementation from INF002/INT002a/INT003 should be merged under C004, or (3) C004 should be closed as duplicate. The relationship between ISSUE-C004 and these other issues needs to be clarified.',NULL,NULL,'open',NULL,NULL,NULL,'2026-04-20 12:42:06',NULL);
INSERT INTO nitpick_findings VALUES(149,'NP-C004-3',1,76,'implemented-to-accepted','verification','critical','Issue has invalid state: status=nitpicking but with no valid task or transition path. Task manager set status to nitpicking without creating a nitpick task or recording the transition','state_changes table: no record of transition to nitpicking. Last recorded: implementing->stuck (2026-04-19 06:40). current_task_id=76, task_ids 689/707 referenced in state_changes - none exist in tasks table (max ID=49). This is a data integrity issue.','Investigate why the task manager incorrectly set status=nitpicking without: (1) a valid nitpick task, (2) a valid task_id reference, (3) proper state_change record. Consider regressing to stuck status and creating a proper research/implement task.',NULL,NULL,'open',NULL,NULL,NULL,'2026-04-20 12:42:06',NULL);
INSERT INTO verification_checkpoints VALUES(1,'VC-1',6,28,'implemented-to-accepted',replace('POST /api/v1/users/avatar endpoint is completely untested in users.test.ts. The test file has 7 tests covering GET/PUT/DELETE /me but zero tests for POST /avatar.\n推荐修复: Add tests for POST /api/v1/users/avatar covering: file upload success, avatarUrl bypass path, file type rejection, file size limit exceeded, and no-file/no-url error.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.043689',9,'2026-04-20 09:45:58.936700');
INSERT INTO verification_checkpoints VALUES(2,'VC-2',6,29,'implemented-to-accepted',replace('PUT /api/v1/users/me lacks input validation for profile fields. No Zod schema, no length limits, no HTML sanitization for name/bio/website.\n推荐修复: Add validation middleware or Zod schema for profile update fields: max string lengths, URL format for website, sanitize HTML/script content in bio/name.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.044164',9,'2026-04-20 09:45:58.937233');
INSERT INTO verification_checkpoints VALUES(3,'VC-3',6,30,'implemented-to-accepted',replace('File type and size rejection not tested for avatar upload. Neither users.test.ts nor upload.test.ts test multer fileFilter rejection or fileSize limit scenarios.\n推荐修复: Add tests for multer fileFilter rejection and file size limit exceeded for both /users/avatar and /upload/avatar endpoints.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.044417',9,'2026-04-20 09:45:58.937587');
INSERT INTO verification_checkpoints VALUES(4,'VC-4',6,31,'implemented-to-accepted',replace('Old avatar files not cleaned up on new upload or account deletion. storageService.deleteFile() exists but is never called from userService.\n推荐修复: Delete old avatar file before updating with new one in updateAvatar(). Clean up avatar storage when user account is deleted in deleteUser().','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.044646',9,'2026-04-20 09:45:58.937908');
INSERT INTO verification_checkpoints VALUES(5,'VC-5',6,32,'implemented-to-accepted',replace('Avatar URL bypass (req.body.avatarUrl) accepts arbitrary URLs without validation. Could accept javascript:, file:, or any arbitrary URL scheme.\n推荐修复: Validate avatarUrl with URL parsing, whitelist http/https schemes, sanitize input, optionally verify the URL points to a valid image.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.044866',9,'2026-04-20 09:45:58.938203');
INSERT INTO verification_checkpoints VALUES(6,'VC-6',6,33,'implemented-to-accepted',replace('userService.ts uses Prisma model fields not in schema.prisma. TypeScript compilation fails with 19 errors for missing fields: displayName, bio, website, location, emailVerified, phoneVerified, privacySettings.\n推荐修复: Either add missing fields to User model in schema.prisma and migrate, or remove non-existent field references from userService.ts.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.045078',9,'2026-04-20 09:45:58.938538');
INSERT INTO verification_checkpoints VALUES(7,'VC-7',6,34,'implemented-to-accepted',replace('userService.ts uses Prisma model fields that don''t exist in schema.prisma. Fields like emailVerified, displayName, bio, website, location, phoneVerified, privacySettings are missing from the User model.\n推荐修复: Add missing fields to User model in prisma/schema.prisma: emailVerified (Boolean), displayName (String?), bio (String?), website (String?), location (String?), phoneVerified (Boolean), privacySettings (Json). Then run prisma generate.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.045292',9,'2026-04-20 09:45:58.938878');
INSERT INTO verification_checkpoints VALUES(8,'VC-8',6,35,'implemented-to-accepted',replace('Avatar URL bypass (req.body.avatarUrl) accepts arbitrary URLs without validation. Could accept javascript: or data: URLs leading to XSS.\n推荐修复: Add URL validation: only allow https:// URLs from allowed domains, or remove the avatarUrl bypass entirely and require file upload only.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.045513',9,'2026-04-20 09:45:58.939188');
INSERT INTO verification_checkpoints VALUES(9,'VC-9',6,36,'implemented-to-accepted',replace('Old avatar files not cleaned up on new upload or account deletion. storageService.deleteFile() exists but is never called when avatar is updated or user is deleted.\n推荐修复: Before updating avatar, fetch old avatarUrl and call storageService.deleteFile(). Before deleting user, clean up avatar file.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.045733',9,'2026-04-20 09:45:58.939484');
INSERT INTO verification_checkpoints VALUES(10,'VC-10',6,37,'implemented-to-accepted',replace('PUT /api/v1/users/me lacks input validation for profile fields. No Zod schema, no length limits, no type checking.\n推荐修复: Add Zod schema validation: name (1-100 chars), displayName (0-50 chars), bio (0-500 chars), website (valid URL), location (0-200 chars).','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.045951',9,'2026-04-20 09:45:58.939797');
INSERT INTO verification_checkpoints VALUES(11,'VC-11',6,38,'implemented-to-accepted',replace('POST /api/v1/users/avatar endpoint has no tests in users.test.ts. The test file only covers GET /me, PUT /me, and DELETE /me routes.\n推荐修复: Add test cases for avatar upload: successful upload, no file provided, invalid file type, file too large, avatarUrl bypass.','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.046160',9,'2026-04-20 09:45:58.940076');
INSERT INTO verification_checkpoints VALUES(12,'VC-12',6,39,'implemented-to-accepted',replace('File type and size rejection not tested for avatar upload. Neither users.test.ts nor upload.test.ts tests multer fileFilter rejection.\n推荐修复: Add test cases: upload .exe file (should return 400), upload .pdf file (should return 400), upload 6MB file (should return 413).','\n',char(10)),'resolved',NULL,'2026-04-20 10:33:19.046373',9,'2026-04-20 09:45:58.940346');
INSERT INTO verification_checkpoints VALUES(13,'VC-13',3,45,'implemented-to-accepted',replace('JWT secret uses insecure fallback value ''your-secret-key'' in production path\n推荐修复: Remove the fallback - throw an error if JWT_SECRET is not set, similar to apps/server/src/middleware/auth.ts:26-27 which correctly requires JWT_SECRET','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.917889');
INSERT INTO verification_checkpoints VALUES(14,'VC-14',3,46,'implemented-to-accepted',replace('Hardcoded verification code ''123456'' bypasses authentication in production path\n推荐修复: Remove hardcoded verification code. Implement proper verification code generation and storage (e.g., Redis with TTL, or database with expiry)','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.918377');
INSERT INTO verification_checkpoints VALUES(15,'VC-15',3,47,'implemented-to-accepted',replace('No rate limiting on forgot-password endpoint enables enumeration attacks\n推荐修复: Add rate limiter to /forgot-password endpoint similar to loginLimiter (5 attempts per 15 minutes)','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.918737');
INSERT INTO verification_checkpoints VALUES(16,'VC-16',3,48,'implemented-to-accepted',replace('req.token used in auth routes but not defined in AuthenticatedRequest type\n推荐修复: Extend Request type to include req.token or use extractToken() from jwt.ts module to get the token for blacklisting','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.919085');
INSERT INTO verification_checkpoints VALUES(17,'VC-17',3,50,'implemented-to-accepted',replace('Mobile app has 301 lint errors and 31 warnings preventing CI pass\n推荐修复: Fix lint errors before merging. Common issues: @typescript-eslint/no-unused-vars and @typescript-eslint/no-explicit-any','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.919410');
INSERT INTO verification_checkpoints VALUES(18,'VC-18',3,51,'implemented-to-accepted',replace('OAuth exchange codes stored in in-memory Map, lost on server restart\n推荐修复: Store exchange codes in Redis or database with TTL for persistence across restarts','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 09:49:07.919677');
INSERT INTO verification_checkpoints VALUES(19,'VC-19',4,63,'implemented-to-accepted',replace('用户注册端点缺失 - authService.registerUser 无路由可达\n推荐修复: 在 routes/v1/auth.ts 中添加 POST /register 端点调用 authService.registerUser()，或确认注册逻辑已迁移到其他位置。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.947025',16,'2026-04-20 09:52:30.259745');
INSERT INTO verification_checkpoints VALUES(20,'VC-20',4,64,'implemented-to-accepted',replace('密码重置端点缺失 - requestPasswordReset 和 resetPassword 无路由\n推荐修复: 在 routes/v1/auth.ts 中添加 POST /forgot-password 和 POST /reset-password 端点。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.947463',16,'2026-04-20 09:52:30.260226');
INSERT INTO verification_checkpoints VALUES(21,'VC-21',4,65,'implemented-to-accepted',replace('登录锁定机制使用内存存储，多实例部署时无法共享状态\n推荐修复: 将登录锁定状态持久化到数据库（prisma），或使用 Redis 等共享存储。在 schema 中添加 LoginAttempt 表记录 userId、attemptCount、lockedUntil。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.947698',16,'2026-04-20 09:52:30.260572');
INSERT INTO verification_checkpoints VALUES(22,'VC-22',4,66,'implemented-to-accepted',replace('验收标准与实现内容严重不匹配\n推荐修复: 重新评估 ISSUE-A002 的范围：为 JWT 认证创建新的 AC，或将当前 AC 重新分配给正确的 Issue。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.947923',16,'2026-04-20 09:52:30.260887');
INSERT INTO verification_checkpoints VALUES(23,'VC-23',4,67,'implemented-to-accepted',replace('auth/routes.test.ts 缺少成功登录的测试用例\n推荐修复: 添加测试用例：用正确密码 mock 登录，验证返回 200 状态码及 tokens.accessToken、tokens.refreshToken 字段存在且非空。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.948134',16,'2026-04-20 09:52:30.261203');
INSERT INTO verification_checkpoints VALUES(24,'VC-24',4,68,'implemented-to-accepted',replace('authService.test.ts 缺少 loginUser 函数测试\n推荐修复: 添加 loginUser 的单元测试，覆盖：成功登录返回 tokens、失败密码递增计数、超过5次触发锁定、验证码登录流程。','\n',char(10)),'resolved',NULL,'2026-04-20 10:22:50.948349',16,'2026-04-20 09:52:30.261475');
INSERT INTO verification_checkpoints VALUES(25,'VC-25',10,69,'implemented-to-accepted',replace('AC与实现严重不匹配：所有4个AC均未在代码中实现。Issue自称''核心框架''，实际实现了NLP提取→L2映射→验证流程，但AC描述的功能来自其他父Issue（AS-VS-002、AS-DATE-001），与核心框架实现无关。\n推荐修复: 重新评估：要么更新AC以匹配核心框架实际提供的能力（实体提取、意图分类、L2映射、验证），要么将当前实现作为依赖库，明确哪些AC在下游实现。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:00:20.468634');
INSERT INTO verification_checkpoints VALUES(26,'VC-26',7,53,'implemented-to-accepted',replace('ValidationError instanceof check fails - 8 validation tests fail due to prototype chain issue\n推荐修复: The Object.setPrototypeOf(this, ValidationError.prototype) call in ValidationError constructor does not properly set the prototype chain in transpiled code. Fix by ensuring proper class inheritance setup or use a different approach.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.184336',21,'2026-04-20 10:02:12.548616');
INSERT INTO verification_checkpoints VALUES(27,'VC-27',7,54,'implemented-to-accepted',replace('XSS regex detection has global flag state bug - detection fails on repeated calls\n推荐修复: Use RegExp.prototype[Symbol.match]() instead of test(), or clone patterns with new RegExp(pattern.source, pattern.flags.replace(''g'', '''')), or use pattern.source to create fresh RegExp for each check.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.184913',21,'2026-04-20 10:02:12.549155');
INSERT INTO verification_checkpoints VALUES(28,'VC-28',7,55,'implemented-to-accepted',replace('SQL injection detection patterns have multiple bypasses\n推荐修复: Add patterns for backtick-quoted injection, double-dash comments (--), subqueries, and Prisma ORM operators. Consider using parameterized queries as primary defense instead of pattern matching.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.185196',21,'2026-04-20 10:02:12.549539');
INSERT INTO verification_checkpoints VALUES(29,'VC-29',7,56,'implemented-to-accepted',replace('sanitizeString() function has multiple XSS bypass vulnerabilities\n推荐修复: sanitizeString only removes < and > but leaves event handlers intact. Need to: 1) Use DOMPurify or similar, 2) Remove all event handler patterns, 3) Normalize unicode/whitespace','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.185441',21,'2026-04-20 10:02:12.549897');
INSERT INTO verification_checkpoints VALUES(30,'VC-30',7,57,'implemented-to-accepted',replace('l2Validation test suite fails to run - L2FieldType import returns undefined\n推荐修复: Verify @bridgeai/shared package is properly built and linked. Check exports chain: schemas/l2/types.ts -> schemas/l2/index.ts -> types.ts -> index.ts. The L2FieldType enum exists in source but is not being exported in the built declaration file.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.185667',21,'2026-04-20 10:02:12.550245');
INSERT INTO verification_checkpoints VALUES(31,'VC-31',7,58,'implemented-to-accepted',replace('Image security test for sensitive content detection fails - returns 0 violations\n推荐修复: Verify the AI image analysis service is properly mocked in tests, or implement the actual content detection integration.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.185900',21,'2026-04-20 10:02:12.550583');
INSERT INTO verification_checkpoints VALUES(32,'VC-32',7,59,'implemented-to-accepted',replace('17 routes handle POST/PUT/PATCH requests without input validation\n推荐修复: Add validation middleware to all routes that accept user input. Create corresponding Zod schemas in src/schemas/ for each route.','\n',char(10)),'resolved',NULL,'2026-04-20 10:16:17.186125',21,'2026-04-20 10:02:12.550880');
INSERT INTO verification_checkpoints VALUES(33,'VC-33',11,72,'implemented-to-accepted',replace('AgentDate/AgentJob/AgentAd canHandle 场景检测全部失败 - 关键词匹配阈值过高\n推荐修复: 方案1: 降低 canHandle 置信度阈值从 0.3 降到 0.15，使 1-2 个关键词匹配即可通过。方案2: 在 detectionKeywords 中为每个场景增加 2-3 个高权重核心关键词（如 AgentDate 增加 ''相亲''、''约会''，AgentJob 增加 ''工作''、''招聘''，AgentAd 增加 ''买''、''购买''），降低阈值到 0.15。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.663909',23,'2026-04-20 10:02:39.940792');
INSERT INTO verification_checkpoints VALUES(34,'VC-34',11,73,'implemented-to-accepted',replace('VisionShareExtractor 位置信息提取失败 - 无法解析中文地址和室内外偏好\n推荐修复: 实现 extractLocation 方法：1) 添加 city 提取正则，匹配 ''XX市''/''XX区''/''XX县'' 等行政区划后缀；2) 添加 indoor/outdoor 关键词检测（''摄影棚''/''室内'' → indoor=true, ''外景''/''户外'' → indoor=false）。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.664398',23,'2026-04-20 10:02:39.941287');
INSERT INTO verification_checkpoints VALUES(35,'VC-35',11,74,'implemented-to-accepted',replace('VisionShareExtractor 验证逻辑失效 - 不完整数据被标记为 valid=true\n推荐修复: 检查 VisionShareExtractor.validate() 实现，确保 requiredFields 中 photographyType 为必填，缺失时返回 valid=false 和 missingFields 列表。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.664649',23,'2026-04-20 10:02:39.941652');
INSERT INTO verification_checkpoints VALUES(36,'VC-36',11,75,'implemented-to-accepted',replace('AgentJobExtractor 薪资提取未实现\n推荐修复: 实现 extractSalaryExpectation 方法，添加正则匹配 ''XXK-XXK''、''XXk-XXk''、''XX元/xx''、''XX元/月'' 等格式，转换为 min/max/period 结构化数据。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.664877',23,'2026-04-20 10:02:39.942005');
INSERT INTO verification_checkpoints VALUES(37,'VC-37',11,76,'implemented-to-accepted',replace('AgentJobExtractor 福利提取精度不足 - 返回 ''年假'' 而非 ''带薪年假''\n推荐修复: 修复 extractBenefits 中对 ''带薪年假'' 的整体匹配，应优先匹配完整短语再考虑部分匹配，或在 benefits 列表中对 ''年假'' 做上下文判断。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.665083',23,'2026-04-20 10:02:39.942334');
INSERT INTO verification_checkpoints VALUES(38,'VC-38',11,77,'implemented-to-accepted',replace('AgentAdExtractor 紧急程度判断逻辑反转\n推荐修复: 在 AgentAdExtractor.extractUrgency() 中添加负面紧迫性关键词检测：''不急''/''慢慢''/''不着急''/''以后再说'' → urgency=''low''，优先级高于正面紧迫性关键词。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.665302',23,'2026-04-20 10:02:39.942660');
INSERT INTO verification_checkpoints VALUES(39,'VC-39',11,78,'implemented-to-accepted',replace('澄清问题生成返回通用回退文本而非具体问题\n推荐修复: AgentDateExtractor.getClarificationQuestion() 中添加 ''partnerCriteria'' → ''请问您对理想伴侣有什么要求？'' 映射，使其与 ''partnerPreferences'' 区分或合并。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.665510',23,'2026-04-20 10:02:39.942976');
INSERT INTO verification_checkpoints VALUES(40,'VC-40',11,79,'implemented-to-accepted',replace('Extractor 代码中大量未使用的函数参数\n推荐修复: 将所有未使用的参数前缀改为 ''_''（如 ''_context''、''_entities''），符合项目 eslint 规则（允许 /^_/u 匹配模式）。','\n',char(10)),'resolved',NULL,'2026-04-20 10:31:09.665715',23,'2026-04-20 10:02:39.943251');
