INSERT INTO verification_checkpoints VALUES(44,'VC-44',13,80,'implemented-to-accepted',replace('Supply extraction API routes exist but are not registered in the application\n推荐修复: Add: router.use("/supply", supplyRoutes); to routes/ai/index.ts. Create and import supplyRoutes from "./supply" in routes/ai/index.ts.','\n',char(10)),'resolved',NULL,'2026-04-20 10:44:21.346374',27,'2026-04-20 10:12:12.423149');
INSERT INTO verification_checkpoints VALUES(45,'VC-45',13,82,'implemented-to-accepted',replace('Test suite fails to run: Cannot find module ../../utils/logger from supplyQualityAssessor.ts\n推荐修复: Fix the import path in supplyQualityAssessor.ts. The correct relative path from src/services/ai/assessors/ to src/utils/logger is ../../../utils/logger (3 levels up, not 2).','\n',char(10)),'resolved',NULL,'2026-04-20 10:44:21.346584',27,'2026-04-20 10:12:12.423522');
INSERT INTO verification_checkpoints VALUES(46,'VC-46',13,84,'implemented-to-accepted',replace('Unused imports in supplyQualityAssessor.ts (ESLint errors)\n推荐修复: Remove unused imports Capability, PricingInfo, QualityMetrics from line 13 of supplyQualityAssessor.ts.','\n',char(10)),'resolved',NULL,'2026-04-20 10:44:21.346790',27,'2026-04-20 10:12:12.423833');
INSERT INTO verification_checkpoints VALUES(47,'VC-47',14,86,'implemented-to-accepted',replace('SupplyExtractionService 测试失败：缺失字段处理测试未通过\n推荐修复: 修复缺失字段处理逻辑，确保 pricing 字段在缺少时被正确标记为失败','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:15:19.119751');
INSERT INTO verification_checkpoints VALUES(48,'VC-48',20,92,'implemented-to-accepted',replace('AgentAdExtractor 误判: 关键词 "找" 过于宽泛，导致 "我想找工作" 被识别为广告场景\n推荐修复: Remove "找" from detectionKeywords, or add negative filters for job-related terms. More precise: keep only "想购", "求购", "购买" instead of standalone "找".','\n',char(10)),'resolved',NULL,'2026-04-20 10:46:57.162931',34,'2026-04-20 10:28:58.882370');
INSERT INTO verification_checkpoints VALUES(49,'VC-49',20,93,'implemented-to-accepted',replace('AgentAdExtractor 产品名提取缺少后缀: "iPhone 15 Pro" 只提取到 "iPhone 15"\n推荐修复: Update pattern to: /(?:iPhone\s*(\d+(?:\s+Pro)?))/i to capture optional suffixes like "Pro".','\n',char(10)),'resolved',NULL,'2026-04-20 10:46:57.163380',34,'2026-04-20 10:28:58.882984');
INSERT INTO verification_checkpoints VALUES(50,'VC-50',20,94,'implemented-to-accepted',replace('AgentBehaviorService 垃圾内容检测失效: "BUY NOW!!! BUY NOW!!! BUY NOW!!!" 被放行\n推荐修复: Add detection for repeated phrase patterns OR lower caps threshold from 0.7 to 0.5. Also add "buy now" as prohibited content keyword.','\n',char(10)),'resolved',NULL,'2026-04-20 10:46:57.163655',34,'2026-04-20 10:28:58.883390');
INSERT INTO verification_checkpoints VALUES(51,'VC-51',20,95,'implemented-to-accepted',replace('AgentBehaviorService 违规计数逻辑缺陷: "inappropriate content" 不触发任何检测导致限制不生效\n推荐修复: Add "inappropriate" to prohibitedContent list, OR lower caps ratio threshold from 0.7 to 0.5, OR add additional spam/content violation indicators.','\n',char(10)),'resolved',NULL,'2026-04-20 10:46:57.163914',34,'2026-04-20 10:28:58.883708');
INSERT INTO verification_checkpoints VALUES(52,'VC-52',15,100,'implemented-to-accepted',replace('supplyQualityAssessor.ts has wrong logger import path, breaking all tests\n推荐修复: Change import in supplyQualityAssessor.ts from ''../../utils/logger'' to ''../../../utils/logger''','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.114644',36,'2026-04-20 10:30:24.434714');
INSERT INTO verification_checkpoints VALUES(53,'VC-53',15,101,'implemented-to-accepted',replace('AS-PROTO-001-AC-1 not implemented: NegotiationMessage does not include creditScore\n推荐修复: Add creditScore field to NegotiationMessage interface and include it in socket message emission','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.115112',36,'2026-04-20 10:30:24.435210');
INSERT INTO verification_checkpoints VALUES(54,'VC-54',15,102,'implemented-to-accepted',replace('supplyToL2Mapper.validateMapping() test fails: empty required field not detected\n推荐修复: Update validateMapping to check if field values are meaningful (non-empty strings/arrays) rather than just checking existence','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.115363',36,'2026-04-20 10:30:24.435565');
INSERT INTO verification_checkpoints VALUES(55,'VC-55',15,103,'implemented-to-accepted',replace('supplyExtractionService: empty pricing object not detected as failed field\n推荐修复: Update getFailedFields to check Object.keys(extraction.pricing || {}).length > 0 instead of just truthiness check','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.115597',36,'2026-04-20 10:30:24.435887');
INSERT INTO verification_checkpoints VALUES(56,'VC-56',15,104,'implemented-to-accepted',replace('Unused imports causing lint errors in AI service files\n推荐修复: Remove unused imports from these files','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.115832',36,'2026-04-20 10:30:24.436205');
INSERT INTO verification_checkpoints VALUES(57,'VC-57',15,105,'implemented-to-accepted',replace('clarificationService test times out due to setInterval in constructor\n推荐修复: Refactor InMemorySessionStore to not start timers in constructor, or properly mock setInterval in tests','\n',char(10)),'resolved',NULL,'2026-04-20 10:57:13.116055',36,'2026-04-20 10:30:24.436470');
INSERT INTO verification_checkpoints VALUES(58,'VC-58',4,119,'implemented-to-accepted',replace('硬编码开发验证码后门：ALLOW_DEV_VERIFICATION_CODE=true 时，任何人都可以用验证码 123456 登录\n推荐修复: 移除此开发后门代码，或确保环境变量在生产环境强制为 false。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.451291');
INSERT INTO verification_checkpoints VALUES(59,'VC-59',4,120,'implemented-to-accepted',replace('认证端点缺少严格的速率限制：auth 路由未应用 strictAuthLimiter，只使用宽松的全局 100req/15min 限制\n推荐修复: 在 auth 路由上应用 strictAuthLimiter 或自定义严格限制。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.451783');
INSERT INTO verification_checkpoints VALUES(60,'VC-60',4,121,'implemented-to-accepted',replace('JWT_SECRET 重复定义三次，authService.ts 存在遗留的独立 jwt.sign/jwt.verify 代码路径\n推荐修复: 统一使用 auth/jwt.ts 中的 generateTokens/verifyToken，废弃 authService.ts 中的直接 jwt 调用。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.452112');
INSERT INTO verification_checkpoints VALUES(61,'VC-61',4,122,'implemented-to-accepted',replace('Refresh token 过期时间配置不一致\n推荐修复: 统一使用同一个配置源和默认值。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.452412');
INSERT INTO verification_checkpoints VALUES(62,'VC-62',4,123,'implemented-to-accepted',replace('jwt.sign() 和 jwt.verify() 未指定 algorithm 选项，存在 algorithm confusion 攻击风险\n推荐修复: 在 jwt.verify() 中添加 algorithms: [''HS256'']，在 jwt.sign() 中指定 algorithm: ''HS256''。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.452720');
INSERT INTO verification_checkpoints VALUES(63,'VC-63',4,124,'implemented-to-accepted',replace('findRefreshToken() 返回包含 passwordHash 的完整用户记录，但 /refresh 路由不使用这些数据\n推荐修复: 移除 include: { user: true }，或只 select 需要的字段。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.453036');
INSERT INTO verification_checkpoints VALUES(64,'VC-64',4,125,'implemented-to-accepted',replace('auth/routes.test.ts 缺少成功登录的测试用例（NP-67 重新打开）\n推荐修复: 添加 should return user and tokens for valid credentials 测试用例。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.453332');
INSERT INTO verification_checkpoints VALUES(65,'VC-65',4,126,'implemented-to-accepted',replace('authService.test.ts 缺少 loginUser() 函数测试（NP-68 重新打开）\n推荐修复: 为 loginUser() 添加测试，覆盖成功登录、错误密码、账户锁定、验证码登录等场景。','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:37:09.453590');
INSERT INTO verification_checkpoints VALUES(66,'VC-66',11,129,'implemented-to-accepted',replace('6 unit tests failing across 4 test suites: clarificationService (1), sceneDetector (2), agentAdExtractor (2), visionShareExtractor (1)\n推荐修复: Fix all 6 test failures: (1) Update clarification test to expect completed when user answers all fields in one response; (2-3) Lower SceneDetector confidence threshold from 0.5 to 0.4 or add job keywords; (4) Narrow AgentAdExtractor detectionKeywords - remove overly generic terms; (5) Fix iPhone regex to capture Pro/Max/etc suffixes; (6) Fix city extraction to preserve 市 suffix consistently with district','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:55:22.245549');
INSERT INTO verification_checkpoints VALUES(67,'VC-67',11,130,'implemented-to-accepted',replace('InMemorySessionStore setInterval never cleared - causes Jest open handle warnings and prevents clean test exit\n推荐修复: Store the interval ID in a class property, add a destroy() method to InMemorySessionStore that calls clearInterval, and call it in test afterAll hooks. This is a resource leak that will cause problems in long-running processes too.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:55:22.246051');
INSERT INTO verification_checkpoints VALUES(68,'VC-68',11,131,'implemented-to-accepted',replace('Two duplicate BaseSceneExtractor classes with incompatible interfaces: base.ts (LLM-based) vs baseExtractor.ts (regex-based)\n推荐修复: Consolidate to one base class and one extractor per scene. Decide on LLM vs regex approach and remove the other. This duplication creates confusion about which implementation is authoritative and doubles maintenance burden.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:55:22.246420');
INSERT INTO verification_checkpoints VALUES(69,'VC-69',11,132,'implemented-to-accepted',replace('Unused import SceneSpecificExtractor in clarificationService.ts\n推荐修复: Remove the unused import on line 9 of clarificationService.ts.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:55:22.246747');
INSERT INTO verification_checkpoints VALUES(70,'VC-70',11,133,'implemented-to-accepted',replace('VisionShareExtractor city extraction strips 市 suffix but district keeps 区 suffix - inconsistent behavior\n推荐修复: Either preserve 市 suffix consistently (match user input) or strip from both city and district. Current behavior is inconsistent - city loses suffix but district keeps it.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 10:55:22.247046');
INSERT INTO verification_checkpoints VALUES(71,'VC-71',7,108,'implemented-to-accepted',replace('sanitizeString() HTML tag stripping is broken - removes individual <> chars instead of full tags. Input ''<script>alert(1)</script>'' becomes ''scriptalert(1)/script'' instead of ''alert(1)''. 3 validation tests fail.\n推荐修复: Replace /[<>]/g with /<[^>]*>/g to strip entire HTML tags, or use a proper HTML sanitization library like DOMPurify.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:00:05.059917');
INSERT INTO verification_checkpoints VALUES(72,'VC-72',7,109,'implemented-to-accepted',replace('NoSQL injection detection has global flag lastIndex bug - pattern.test() alternates true/false on repeated calls. NoSQL injection attacks succeed 50% of the time.\n推荐修复: Apply the same cloning guard used in containsXSS/containsSQLInjection: new RegExp(pattern.source, pattern.flags.replace(''g'', '''')). Or use the String.prototype.search() method which ignores lastIndex.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:00:05.060399');
INSERT INTO verification_checkpoints VALUES(73,'VC-73',7,111,'implemented-to-accepted',replace('POST /api/v1/auth/change-password route missing Zod validation middleware. No password strength validation on newPassword field.\n推荐修复: Add a changePasswordSchema to authSchemas.ts with oldPassword and newPassword fields (newPassword should match resetPasswordSchema strength requirements), and add validate({ body: changePasswordSchema }) middleware.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:00:05.060735');
INSERT INTO verification_checkpoints VALUES(74,'VC-74',7,112,'implemented-to-accepted',replace('AppError subclasses have inconsistent Object.setPrototypeOf - only ValidationError and MulterUploadError have it, other subclasses (NotFoundError, UnauthorizedError, ForbiddenError, ConflictError, RateLimitError) are missing it.\n推荐修复: Add Object.setPrototypeOf(this, ClassName.prototype) to all AppError subclasses for consistency, or move it to the base AppError constructor.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:00:05.061011');
INSERT INTO verification_checkpoints VALUES(75,'VC-75',13,136,'reviewed-to-implemented',replace('Semantic inconsistency: getExtractedFields() reports pricing:{} as extracted (truthy check on line 598), while getFailedFields() correctly detects it as failed (empty-object check on lines 617-625). Same empty pricing appears in both fieldsExtracted and fieldsFailed arrays.\n推荐修复: Align getExtractedFields with getFailedFields: also check Object.keys(extraction.pricing).length > 0 before adding to fieldsExtracted, so empty pricing is not reported as extracted.','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:02:00.949486');
INSERT INTO verification_checkpoints VALUES(76,'VC-76',15,145,'implemented-to-accepted',replace('Socket handler only includes creditScore in 1 of 5 negotiation:message emissions, violating AS-PROTO-001-AC-1 (every message must include creditScore). While agentNegotiationService.ts correctly adds creditScore to all NegotiationMessage objects, the socket handler manually picks fields and strips creditScore in: merchant submitOffer (line 178), consumer askQuestion broadcast (line 318), comparison report (line 386), and confirmation broadcast (line 519). Only the consumer introduction (line 131) includes creditScore.\n推荐修复: Add creditScore field to all 5 negotiation:message emission points in the socket handler, or refactor to spread the full message object (e.g., message: { ...msg } instead of manually picking fields).','\n',char(10)),'open',NULL,NULL,NULL,'2026-04-20 11:10:49.087365');
