INSERT INTO issues VALUES(4,'ISSUE-A002','JWT认证与API安全',replace('实现基于 JWT 的 API 认证机制，包括 Token 生成与验证、\n刷新令牌机制、Token 黑名单、API 权限控制等安全功能。\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'findings_minor','2026-04-14 15:16:10.301084','2026-04-20 12:34:43.730193');
