INSERT INTO issues VALUES(7,'ISSUE-A004','输入验证与数据校验',replace('实现统一的输入验证和数据校验机制，包括请求参数验证、\n数据格式校验、XSS 防护、SQL 注入防护等安全功能。\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,300,1,NULL,NULL,'no_findings','2026-04-14 15:16:11.384412','2026-04-20 12:34:43.731957');
