INSERT INTO issues VALUES(9,'ISSUE-AI002','需求智能提炼服务',replace('实现需求智能提炼服务，将用户自然语言描述转换为结构化的L1/L2/L3信息模型。\n该Issue已拆分为子Issue:\n- ISSUE-AI002a: 核心框架（解析引擎、结构化映射、验证系统）\n- ISSUE-AI002b: 场景提取器（VisionShare/AgentDate/AgentJob/AgentAd场景适配）\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,'no_findings','2026-04-14 15:16:12.501258','2026-04-20 09:50:12.231018');
INSERT INTO issues VALUES(10,'ISSUE-AI002a','需求智能提炼服务 - 核心框架',replace('实现需求智能提炼服务的核心框架部分，提供基础的解析引擎、\n结构化映射、验证系统和API接口，为后续场景特定提取器提供\n基础设施和扩展点。\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,9,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'findings_minor','2026-04-14 15:16:12.723668','2026-04-20 10:00:20.468790');
INSERT INTO issues VALUES(11,'ISSUE-AI002b','需求智能提炼服务 - 场景提取器实现',replace('实现需求智能提炼服务的场景特定提取器，支持VisionShare、AgentDate、\nAgentJob、AgentAd等多个业务场景的需求提取，以及需求澄清对话机制，\n处理缺失信息的多轮对话交互。\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,9,NULL,NULL,NULL,NULL,NULL,1,123,1,NULL,NULL,'findings_minor','2026-04-14 15:16:12.995221','2026-04-20 12:34:43.734141');
INSERT INTO issues VALUES(12,'ISSUE-AI003','供给智能提炼服务',replace('【已拆分】实现供给智能提炼服务，使用LLM分析服务提供者、商家、\n求职者等的自然语言描述，自动提取结构化供给信息\n(服务范围、价格、资质、时间等)，支持多场景。\n\n拆分为以下子任务:\n- ISSUE-AI003a: 核心解析引擎 + API\n- ISSUE-AI003b: 场景提取器\n- ISSUE-AI003c: 映射、补全、评估\n','\n',char(10)),'implement','nitpicking',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:13.291393','2026-04-20 10:11:36.297876');
INSERT INTO issues VALUES(13,'ISSUE-AI003a','供给智能提炼服务 - 核心解析引擎与API',replace('实现供给智能提炼服务的核心解析引擎和API端点，\n包含供给解析引擎和供给API与集成，为场景提取器提供基础能力\n','\n',char(10)),'implement','ai_confirmed',1,1,0,NULL,NULL,12,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'findings_minor','2026-04-14 15:16:13.330851','2026-04-20 11:02:00.949633');
INSERT INTO issues VALUES(14,'ISSUE-AI003b','供给智能提炼服务 - 场景提取器',replace('实现供给场景提取器，支持VisionShare摄影师、AgentJob求职者、AgentAd商家\n等多场景的供给信息提取，包含供给方资质提取和场景自动识别能力\n','\n',char(10)),'implement','ai_confirmed',0,1,0,NULL,NULL,12,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'findings_minor','2026-04-14 15:16:13.634798','2026-04-20 11:04:49.504843');
INSERT INTO issues VALUES(15,'ISSUE-AI003c','供给智能提炼服务 - 映射、补全与评估',replace('实现供给结构化映射、信息补全和质量评估功能，\n包含供给到L2模型的映射、智能补全建议和质量评估系统\n','\n',char(10)),'implement','fixing',0,1,0,49,NULL,12,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:13.915470','2026-04-20 11:10:49.090019');
INSERT INTO issues VALUES(16,'ISSUE-AI004','Agent对话生成服务',replace('实现Agent对话生成服务，为AI Agent提供智能对话能力，\n支持Agent间的自主沟通、协商、匹配对话，以及Agent与用户\n的交互对话，具备上下文记忆和个性化回复能力。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:14.141127','2026-04-20 09:49:14.738026');
INSERT INTO issues VALUES(17,'ISSUE-AI005','图像分析与Vision API',replace('实现图像分析与Vision API服务，集成多模态大语言模型，\n提供图像理解、内容审核、OCR文字识别、场景分析等能力，\n支持VisionShare场景的照片分析和AI相册检索。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:14.765294','2026-04-20 09:49:14.738475');
INSERT INTO issues VALUES(18,'ISSUE-AI006','AI服务降级与容错策略',replace('实现AI服务降级与容错策略，在LLM服务不可用或响应过慢时\n提供优雅的降级方案，包括缓存回退、简化模型、预设回复、\n异步队列等机制，确保系统核心功能可用性。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:15.378303','2026-04-20 09:49:14.739029');
INSERT INTO issues VALUES(19,'ISSUE-API001','API文档与OpenAPI规范',replace('建立完整的API文档体系，使用OpenAPI 3.0规范描述所有后端接口。\n包括自动生成API文档、请求/响应示例、接口版本管理、API测试工具集成等。\n为前端开发、E2E测试和第三方集成提供完整的API参考文档。\n\n**核心目标**:\n- 100% API接口OpenAPI规范覆盖\n- 自动化文档生成和发布\n- API版本管理和兼容性文档\n- 与E2E测试框架集成\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:15.798456','2026-04-20 10:39:44.010638');
