INSERT INTO issues VALUES(21,'ISSUE-C002','Agent信息模型系统',replace('实现 Agent 三层信息模型系统，为Agent提供完整的信息表达能力。\n该Issue已拆分为子Issue:\n- ISSUE-C002a: L1基础信息模型（年龄、性别、地域等基础字段）\n- ISSUE-C002b: L2结构化信息模型（场景特定的结构化属性）\n- ISSUE-C002c: L3自然语言信息模型（自由文本描述和多媒体）\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:17.042642','2026-04-20 10:14:36.380858');
