INSERT INTO issues VALUES(32,'ISSUE-COM002','聊天房间系统',replace('实现聊天房间系统，支持私聊、群聊和消息管理。\n该Issue已拆分为子Issue:\n- ISSUE-COM002a: 聊天房间基础架构（房间创建、成员管理、消息路由）\n- ISSUE-COM002b: 消息持久化与历史记录（消息存储、查询、分页）\n- ISSUE-COM002c: 群聊状态同步与在线状态（已读回执、在线状态、打字指示）\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,'scope_too_large',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:22.754294','2026-04-20 12:34:43.740327');
