INSERT INTO issues VALUES(34,'ISSUE-CR001','信用分计算系统',replace('实现用户信用分计算系统，包括信用分模型设计、多维度评分算法、\n信用等级划分、信用分历史追踪、以及信用分的实时更新机制。\n信用分是平台信任体系的核心，影响用户的匹配优先级、交易权限和场景准入。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,'2026-04-14 15:16:24.097039','2026-04-20 09:41:12.887494');
INSERT INTO issues VALUES(35,'ISSUE-CR002','评分与评价系统',replace('实现用户评分与评价系统，包括双向评分机制、评价内容管理、\n评价审核与反作弊、评价统计与展示。评价系统与信用分计算联动，\n为平台提供可信的用户反馈机制。\n\n本Issue已拆分为以下子Issue：\n- ISSUE-CR002a: 后端API (c1, c2, c3) ~900行\n- ISSUE-CR002b: 前端UI (c4) ~500行\n- ISSUE-CR002c: 业务逻辑 (c5, c6) ~450行\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:24.764798','2026-04-18 18:16:41.535590');
INSERT INTO issues VALUES(36,'ISSUE-CR002a','评分与评价系统 - 后端API',replace('实现评分与评价系统的后端API部分，包括数据模型设计和核心API接口。\n提供评价的提交、查询、回复、删除等基础功能，以及评价审核与反作弊机制。\n本Issue是ISSUE-CR002的拆分部分，专注于后端实现。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,35,NULL,NULL,NULL,NULL,900,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.027935','2026-04-20 09:41:12.891361');
