INSERT INTO issues VALUES(38,'ISSUE-CR002c','评分与评价系统 - 业务逻辑',replace('实现评分与评价系统的业务逻辑部分，包括评价与信用分联动机制、\n评价相关的通知与提醒功能。本Issue是ISSUE-CR002的拆分部分，专注于业务逻辑实现。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,35,NULL,NULL,NULL,NULL,450,1,300,1,NULL,NULL,NULL,'2026-04-14 15:16:25.488338','2026-04-19 10:38:06.132662');
INSERT INTO issues VALUES(39,'ISSUE-CR003','积分系统基础与交易记录',replace('实现平台积分系统，包括积分账户管理、积分获取与消耗、\n交易记录追踪、积分商城基础、以及积分在场景中的应用(如VisionShare照片购买)。\n积分作为平台内流通的虚拟货币，支持平台经济生态。\n\n注意: 本Issue已拆分为子Issue，详见 sub_issues 列表。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.775927','2026-04-20 09:41:12.893073');
INSERT INTO issues VALUES(40,'ISSUE-CR003a','积分账户数据模型',replace('积分系统数据库设计与基础数据模型实现。\n包括积分账户、交易记录、冻结记录等核心数据表设计。\n作为积分系统的数据层基础，为上层服务提供数据支撑。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,39,NULL,NULL,NULL,NULL,150,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.817900','2026-04-20 09:41:12.893558');
INSERT INTO issues VALUES(41,'ISSUE-CR003c','积分交易记录API',replace('积分交易记录查询API实现，包括余额查询、交易记录列表、交易详情、积分统计等功能。\n作为积分系统的API层，为客户端提供积分数据访问接口。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,39,NULL,NULL,'environment_failed',NULL,200,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.840516','2026-04-19 10:52:29.024600');
INSERT INTO issues VALUES(42,'ISSUE-CR003d','积分钱包UI与VisionShare场景支付',replace('积分钱包移动端UI实现，以及VisionShare场景下的积分支付功能。\n包括积分钱包界面、交易记录展示、照片购买积分支付等应用层功能。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,39,NULL,NULL,NULL,NULL,300,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.855446','2026-04-18 22:23:24.169227');
INSERT INTO issues VALUES(43,'ISSUE-DATE001','交友画像配置 - AI智能提炼服务',replace('实现AgentDate交友场景的AI智能提炼服务。\n将用户的自然语言描述转化为结构化交友需求，支持从自我介绍中提取关键信息。\n\n拆分来源: ISSUE-DATE001\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'environment_failed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:25.866842','2026-04-18 22:40:13.663701');
INSERT INTO issues VALUES(44,'ISSUE-DATE002','Agent主动匹配推荐',replace('实现AgentDate场景的Agent主动匹配推荐系统。系统根据用户的交友画像，\n自动筛选匹配对象，由用户的Agent主动发起对话，经过初步交流后向用户推荐合适的交友对象。\n支持匹配度算法、个性化推荐排序、每日推荐推送等功能。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'design_flawed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:26.929920','2026-04-19 10:27:03.653922');
INSERT INTO issues VALUES(45,'ISSUE-DATE003','Agent间对话匹配',replace('实现AgentDate场景的Agent间对话匹配系统。双方Agent在隔离环境中进行多轮对话，\n了解彼此、验证匹配度、挖掘共同话题。对话结束后生成对话摘要和匹配评估报告，\n供用户决定是否同意进一步交流。支持人设一致性维护、话题深度控制、对话质量评估。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,'2026-04-14 15:16:27.659446','2026-04-18 19:35:30.767414');
INSERT INTO issues VALUES(46,'ISSUE-DESIGN-1','项目初始化 - 创建 Specs',replace('通过与用户的多轮交流，将项目想法转化为结构化的规格文档。\n包含 CONCEPTS.md, PROJECT.md, TECH_STACK.md, ARCHITECTURE.md, USER_STORIES.md。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:28.140296','2026-04-18 20:17:55.614846');
INSERT INTO issues VALUES(47,'ISSUE-DESIGN-2','生成并完善 IssueTree',replace('基于 specs 文档，通过多轮评审完善 IssueTree.md。\n确定所有 features、components、modules 及其依赖关系。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:28.384236','2026-04-18 20:18:03.075290');
INSERT INTO issues VALUES(48,'ISSUE-F001','项目初始化与开发环境搭建',replace('初始化 BridgeAI Agent通信平台项目，搭建完整的开发环境。\n包括 monorepo 结构设置、TypeScript 配置、代码规范工具配置、\nGit 工作流设置以及开发文档模板。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'design_flawed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:29.269835','2026-04-19 10:50:37.460262');
INSERT INTO issues VALUES(49,'ISSUE-F002','数据库设计与Prisma ORM搭建',replace('设计 BridgeAI 平台的数据库 schema，配置 Prisma ORM，\n包括用户、Agent、消息、匹配、信用等核心实体的数据模型定义，\n以及数据库迁移和种子数据管理。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'design_flawed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:29.770840','2026-04-19 10:25:54.230791');
INSERT INTO issues VALUES(50,'ISSUE-F003','Express后端基础框架',replace('搭建 Express 后端服务基础框架，包括路由结构、中间件配置、\n错误处理、请求/响应标准化、API 版本控制等核心基础设施。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:30.532155','2026-04-18 22:02:00.369952');
INSERT INTO issues VALUES(51,'ISSUE-F004','Expo移动端项目初始化',replace('初始化 Expo React Native 移动端项目，配置开发环境、\n导航结构、状态管理、网络请求等基础设施，支持 iOS/Android 双平台。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'implement_incomplete',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:31.268308','2026-04-18 22:24:59.665827');
INSERT INTO issues VALUES(52,'ISSUE-F005','日志系统与结构化日志',replace('实现统一的结构化日志系统，支持日志级别控制、上下文追踪、\n多输出目标(控制台、文件、远程)，以及日志聚合和分析。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'.issuetree/worktrees/ISSUE-F005',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,0,NULL,NULL,NULL,'2026-04-14 15:16:32.108537','2026-04-19 10:50:37.503646');
INSERT INTO issues VALUES(53,'ISSUE-F006','错误追踪与监控集成',replace('集成错误追踪和监控服务(Sentry)，实现错误自动上报、\n性能监控、用户反馈收集，以及告警机制。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:32.714795','2026-04-19 10:13:13.908809');
INSERT INTO issues VALUES(54,'ISSUE-INF001','API Gateway 设计与实现',replace('设计并实现统一的 API Gateway，作为所有后端服务的入口。\n提供路由、负载均衡、认证、限流、日志聚合等功能。\n支持微服务架构下的服务发现和动态路由。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:32.914716','2026-04-20 10:39:44.023528');
INSERT INTO issues VALUES(55,'ISSUE-INF002','Redis 缓存层设计与实现',replace('设计并实现统一的 Redis 缓存层，为应用提供高性能数据缓存能力。\n支持多种缓存策略（Cache-Aside、Write-Through、Read-Through）。\n实现缓存预热、自动过期、一致性保障等机制。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:32.952942','2026-04-18 22:01:57.549280');
INSERT INTO issues VALUES(56,'ISSUE-INF003','任务队列系统设计与实现',replace('设计并实现可靠的任务队列系统，支持异步任务处理、延时任务、定时任务。\n基于 Redis/Bull 实现高可用队列，支持任务重试、死信队列、优先级控制。\n提供任务监控、进度追踪、失败告警能力。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:33.505158','2026-04-18 21:53:12.502937');
INSERT INTO issues VALUES(57,'ISSUE-INF004','数据库迁移系统',replace('建立规范的数据库迁移流程，基于 Prisma Migration 实现版本化管理。\n支持多环境迁移（开发、测试、生产）。\n实现迁移脚本审查、回滚、数据备份恢复机制。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:33.582821','2026-04-18 21:48:51.795569');
INSERT INTO issues VALUES(58,'ISSUE-INF005','推送通知服务',replace('设计并实现统一的推送通知服务，支持多平台（iOS、Android、Web）。\n集成 APNs、FCM、Web Push 等渠道。\n支持富媒体通知、分组、定时发送、用户偏好管理。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:33.607963','2026-04-20 10:13:06.622493');
INSERT INTO issues VALUES(59,'ISSUE-INF006','邮件服务系统',replace('设计并实现邮件服务系统，支持事务邮件、营销邮件、模板管理。\n集成 SMTP、SendGrid、AWS SES 等多种发送渠道。\n支持邮件追踪、退信处理、反垃圾检测。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:34.137340','2026-04-18 21:33:02.660409');
INSERT INTO issues VALUES(60,'ISSUE-INT001a','VisionShare + AgentDate E2E测试',replace('VisionShare和AgentDate两大核心场景的端到端集成测试。\n验证需求发布到接单、相机拍照与AI脱敏、照片查看与积分支付、\nAI相册智能检索、交友画像配置、Agent匹配推荐、Agent间对话匹配、\n双向同意引荐、人机切换等完整流程。\n确保用户场景模块与核心服务模块的协同工作正常。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'/Users/apple/projects/bridgeai/.issuetree/worktrees/ISSUE-INT001a',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:34.164452','2026-04-19 09:01:27.500748');
INSERT INTO issues VALUES(61,'ISSUE-INT001b','AgentJob + AgentAd E2E测试',replace('AgentJob和AgentAd两大核心场景的端到端集成测试。\n验证求职者画像与简历配置、招聘方职位发布、简历智能匹配筛选、\n薪资协商与面试安排、消费需求画像配置、商家优惠配置发布、\nAgent优惠协商谈判、一键购买与优惠码验证、多商家比价等完整流程。\n确保用户场景模块与核心服务模块的协同工作正常。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:34.881636','2026-04-19 10:58:38.058282');
INSERT INTO issues VALUES(62,'ISSUE-INT001c','跨模块集成与测试框架基础设施',replace('跨模块集成测试与测试框架基础设施验证。\n验证Auth-Core-Matching层间API契约、AI服务与核心业务模块集成、\n通信层与各场景模块消息流转、信用积分系统全链路、\nSocket.io实时通信集成，以及测试框架覆盖率报告生成。\n确保系统基础设施层与测试体系的完整性和稳定性。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'environment_failed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:35.256103','2026-04-18 21:47:33.115966');
INSERT INTO issues VALUES(63,'ISSUE-INT002','性能优化与压测',replace('[已拆分] 原Issue已按阶段拆分为子Issue。\n\n阶段目标：\n- 阶段1 (INT002a): 基础设施性能 - API响应时间P95<200ms + 数据库优化\n- 阶段2 (INT002b): 实时服务性能 - WebSocket延迟<100ms + AI服务熔断降级\n- 阶段3 (INT002c): 端到端验证 - 移动端优化 + 全链路压测(1000+并发)\n\n原描述（供参考）：\n执行系统性能优化与压力测试，确保系统在高并发场景下稳定运行。\n包括API响应时间优化、数据库查询优化、Socket.io连接性能调优、\nAI服务熔断降级策略验证、以及全链路压力测试。\n目标是支撑1000+并发用户，API响应时间P95<200ms，WebSocket延迟<100ms。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:35.265151','2026-04-18 18:43:13.980521');
INSERT INTO issues VALUES(64,'ISSUE-INT002a','基础设施性能优化',replace('执行系统基础设施层性能优化与压力测试，包括API响应时间优化和数据库查询优化。\n这是ISSUE-INT002的阶段1，专注于基础设施性能，为后续实时服务性能优化奠定基础。\n目标：API响应时间P95<200ms，数据库查询性能达到高并发要求。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,63,NULL,NULL,'environment_failed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:35.278886','2026-04-19 06:19:58.810951');
INSERT INTO issues VALUES(65,'ISSUE-INT002b','实时服务性能优化',replace('执行实时服务层性能优化与压力测试，包括WebSocket实时通信性能调优和AI服务熔断降级策略验证。\n这是ISSUE-INT002的阶段2，依赖于基础设施性能优化完成（INT002a）。\n目标：WebSocket延迟<100ms，AI服务在高负载下稳定运行并具备降级能力。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,63,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:35.753892','2026-04-18 19:29:36.369297');
INSERT INTO issues VALUES(66,'ISSUE-INT002c','端到端性能验证',replace('执行端到端性能验证，包括移动端性能测试优化和全链路压力测试。\n这是ISSUE-INT002的阶段3，依赖于实时服务性能优化完成（INT002b），\n是整个性能优化工作的最终验证阶段。\n目标：移动端体验流畅（启动<3s，滚动60fps），系统支撑1000+并发用户。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,63,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:35.771298','2026-04-18 21:24:56.664313');
INSERT INTO issues VALUES(67,'ISSUE-INT003','Demo演示准备',replace('准备产品演示环境和演示脚本，确保Demo流畅展示四大核心场景。\n包括演示数据准备、演示脚本编写、演示环境部署、故障回退方案、\n演示录制与文档准备。目标是能够在15分钟内完整展示VisionShare、\nAgentDate、AgentJob、AgentAd四大场景的核心价值。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:36.899982','2026-04-19 06:38:00.009338');
INSERT INTO issues VALUES(68,'ISSUE-JOB001','求职者画像与简历',replace('实现求职者Agent的画像配置与简历管理功能。求职者通过自然语言\n或结构化表单描述个人技能、工作经历、期望薪资等，AI提炼核心\n信息并生成标准化简历。支持简历隐私控制和定向投递。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'environment_failed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:37.570284','2026-04-18 21:35:38.963324');
INSERT INTO issues VALUES(69,'ISSUE-JOB003','简历智能匹配筛选',replace('实现求职者与招聘方的智能双向匹配系统。AI分析简历与职位\n要求的匹配度，考虑技能、经验、薪资期望等多维度因素，\n为双方推荐最合适的匹配对象。支持匹配筛选与排序。\n\n这是一个史诗级任务，包含以下子任务:\n- ISSUE-JOB003a: 核心算法层 - 匹配度算法实现\n- ISSUE-JOB003b: 服务层 - 筛选服务+推荐引擎\n- ISSUE-JOB003c: 接口层 - API+通知\n- ISSUE-JOB003d: UI层 - 移动端界面\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,6,1,NULL,NULL,NULL,'2026-04-14 15:16:37.770705','2026-04-19 10:55:04.680363');
INSERT INTO issues VALUES(70,'ISSUE-JOB003a','简历智能匹配 - 核心算法层',replace('实现职位匹配度核心算法，包括技能匹配、经验评估、\n薪资匹配等多维度计算，输出0-100的综合匹配度评分。\n预估代码量: 200-300行\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,69,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:37.784793','2026-04-19 10:54:15.704357');
INSERT INTO issues VALUES(71,'ISSUE-JOB003b','简历智能匹配 - 服务层',replace('实现AI筛选服务和双向推荐引擎，基于LLM进行简历深度分析，\n为求职者和招聘方生成智能推荐。\n预估代码量: 300-450行\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,69,NULL,NULL,'environment_failed',NULL,NULL,1,4,NULL,NULL,NULL,NULL,'2026-04-14 15:16:37.797073','2026-04-18 21:14:02.263885');
INSERT INTO issues VALUES(72,'ISSUE-JOB003c','简历智能匹配 - 接口层',replace('实现匹配查询API和匹配通知系统，支持多条件搜索、\n结果排序，以及匹配相关的推送通知。\n预估代码量: 250-350行\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,69,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:38.229725','2026-04-18 21:03:13.155413');
INSERT INTO issues VALUES(73,'ISSUE-JOB003d','简历智能匹配 - UI层',replace('实现移动端匹配展示界面，包括推荐列表、匹配详情、\n匹配度可视化展示和快速操作功能。\n预估代码量: 250-350行\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,69,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:38.448782','2026-04-18 21:00:07.120769');
INSERT INTO issues VALUES(74,'ISSUE-JOB004','薪资协商与面试安排',replace('实现Agent驱动的薪资协商与面试安排功能。当求职者与招聘方\n达成初步匹配意向后，双方Agent介入进行沟通，协商薪资细节、\n工作时间等条件，并协调安排面试时间。支持人机切换。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'/Users/apple/projects/bridgeai/.issuetree/worktrees/ISSUE-JOB004',NULL,NULL,NULL,NULL,NULL,NULL,1,4,1,NULL,NULL,NULL,'2026-04-14 15:16:38.777496','2026-04-18 21:49:30.072827');
INSERT INTO issues VALUES(75,'ISSUE-M001','匹配查询系统',replace('实现匹配查询系统，提供强大的Agent筛选和查询能力。\n该Issue已拆分为子Issue:\n- ISSUE-M001a: 查询构建器与DSL设计（查询语法、条件操作符、类型安全）\n- ISSUE-M001b: 实时查询执行引擎（查询编译、执行优化、并行查询）\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:39.329035','2026-04-19 09:00:42.307640');
INSERT INTO issues VALUES(76,'ISSUE-M001a','查询构建器与DSL设计',replace('设计并实现查询构建器和领域特定语言(DSL)，\n支持复杂的 Agent 筛选和匹配查询。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,75,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:39.653146','2026-04-19 09:15:43.806776');
INSERT INTO issues VALUES(77,'ISSUE-M001b','实时查询执行引擎',replace('实现高效的实时查询执行引擎，支持复杂的 Agent 筛选\n和实时结果更新。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,75,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:39.893120','2026-04-19 10:58:38.089855');
INSERT INTO issues VALUES(78,'ISSUE-SEC001','RBAC权限控制系统',replace('实现基于角色的访问控制(RBAC)系统，定义和管理用户角色(普通用户、管理员等)、\n权限粒度控制、资源访问策略、角色继承关系等，确保系统资源的安全访问。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,'2026-04-14 15:16:40.466195','2026-04-20 10:39:44.037702');
INSERT INTO issues VALUES(79,'ISSUE-SEC002','敏感数据加密与保护',replace('实现敏感数据的加密存储与传输保护，包括用户个人信息、聊天记录、\n支付信息等敏感字段的加密方案，密钥管理，以及数据脱敏策略。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:41.381233','2026-04-20 10:39:44.038372');
INSERT INTO issues VALUES(80,'ISSUE-SEC003','API限流与安全防护',replace('实现API限流与安全防护机制，包括请求频率限制、DDoS防护、\nIP黑名单、请求大小限制、CORS配置等，保护API服务免受滥用和攻击。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:41.597601','2026-04-19 08:41:31.268904');
INSERT INTO issues VALUES(81,'ISSUE-SEC004','图片上传安全检查',replace('实现图片上传的安全检查机制，包括文件类型验证、大小限制、\n恶意内容检测、病毒扫描、图片元数据清理等，确保上传的图片文件安全可靠。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:41.824700','2026-04-19 08:28:33.128818');
INSERT INTO issues VALUES(82,'ISSUE-SEC005','举报与内容审核系统',replace('实现用户举报系统和内容审核机制，包括举报提交、审核工作流、\n违规内容处理、用户处罚管理、申诉流程等，维护平台内容安全和秩序。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:42.390310','2026-04-19 00:41:07.560700');
INSERT INTO issues VALUES(83,'ISSUE-T001','单元测试框架搭建(Jest)',replace('搭建完整的单元测试框架，使用Jest作为测试运行器，覆盖后端服务和共享包的单元测试。\n包括测试环境配置、Mock工具、测试数据工厂、覆盖率报告等基础设施。\n确保测试可以在CI/CD流水线中自动运行。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:42.762496','2026-04-20 10:13:06.633894');
INSERT INTO issues VALUES(84,'ISSUE-T002','API集成测试框架',replace('搭建API集成测试框架，使用supertest测试HTTP端点，验证API的整体功能。\n包括测试数据库管理、请求辅助工具、认证辅助、响应验证等。\n确保API在集成层面工作正常。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:43.201929','2026-04-19 10:51:18.022524');
INSERT INTO issues VALUES(85,'ISSUE-T003','移动端测试框架',replace('搭建React Native移动端测试框架，支持组件测试、Hook测试和快照测试。\n使用Jest + React Native Testing Library进行测试，配置 Expo 测试环境。\n确保移动端代码质量和稳定性。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:43.401458','2026-04-19 10:52:15.175385');
INSERT INTO issues VALUES(86,'ISSUE-T004','E2E端到端测试框架',replace('搭建端到端(E2E)测试框架，采用Detox + Maestro双层架构。\n\n**生产层(Detox)**: 使用Detox进行稳定可靠的移动端E2E测试，覆盖完整的用户操作流程。包括测试环境配置、测试数据准备、页面对象模式、测试报告等。确保整个系统从前端到后端的完整流程正常工作。\n\n**探索层(Maestro)**: 使用YAML声明式的Maestro测试框架，专为AI Agent自动化设计。支持快速验证新功能，AI可直接生成测试脚本。验证通过后再迁移到Detox生产套件。\n\n**严格标准要求**:\n- 测试稳定性: Flaky rate < 2%\n- 执行效率: 单测试≤2分钟，全套件≤15分钟(并行)\n- 测试隔离: 100%测试独立，无状态依赖\n- 断言密度: 每流程≥5个关键断言\n- 覆盖率: 核心用户流程≥90%','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:44.160015','2026-04-19 09:01:27.502620');
INSERT INTO issues VALUES(87,'ISSUE-UI001','设计系统与组件库',replace('建立 BridgeAI 统一设计系统，包含色彩、字体、间距规范，\n以及基础UI组件库（Button、Input、Card、Modal等）。\n使用 React Native 实现跨平台一致的视觉体验。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'/Users/apple/projects/bridgeai/.issuetree/worktrees/ISSUE-UI001',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,'2026-04-14 15:16:44.587310','2026-04-18 20:03:09.957559');
INSERT INTO issues VALUES(88,'ISSUE-UI002','全局导航与布局',replace('实现应用全局导航结构和布局系统，包括底部 Tab 导航、\n侧边抽屉导航、导航状态管理、页面布局容器等。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:45.050474','2026-04-18 19:59:38.031693');
INSERT INTO issues VALUES(89,'ISSUE-UI003','首页与状态展示',replace('实现应用首页界面，包括 Agent 状态概览、匹配结果展示、\n最近活动、快捷操作入口等模块，为用户提供应用状态的总体视图。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:45.399593','2026-04-20 10:14:36.413237');
INSERT INTO issues VALUES(90,'ISSUE-UI004','聊天界面组件',replace('实现聊天界面组件，提供完整的聊天UI体验。\n该Issue已拆分为子Issue:\n- ISSUE-UI004a: 聊天消息组件与输入框（消息气泡、输入组件、发送按钮）\n- ISSUE-UI004b: Agent/人类用户状态指示器（头像、名称、在线状态）\n- ISSUE-UI004c: 聊天记录滚动与分页加载（FlatList优化、下拉加载、无限滚动）\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:45.679785','2026-04-18 19:44:37.428653');
INSERT INTO issues VALUES(91,'ISSUE-UI004a','聊天消息组件与输入框',replace('实现聊天界面核心组件，包括消息气泡、消息列表、\n输入框、表情选择器、快捷回复等，支持人机混合对话体验。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,90,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:46.004445','2026-04-18 19:28:12.693604');
INSERT INTO issues VALUES(92,'ISSUE-UI004b','Agent/人类用户状态指示器',replace('实现在聊天和列表中显示 Agent 和真人用户状态的指示器组件，\n包括在线状态、输入状态、身份标识等，增强用户对对话对象的认知。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,90,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:46.132890','2026-04-19 10:54:41.001225');
INSERT INTO issues VALUES(93,'ISSUE-UI004c','聊天记录滚动与分页加载',replace('实现聊天界面的滚动体验和消息分页加载功能，包括反向滚动加载历史消息、\n滚动位置保持、新消息提示等，确保流畅的聊天浏览体验。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,90,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:46.669401','2026-04-19 10:50:37.479151');
INSERT INTO issues VALUES(94,'ISSUE-UI005','Agent配置界面',replace('实现 Agent 的配置管理界面，包括创建向导、基础信息配置、\n场景设置、模型选择、行为规则配置等，让用户可以灵活定制自己的 Agent。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:47.017862','2026-04-20 10:14:36.415530');
INSERT INTO issues VALUES(95,'ISSUE-UI006','消息中心',replace('实现应用消息中心界面，包括系统通知、聊天会话列表、\n消息搜索、会话管理等功能，集中管理用户的所有消息和通知。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:47.391689','2026-04-19 09:01:27.495476');
INSERT INTO issues VALUES(96,'ISSUE-UI007','个人中心与信用展示',replace('实现用户个人中心界面，包括个人资料管理、信用分展示、\n积分账户、活动历史、设置等功能，展示用户的平台身份和信誉。\n','\n',char(10)),'implement','accepted',1,1,0,NULL,NULL,NULL,NULL,NULL,'design_flawed',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:47.766037','2026-04-20 09:41:12.928172');
INSERT INTO issues VALUES(97,'ISSUE-VS002','附近任务查询与接单',replace('实现VisionShare场景的附近任务查询和接单功能。供给方可以基于地理位置\n查看附近的需求任务，使用匹配引擎的推送通知获取推荐任务，并可以\n接受或拒绝任务邀请。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'/Users/apple/projects/bridgeai/.issuetree/worktrees/ISSUE-VS002/.issuetree/worktrees/ISSUE-VS002',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,'2026-04-14 15:16:47.976544','2026-04-19 09:01:27.503188');
INSERT INTO issues VALUES(98,'ISSUE-VS003','相机拍照与上传',replace('实现VisionShare场景的相机拍照和照片上传功能。接单用户通过相机拍摄实时照片，\n支持拍照预览、照片编辑、批量上传等功能。集成图片安全检查，\n确保上传内容符合规范。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,120,1,NULL,NULL,NULL,'2026-04-14 15:16:48.524676','2026-04-19 09:01:27.494961');
INSERT INTO issues VALUES(99,'ISSUE-VS004','AI隐私脱敏处理',replace('实现VisionShare场景的AI隐私脱敏处理功能。使用AI图像分析和Vision API\n自动识别照片中的敏感信息(人脸、车牌、地址标识等)，并提供智能脱敏处理选项，\n包括模糊、马赛克、区域替换等方式，保护用户隐私。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,'.issuetree/worktrees/ISSUE-VS004',NULL,NULL,NULL,NULL,NULL,NULL,1,0,1,NULL,NULL,NULL,'2026-04-14 15:16:48.955497','2026-04-18 20:01:45.746577');
INSERT INTO issues VALUES(100,'ISSUE-VS005a','照片浏览与画廊展示',replace('实现VisionShare场景的照片浏览和画廊展示功能。\n需求方可以浏览供给方上传的照片，查看缩略图网格、大图预览、图片信息等。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,'dependency_blocked',NULL,400,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:48.980527','2026-04-19 10:50:37.416200');
INSERT INTO issues VALUES(101,'ISSUE-VS005b','积分支付与高清解锁',replace('实现VisionShare场景的积分支付核心功能和高清原图解锁机制。\n支持单图/多图支付、支付确认、支付后自动解锁高清原图下载。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,500,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:48.993822','2026-04-19 09:01:27.493720');
INSERT INTO issues VALUES(102,'ISSUE-VS005c','交易记录与退款申诉',replace('实现VisionShare场景的交易记录管理和退款申诉功能。\n用户可以查看支付历史、交易详情，并在需要时发起退款申请和申诉。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,400,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:49.263891','2026-04-19 06:39:03.944948');
INSERT INTO issues VALUES(103,'ISSUE-VS005d','支付安全与风控',replace('实现VisionShare场景的支付安全和风控系统。\n包括支付行为风控检测、异常交易预警、支付限额控制等安全功能。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,350,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:49.280020','2026-04-19 06:38:26.475352');
INSERT INTO issues VALUES(104,'ISSUE-VS007','本地相册AI智能检索',replace('实现VisionShare场景的本地相册AI智能检索功能。扩展AI相册搜索能力到用户设备本地相册，\n在保护隐私的前提下，对本地照片进行AI分析和索引，支持自然语言搜索本地照片，\n实现云端和本地照片的统一检索体验。\n','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-14 15:16:49.667264','2026-04-19 06:38:26.455117');
INSERT INTO issues VALUES(106,'ISSUE-A003b','用户资料管理 - 移动端 API Client 层',replace('在移动端封装统一的用户资料 API 调用层，依赖后端 ISSUE-A003a 的接口。\n\n目标：给 A003c（移动端 UI）提供稳定的数据访问接口。\n\n实现内容：\n- 创建 apps/mobile/src/api/user/ 目录结构\n- 封装 userService 相关 API：\n  - GET/PUT /api/v1/users/me（用户资料读写）\n  - POST /api/v1/users/avatar（头像上传）\n  - POST/PUT /api/v1/users/privacy（隐私设置读写）\n  - POST /api/v1/users/password（修改密码）\n  - POST /api/v1/users/phone（手机绑定）\n  - POST /api/v1/users/email（邮箱绑定）\n  - GET/DELETE /api/v1/users/devices（设备管理）\n  - GET/POST/DELETE /api/v1/users/block（黑名单管理）\n- 统一错误处理、Loading 状态、TypeScript 类型定义\n- 依赖 apps/server/src/routes/users.ts、userPrivacy.ts 中的接口（已在 A003a 实现）\n\n技术栈：TypeScript、Fetch/axios、统一类型定义\n\n验收标准：\n- [ ] 所有用户资料相关 API 均有封装函数\n- [ ] TypeScript 类型与后端接口字段一致\n- [ ] 错误处理统一（网络错误、业务错误分类）\n- [ ] A003c 可直接调用本层 API 完成 UI 对接','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-18 12:18:20','2026-04-20 11:04:49.539293');
INSERT INTO issues VALUES(107,'ISSUE-A003c','用户资料管理 - 移动端 UI 对接',replace('将移动端所有设置页面的 stub/TODO 替换为真实 API 调用，依赖移动端 API Client 层（ISSUE-A003b）。\n\n目标：用户可在 App 内完成完整的个人资料管理。\n\n实现内容（按页面）：\n- EditProfileScreen：头像上传替换 stub、基本信息编辑\n- SecuritySettingsScreen：密码修改、手机绑定、邮箱绑定、登录设备管理、删除账号\n- PrivacySettingsScreen：隐私设置读写、阻止用户列表、添加/移除黑名单\n- DisclosureSettings：信息披露设置（对接 Agent 相关披露规则）\n\n技术栈：React Native、Zustand/React Query、依赖 A003b 的 API 封装层\n\n验收标准：\n- [ ] EditProfileScreen 头像上传正常（选图 → 上传 → 预览）\n- [ ] SecuritySettingsScreen 所有功能正常（密码/手机/邮箱/设备/注销）\n- [ ] PrivacySettingsScreen 隐私设置和黑名单功能正常\n- [ ] DisclosureSettings 信息披露设置正常\n- [ ] 所有页面无 stub、无 TODO','\n',char(10)),'implement','accepted',0,1,0,NULL,NULL,5,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2026-04-18 12:18:30','2026-04-19 06:38:00.021552');
