PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE stories (
	id INTEGER NOT NULL, 
	slug VARCHAR NOT NULL, 
	story_type VARCHAR NOT NULL, 
	title VARCHAR NOT NULL, 
	narrative TEXT, 
	description TEXT, 
	technical_notes TEXT, 
	priority INTEGER, 
	parent_id INTEGER, 
	status VARCHAR NOT NULL, 
	source_file VARCHAR, 
	created_at DATETIME NOT NULL, 
	updated_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_stories_story_type CHECK (story_type IN ('user', 'agent')), 
	CONSTRAINT ck_stories_priority CHECK (priority IN (0, 1, 2, 3)), 
	CONSTRAINT ck_stories_status CHECK (status IN ('active', 'completed', 'cancelled')), 
	UNIQUE (slug), 
	FOREIGN KEY(parent_id) REFERENCES stories (id) ON DELETE SET NULL
);
CREATE TABLE state_changes (
	id INTEGER NOT NULL, 
	entity_type VARCHAR NOT NULL, 
	entity_id INTEGER NOT NULL, 
	field VARCHAR NOT NULL, 
	old_value TEXT, 
	new_value TEXT, 
	changed_by VARCHAR NOT NULL, 
	session_id VARCHAR, 
	metadata TEXT, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_state_changes_entity_type CHECK (entity_type IN ('issue', 'task'))
);
CREATE TABLE acceptance_criteria (
	id INTEGER NOT NULL, 
	slug VARCHAR NOT NULL, 
	story_id INTEGER, 
	description TEXT NOT NULL, 
	criteria_type VARCHAR NOT NULL, 
	verification_method TEXT, 
	priority INTEGER NOT NULL, 
	coverage_ai VARCHAR, 
	coverage_e2e VARCHAR, 
	coverage_integration VARCHAR, 
	coverage_manual VARCHAR, 
	coverage_unit VARCHAR, 
	ai_status VARCHAR NOT NULL, 
	human_status VARCHAR NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_ac_criteria_type CHECK (criteria_type IN ('functional', 'edge_case', 'performance', 'security')), 
	CONSTRAINT ck_ac_ai_status CHECK (ai_status IN ('pending', 'passed', 'failed')), 
	CONSTRAINT ck_ac_human_status CHECK (human_status IN ('pending', 'passed', 'failed')), 
	UNIQUE (slug), 
	FOREIGN KEY(story_id) REFERENCES stories (id) ON DELETE CASCADE
);
CREATE TABLE issue_prerequisites (
	issue_id INTEGER NOT NULL, 
	prereq_id INTEGER NOT NULL, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (issue_id, prereq_id), 
	CONSTRAINT ck_no_self_dependency CHECK (issue_id != prereq_id), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(prereq_id) REFERENCES issues (id) ON DELETE CASCADE
);
CREATE TABLE issue_story_mapping (
	issue_id INTEGER NOT NULL, 
	story_id INTEGER NOT NULL, 
	PRIMARY KEY (issue_id, story_id), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(story_id) REFERENCES stories (id) ON DELETE CASCADE
);
CREATE TABLE tasks (
	id INTEGER NOT NULL, 
	slug VARCHAR NOT NULL, 
	issue_id INTEGER NOT NULL, 
	type VARCHAR NOT NULL, 
	status VARCHAR NOT NULL, 
	result_passed BOOLEAN, 
	result_summary TEXT, 
	error_message TEXT, 
	session_info TEXT, 
	started_at DATETIME, 
	completed_at DATETIME, 
	timeout_minutes INTEGER NOT NULL, 
	retry_attempt INTEGER NOT NULL, 
	previous_task_id INTEGER, 
	description TEXT, 
	prompt TEXT, 
	execution_time_minutes INTEGER, 
	notes TEXT, 
	context_files TEXT, 
	time_limit_minutes INTEGER, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_tasks_type CHECK (type IN ('review', 'implement', 'accept', 'investigate', 'split', 'fix', 'nitpick', 'arbitrate')), 
	CONSTRAINT ck_tasks_status CHECK (status IN ('queued', 'running', 'completed', 'failed', 'timeout')), 
	UNIQUE (slug), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(previous_task_id) REFERENCES tasks (id) ON DELETE SET NULL
);
CREATE TABLE issue_acceptance_criteria (
	issue_id INTEGER NOT NULL, 
	ac_id INTEGER NOT NULL, 
	status VARCHAR NOT NULL, 
	verified_at DATETIME, 
	notes TEXT, 
	PRIMARY KEY (issue_id, ac_id), 
	CONSTRAINT ck_iac_status CHECK (status IN ('pending', 'verified', 'failed')), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(ac_id) REFERENCES acceptance_criteria (id) ON DELETE CASCADE
);
CREATE TABLE nitpick_findings (
	id INTEGER NOT NULL, 
	slug VARCHAR NOT NULL, 
	issue_id INTEGER NOT NULL, 
	task_id INTEGER NOT NULL, 
	transition VARCHAR NOT NULL, 
	category VARCHAR NOT NULL, 
	severity VARCHAR NOT NULL, 
	description TEXT NOT NULL, 
	evidence TEXT, 
	recommendation TEXT, 
	file_path VARCHAR, 
	line_range VARCHAR, 
	status VARCHAR NOT NULL, 
	disposition VARCHAR, 
	related_ac_id INTEGER, 
	duplicate_of INTEGER, 
	created_at DATETIME NOT NULL, 
	resolved_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_nitpick_transition CHECK (transition IN ('draft-to-reviewed', 'reviewed-to-implemented', 'implemented-to-accepted')), 
	CONSTRAINT ck_nitpick_category CHECK (category IN ('ac_quality', 'requirement', 'code_quality', 'test_coverage', 'verification', 'consistency', 'runtime_behavior')), 
	CONSTRAINT ck_nitpick_severity CHECK (severity IN ('critical', 'warning', 'info')), 
	CONSTRAINT ck_nitpick_disposition CHECK (disposition IS NULL OR disposition IN ('become_ac', 'become_issue', 'become_subissue', 'fix_inline')), 
	UNIQUE (slug), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(task_id) REFERENCES tasks (id) ON DELETE CASCADE, 
	FOREIGN KEY(related_ac_id) REFERENCES acceptance_criteria (id) ON DELETE SET NULL, 
	FOREIGN KEY(duplicate_of) REFERENCES nitpick_findings (id) ON DELETE SET NULL
, CONSTRAINT ck_nitpick_status CHECK (status IN ('open', 'adopted', 'dismissed', 'duplicate', 'resolved')));
CREATE TABLE verification_checkpoints (
	id INTEGER NOT NULL, 
	slug VARCHAR NOT NULL, 
	issue_id INTEGER NOT NULL, 
	finding_id INTEGER, 
	transition VARCHAR NOT NULL, 
	description TEXT NOT NULL, 
	status VARCHAR NOT NULL, 
	promoted_to_ac_id INTEGER, 
	resolved_at DATETIME, 
	resolved_by_task_id INTEGER, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_checkpoint_transition CHECK (transition IN ('draft-to-reviewed', 'reviewed-to-implemented', 'implemented-to-accepted')), 
	CONSTRAINT ck_checkpoint_status CHECK (status IN ('open', 'resolved', 'superseded')), 
	UNIQUE (slug), 
	FOREIGN KEY(issue_id) REFERENCES issues (id) ON DELETE CASCADE, 
	FOREIGN KEY(finding_id) REFERENCES nitpick_findings (id) ON DELETE SET NULL, 
	FOREIGN KEY(promoted_to_ac_id) REFERENCES acceptance_criteria (id) ON DELETE SET NULL, 
	FOREIGN KEY(resolved_by_task_id) REFERENCES tasks (id) ON DELETE SET NULL
);
CREATE TABLE issues (
    id INTEGER NOT NULL,
    slug VARCHAR NOT NULL,
    title VARCHAR NOT NULL,
    description TEXT NOT NULL,
    issue_type VARCHAR NOT NULL,
    status VARCHAR NOT NULL,
    is_blocked BOOLEAN NOT NULL,
    priority INTEGER NOT NULL,
    failure_count INTEGER NOT NULL,
    current_task_id INTEGER,
    worktree_path VARCHAR,
    parent_issue_id INTEGER,
    stuck_previous_status VARCHAR,
    stuck_reason VARCHAR,
    investigation_result VARCHAR,
    stuck_at DATETIME,
    estimated_lines INTEGER,
    test_passed BOOLEAN,
    test_duration_seconds INTEGER,
    merged_to_master BOOLEAN,
    human_accepted BOOLEAN,
    human_accepted_at DATETIME,
    nitpick_result VARCHAR,
    created_at DATETIME NOT NULL,
    updated_at DATETIME NOT NULL,
    PRIMARY KEY (id),
    UNIQUE (slug),
    CHECK (issue_type IN ('implement', 'fix')),
    CHECK (status IN ('draft', 'reviewing', 'reviewed', 'implementing', 'implemented',
                      'accepting', 'accepted', 'nitpicking', 'arbitrating', 'fixing',
                      'ai_confirmed', 'stuck', 'investigating', 'need-help', 'split')),
    CHECK (stuck_reason IS NULL OR stuck_reason IN (
        'start_failed', 'implement_failed', 'implement_timeout',
        'accept_failed', 'review_failed', 'fix_failed',
        'nitpick_failed', 'arbitrate_failed')),
    CHECK (nitpick_result IS NULL OR nitpick_result IN (
        'no_findings', 'findings_minor', 'findings_critical')),
    FOREIGN KEY(current_task_id) REFERENCES tasks (id) ON DELETE SET NULL,
    FOREIGN KEY(parent_issue_id) REFERENCES issues (id) ON DELETE CASCADE
);
COMMIT;
